INSERT INTO public.questions (id, question_text, answer_text, question_type, difficulty, scope, organization_id, source_type, estimated_time_minutes, is_active)
VALUES
    -- Topic 1: Computer Networks (5 questions)
    (1, 'What is the difference between TCP and UDP? When would you use each?',
     'TCP (Transmission Control Protocol) is connection-oriented, ensures reliable delivery with acknowledgments, maintains packet order, and includes error checking. UDP (User Datagram Protocol) is connectionless, faster but unreliable, with no guaranteed delivery or ordering. TCP is used for HTTP, email, file transfers where reliability matters. UDP is used for streaming, gaming, DNS, VoIP where speed is critical and occasional packet loss is acceptable.',
     'technical', 'easy', 'organization', 1, 'custom', 5, true),
    
    (2, 'Explain the OSI model layers and their functions. How does data flow through these layers?',
     'OSI has 7 layers: (1) Physical - bits over medium, (2) Data Link - MAC addressing, frame error detection, (3) Network - IP addressing, routing, (4) Transport - TCP/UDP, segmentation, (5) Session - connection management, (6) Presentation - encryption, compression, (7) Application - user interfaces, HTTP/FTP. Data encapsulates downward (headers added at each layer) and de-encapsulates upward at the receiver.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (3, 'How does the three-way handshake work in TCP? What happens if the third ACK is lost?',
     'Three-way handshake: (1) Client sends SYN, (2) Server responds SYN-ACK, (3) Client sends ACK. If third ACK is lost, the server remains in SYN-RECEIVED state until timeout. From the client perspective, connection is established and it can send data. Server will accept data from client even without receiving final ACK as it transitions to ESTABLISHED upon receiving client data. Most implementations handle this gracefully.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (4, 'Design a solution to detect and diagnose network latency issues in a distributed microservices architecture.',
     'Implement distributed tracing (Jaeger/Zipkin) to track request flows across services. Use service mesh (Istio/Linkerd) for network-level metrics. Deploy monitoring agents on each node to collect: RTT, packet loss, throughput, connection counts. Aggregate metrics in centralized system (Prometheus/Grafana). Implement health checks with timeout thresholds. Use tools like traceroute/mtr for path analysis. Set up alerts for latency SLA violations. Create network topology maps to identify bottlenecks.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (5, 'Explain how BGP works and discuss a scenario where BGP hijacking could occur. How would you detect and prevent it?',
     'BGP (Border Gateway Protocol) is the routing protocol of the internet, using path vector algorithm. Routers announce IP prefixes they can reach. BGP hijacking occurs when malicious actor announces unauthorized IP prefixes, redirecting traffic. Example: Attacker announces more specific prefix (longer match) than legitimate owner. Detection: monitor BGP announcements using services like BGPmon, compare announced routes against IRR databases, implement RPKI (Resource Public Key Infrastructure) to cryptographically validate announcements. Prevention: use RPKI ROA, filter routes based on IRR/RPKI, implement route dampening, peer with trusted neighbors only.',
     'technical', 'hard', 'organization', 1, 'custom', 20, true),

    -- Topic 2: Operating Systems (5 questions)
    (6, 'What is the difference between a process and a thread?',
     'A process is an independent program in execution with its own memory space (code, data, heap, stack). Threads are lightweight execution units within a process that share the same memory space (code, data, heap) but have separate stacks and registers. Processes have higher overhead for creation and context switching. Threads enable concurrent execution with lower overhead and easier inter-thread communication but require synchronization mechanisms to prevent race conditions.',
     'technical', 'easy', 'organization', 1, 'custom', 5, true),
    
    (7, 'Explain the different CPU scheduling algorithms and their use cases.',
     'FCFS (First-Come-First-Serve): Simple but causes convoy effect. SJF (Shortest Job First): Minimizes average waiting time but requires job length prediction. Round Robin: Fair time-sharing with time quantum, good for interactive systems. Priority Scheduling: Jobs with higher priority execute first, can cause starvation. Multi-level Queue: Different queues for different process types. Multi-level Feedback Queue: Processes move between queues based on behavior, used in modern OS like Linux CFS.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (8, 'What is a deadlock? Explain the four necessary conditions and strategies to prevent/avoid/detect deadlocks.',
     'Deadlock occurs when processes wait indefinitely for resources held by each other. Four necessary conditions: (1) Mutual Exclusion - resources cannot be shared, (2) Hold and Wait - process holds resources while waiting for others, (3) No Preemption - resources cannot be forcibly taken, (4) Circular Wait - circular chain of waiting processes. Prevention: break one condition (e.g., order resources). Avoidance: Banker''s algorithm. Detection: use resource allocation graphs, detect cycles. Recovery: kill processes or preempt resources.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (9, 'Explain virtual memory, paging, and how page replacement algorithms like LRU work.',
     'Virtual memory allows execution of programs larger than physical RAM by using disk as extended memory. System divides memory into fixed-size pages. Page table maps virtual to physical addresses. When program accesses page not in RAM (page fault), OS loads it from disk. Page replacement algorithms decide which page to evict: LRU (Least Recently Used) evicts page unused for longest time, requires tracking access time. Implementations use approximations like clock algorithm or aging bits. Other algorithms: FIFO, Optimal, Clock, Second Chance.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (10, 'You have a high-traffic database system where readers vastly outnumber writers, but writes are critical. Compare different synchronization strategies for the readers-writers problem. What are the starvation risks and how would you choose between reader-preference, writer-preference, and fair queuing approaches?',
     'Reader-preference: allows multiple readers, writers wait, risks writer starvation in read-heavy workload. Writer-preference: blocks new readers when writer waiting, ensures writers don''t starve, risks reader starvation under continuous writes. Fair queuing (FIFO): processes requests in order, no starvation but potentially lower throughput. Trade-offs: Reader-preference maximizes read throughput but can indefinitely delay writes in read-heavy systems. Writer-preference ensures data freshness and write progress but may impact read latency. Fair approaches balance both but add complexity. Choice factors: read/write ratio, latency requirements, data freshness needs. Real-world: databases often use hybrid approaches - short reader preference with eventual writer priority, or tiered priority based on wait time. Modern OS primitives (pthread_rwlock) provide tunable fairness. Consider: lock-free structures for read-heavy, eventual consistency models, read replicas for scaling reads.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 3: Object-Oriented Programming (5 questions)
    (11, 'Explain the four pillars of Object-Oriented Programming with examples.',
     'Encapsulation: bundling data and methods, hiding internal details (e.g., private fields with public getters). Abstraction: hiding complex implementation, exposing essential features (e.g., abstract classes, interfaces). Inheritance: creating child classes from parent, promoting code reuse (e.g., Dog extends Animal). Polymorphism: objects taking multiple forms - method overloading (same method name, different parameters) and overriding (child redefines parent method). Example: Payment interface with CreditCard and PayPal implementations.',
     'technical', 'easy', 'organization', 1, 'custom', 7, true),
    
    (12, 'What is the difference between abstract classes and interfaces? When would you use each?',
     'Abstract classes can have both abstract and concrete methods, constructors, fields with state, and support single inheritance. Interfaces define contracts with method signatures only (Java 8+ allows default methods), no state, support multiple inheritance. Use abstract class when: sharing code among related classes, need protected/private members, want to define non-static fields. Use interface when: defining contracts for unrelated classes, achieving multiple inheritance, creating plug-in architecture. Example: Template Method pattern uses abstract class; Strategy pattern uses interface.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (13, 'Explain the SOLID principles and provide an example of violating and then fixing the Liskov Substitution Principle.',
     'SOLID: (S) Single Responsibility - one reason to change, (O) Open/Closed - open for extension, closed for modification, (L) Liskov Substitution - subtypes must be substitutable for base types, (I) Interface Segregation - no fat interfaces, (D) Dependency Inversion - depend on abstractions. LSP Violation: Rectangle class with setWidth/setHeight. Square extends Rectangle but overrides both to maintain equal sides, breaking LSP since Square cannot substitute Rectangle (area calculations fail). Fix: make Rectangle and Square both implement Shape interface, or use composition instead of inheritance.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (14, 'Compare and contrast composition vs inheritance. Provide a real-world scenario where composition is preferred.',
     'Inheritance (is-a): subclass inherits behavior from parent, tight coupling, single inheritance limitation in many languages. Composition (has-a): object contains instances of other classes, loose coupling, flexible, supports multiple behaviors. Prefer composition when: need multiple behaviors, runtime behavior change, avoid fragile base class problem. Example: Car engine - Inheritance: ElectricCar extends Car (rigid). Composition: Car has Engine interface (GasEngine, ElectricEngine), allowing runtime swap, multiple car types sharing engines.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (15, 'You need to design a parking lot management system with different spot sizes, multiple payment methods, and real-time availability tracking. Discuss how you would apply OOP principles (inheritance vs composition, abstraction, polymorphism) and which design patterns would be appropriate. What are the trade-offs between different architectural approaches?',
     'OOP approach: Use abstraction for common behaviors (Vehicle, ParkingSpot, Payment), inheritance for specialized types (CompactSpot/LargeSpot extending ParkingSpot, Car/Truck extending Vehicle), polymorphism for payment processing. Composition vs inheritance: compose behaviors (vehicle has pricing strategy, spot has availability tracker) rather than deep inheritance hierarchies for flexibility. Design patterns: (1) Singleton for ParkingLot instance, but consider dependency injection for testability. (2) Factory for creating spots/vehicles based on type. (3) Strategy for payment methods (cash, card, mobile) - easily extensible. (4) Observer for available spot notifications. (5) State pattern for spot states (available, occupied, reserved). Trade-offs: Deep inheritance is rigid, composition more flexible but verbose. Singleton simplifies access but harder to test. Strategy pattern adds classes but enables runtime swapping. Key decisions: How to assign spots - first-available vs optimized placement, handle reservations, pricing (hourly, daily, vehicle type), concurrency (thread-safe spot assignment). Real-world considerations: scalability (multiple locations), integration (payment gateways), audit trail.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 4: Computer Organization and Architecture (5 questions)
    (16, 'Explain the difference between Von Neumann and Harvard architecture.',
     'Von Neumann: single memory space for instructions and data, single bus connecting CPU to memory, simpler design but instruction fetch and data access cannot happen simultaneously (von Neumann bottleneck). Harvard: separate memory and buses for instructions and data, allows simultaneous instruction fetch and data access, faster but more complex and expensive. Most modern CPUs use modified Harvard architecture with separate L1 caches but unified lower-level caches and main memory.',
     'technical', 'easy', 'organization', 1, 'custom', 7, true),
    
    (17, 'Explain the memory hierarchy and the principle of locality. How do caches exploit locality?',
     'Memory hierarchy: registers (fastest, smallest), L1/L2/L3 cache, main RAM, secondary storage (slowest, largest). Principle of locality: programs access small portion of address space at any time. Temporal locality: recently accessed data likely accessed again soon. Spatial locality: nearby data likely accessed together. Caches exploit this by: storing recently used data (temporal) and loading entire cache lines/blocks (spatial). Cache hit provides fast access, miss fetches from slower memory.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (18, 'What is pipelining in CPU architecture? Explain pipeline hazards and how they are resolved.',
     'Pipelining divides instruction execution into stages (fetch, decode, execute, memory, write-back) allowing multiple instructions in different stages simultaneously, increasing throughput. Hazards: (1) Structural - hardware resource conflict, resolved by duplicating resources. (2) Data - instruction depends on previous result, resolved by forwarding/bypassing or stalling. (3) Control - branch instructions, resolved by branch prediction, speculative execution, or pipeline flush. Modern CPUs use out-of-order execution, register renaming, and sophisticated branch predictors.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (19, 'Explain cache coherence in multi-core systems and the MESI protocol.',
     'Cache coherence ensures all caches have consistent view of memory in multi-core systems. MESI protocol states: Modified (dirty, exclusive, only copy), Exclusive (clean, only copy, not modified), Shared (clean, may exist in other caches), Invalid (not valid). State transitions: Read miss in I→E or I→S, write hit S→M, write hit E→M. Snooping protocol: caches monitor bus for memory operations. On write, invalidate/update other caches. Directory-based protocols scale better for many cores.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (20, 'A company wants to build a specialized processor for real-time image processing (filters, edge detection, color conversion). Discuss the architectural trade-offs between using a general-purpose CPU, GPU, FPGA, or designing a custom ASIC. What instruction set features would be most valuable and why?',
     'Architecture options: (1) General CPU: flexible,  easy to program, poor performance for parallel pixel operations. (2) GPU: excellent SIMD parallelism, good for matrix operations, power-hungry, latency issues for real-time. (3) FPGA: reconfigurable, low latency, complex development, moderate power. (4) Custom ASIC: optimal performance and power, expensive NRE, inflexible. Trade-offs: Performance vs cost vs flexibility. For image processing, key needs: (1) SIMD/vector operations for parallel pixel processing, (2) Specialized capabilities for common operations (convolution, color space conversion, edge detection), (3) Fast memory bandwidth for large image data, (4) Low latency for real-time constraints. Instruction set considerations: RISC vs CISC base, vector register width (128-bit, 256-bit, 512-bit), addressing modes for efficient image access (2D array indexing), dedicated hardware blocks vs generic instructions. Real-world examples: Apple Neural Engine (dedicated ML/image), Intel AVX-512 for SIMD, ARM Neon for mobile image processing. Decision factors: production volume (justifies ASIC NRE cost), time-to-market pressures, performance requirements, power budget (mobile vs datacenter), algorithm stability (ASIC inflexible if algorithms change frequently).',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 5: Database Management Systems (5 questions)
    (21, 'Explain ACID properties in databases with examples.',
     'Atomicity: transaction is all-or-nothing (bank transfer: both debit and credit must succeed or both fail). Consistency: database moves from one valid state to another (foreign key constraints maintained). Isolation: concurrent transactions don''t interfere (read committed, serializable isolation levels). Durability: committed changes persist even after system failure (write-ahead logging, checkpoints). Example: Bank transfer of $100 - atomicity ensures both accounts updated, consistency maintains total money constant, isolation prevents concurrent transfers from seeing intermediate state, durability ensures committed transfer survives crash.',
     'technical', 'easy', 'organization', 1, 'custom', 7, true),
    
    (22, 'What are database indexes? Explain B-tree and Hash indexes and their use cases.',
     'Indexes are data structures that improve query performance by providing fast lookups. B-tree index: balanced tree, supports range queries, equality, ORDER BY, maintains sorted order, used for most cases. Complexity: O(log n) search. Hash index: hash table, very fast equality lookups O(1), cannot do range queries or sorting, good for exact-match lookups. Use B-tree for: range queries, sorting, composite keys. Use Hash for: equality-only lookups, very high cardinality columns. Most databases use B+ tree variant with all data in leaves.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (23, 'Explain different isolation levels and the problems they solve (dirty read, non-repeatable read, phantom read).',
     'Read Uncommitted: no isolation, allows dirty reads (reading uncommitted changes). Read Committed: prevents dirty reads, but allows non-repeatable reads (same query returns different results). Repeatable Read: prevents dirty and non-repeatable reads, but allows phantom reads (new rows appearing). Serializable: full isolation, prevents all anomalies. Examples: Dirty read - T1 updates row, T2 reads, T1 rolls back. Non-repeatable - T1 reads row, T2 updates, T1 reads again (different value). Phantom - T1 reads WHERE condition, T2 inserts matching row, T1 reads again (extra row).',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (24, 'Explain database normalization forms (1NF, 2NF, 3NF, BCNF) and when denormalization might be appropriate.',
     '1NF: atomic values, no repeating groups. 2NF: 1NF + no partial dependencies (non-key attributes depend on entire primary key). 3NF: 2NF + no transitive dependencies (non-key attributes depend only on primary key). BCNF: 3NF + every determinant is a candidate key. Example: Orders(OrderID, CustomerName, CustomerAddress) violates 3NF - CustomerAddress depends on CustomerName, not OrderID. Fix: separate Customers table. Denormalization appropriate when: read-heavy workload, complex joins hurt performance, data rarely changes, acceptable slight inconsistency (caching, reporting databases, materialized views).',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (25, 'You''re building a multi-tenant SaaS application expecting to scale from 10 to 10,000 customers. Compare the trade-offs between shared schema, schema-per-tenant, and database-per-tenant approaches. How would you choose between different sharding strategies and what are the implications for billing, compliance, and data migration?',
     'Multi-tenancy approaches: (1) Shared schema with tenant_id: most cost-efficient, complex query filtering, highest density, difficult tenant isolation for compliance. (2) Schema-per-tenant: better isolation, more complex migration/upgrades, moderate costs. (3) Database-per-tenant: strongest isolation, highest cost, simpler compliance (GDPR data deletion), difficult cross-tenant analytics. Sharding considerations: Tenant sharding (all tenant data together) simplifies queries but creates hot spots for large tenants. Hash sharding distributes load evenly but complicates tenant-specific operations. Geographic sharding helps compliance (EU data stays in EU) but increases complexity. Trade-offs: Cost vs isolation vs complexity. Shared schema scales cheaply but has noisy neighbor issues. Separate DBs provide isolation but expensive at scale. Decision factors: customer size distribution (few large vs many small), compliance requirements (HIPAA, GDPR), budget for infrastructure, team capability. Real-world: Start shared schema, migrate enterprise customers to dedicated as they grow. Consider hybrid: shared for small tenants, dedicated for enterprise.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 6: Data Structures and Algorithms (5 questions)
    (26, 'Explain the difference between an array and a linked list. When would you use each?',
     'Array: contiguous memory, O(1) random access by index, cache-friendly, fixed/dynamic size, O(n) insertion/deletion in middle. Linked List: non-contiguous nodes with pointers, O(n) access by index, O(1) insertion/deletion with pointer, more memory overhead (pointers). Use array when: frequent random access, known size limits, cache performance critical. Use linked list when: frequent insertions/deletions, size unknown or highly variable, implementing queues/stacks.',
     'technical', 'easy', 'organization', 1, 'custom', 5, true),
    
    (27, 'Explain how a hash table works, including collision resolution strategies.',
     'Hash table uses hash function to map keys to array indices for O(1) average-case insert, delete, lookup. Collision occurs when hash(key1) == hash(key2). Resolution strategies: (1) Chaining - each bucket is linked list, O(n) worst case if all keys hash to same bucket. (2) Open addressing - probing (linear, quadratic, double hashing) to find next empty slot, requires good load factor control. Rehashing occurs when load factor exceeds threshold (typically 0.75), creating larger array and rehashing all keys. Good hash function distributes keys uniformly.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (28, 'Compare quicksort, mergesort, and heapsort. Analyze time/space complexity and stability.',
     'Quicksort: O(n log n) average, O(n²) worst (bad pivot), O(log n) space, unstable, in-place, cache-friendly, fastest in practice. Mergesort: O(n log n) guaranteed, O(n) space, stable, not in-place, good for linked lists and external sorting. Heapsort: O(n log n) guaranteed, O(1) space, unstable, in-place, not cache-friendly. Stability: stable algorithms maintain relative order of equal elements. Use quicksort for: general arrays, Mergesort for: stable sort needed, linked lists, Heapsort for: space-constrained, guaranteed performance.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (29, 'Explain graph traversal algorithms (BFS, DFS) and their applications. Provide time complexity analysis.',
     'BFS (queue): explores level by level, finds shortest path in unweighted graphs, O(V+E) time, O(V) space. Applications: shortest path, level-order traversal, peer-to-peer networks. DFS (stack/recursion): explores deeply before backtracking, O(V+E) time, O(V) space for recursion stack. Applications: detecting cycles, topological sort, maze solving, connected components. BFS uses more memory (entire level in queue) but finds shortest paths. DFS uses less memory but may not find shortest path. Both marked visited nodes to avoid infinite loops.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (30, 'Explain the data structure combination needed to build an LRU cache with O(1) get and put operations. Why is this combination necessary and what would be the trade-offs of using alternative approaches like a simple hash map with timestamps or a sorted tree?',
     'LRU cache requires O(1) access and O(1) eviction of least recent item. Solution needs: (1) Fast lookup - hash map provides O(1) key access. (2) Fast reordering - doubly linked list allows O(1) add/remove/move operations. (3) Track recency - list order represents usage (head=most recent, tail=least recent). Why both: HashMap alone can''t efficiently track LRU order. Sorted tree (TreeMap) is O(log n). Array requires O(n) reordering. DLL alone is O(n) for lookup. Combined: HashMap stores key→node mappings, DLL maintains usage order, both together achieve O(1). Trade-offs of alternatives: HashMap + timestamps requires O(n) scan to find minimum timestamp on eviction. Priority queue (min-heap) gives O(log n) eviction. Sorted tree (TreeMap by last-used time) is O(log n) for all ops. Simple array with circular buffer is O(n) for access. The HashMap+DLL combination is the only way to achieve O(1) for both operations while maintaining LRU ordering. Space trade-off: extra memory for pointers in DLL nodes and hash map overhead, but worth it for performance.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- ============================================================================
    -- PART 2: Backend Engineering Topics (Topics 7-20)
    -- ============================================================================

    -- Topic 7: RESTful APIs (5 questions)
    (31, 'What are the key principles of RESTful API design?',
     'REST principles: (1) Client-Server: separation of concerns, (2) Stateless: each request contains all information needed, (3) Cacheable: responses explicitly indicate cacheability, (4) Uniform Interface: consistent resource identification via URIs, (5) Layered System: architecture can have intermediaries, (6) Code-on-Demand (optional): server can send executable code. Best practices: use HTTP methods semantically (GET/POST/PUT/DELETE/PATCH), noun-based resource URIs (/users not /getUsers), proper status codes (200, 201, 404, 500), versioning (/api/v1/), HATEOAS for discoverability.',
     'technical', 'easy', 'organization', 1, 'custom', 7, true),
    
    (32, 'Explain the difference between PUT and PATCH. When would you use each?',
     'PUT: replaces entire resource, client sends complete representation, idempotent (multiple calls same result). Example: PUT /users/1 with full user object replaces all fields. PATCH: partial update, client sends only changed fields, may not be idempotent. Example: PATCH /users/1 with {"email": "new@example.com"} updates only email. Use PUT when: client has complete resource representation, want to ensure full replacement. Use PATCH when: updating specific fields, large resources where sending entire object is inefficient, complex partial updates. PATCH requires server support for merge logic.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (33, 'How would you implement API rate limiting? Discuss different algorithms and their trade-offs.',
     'Algorithms: (1) Fixed Window: count requests per time window (e.g., 100/min), simple but allows bursts at boundaries. (2) Sliding Window: weighted count across rolling window, smoother but complex. (3) Token Bucket: tokens added at fixed rate, requests consume tokens, allows bursts up to bucket size. (4) Leaky Bucket: requests queued, processed at fixed rate, smooth but may delay requests. Implementation: store counters in Redis with TTL. Consider: distributed systems (shared state), user vs IP-based limiting, different limits per endpoint/plan, 429 status with Retry-After header.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (34, 'Design a RESTful API for a social media platform including posts, comments, likes, and follows. Include authentication and authorization.',
     'Resources: POST /api/v1/posts, GET /api/v1/posts/{id}, GET /api/v1/posts?user_id=X&page=1, POST /api/v1/posts/{id}/comments, POST /api/v1/posts/{id}/likes, DELETE /api/v1/posts/{id}/likes, POST /api/v1/users/{id}/follow. Authentication: JWT tokens via OAuth2, POST /auth/login returns access+refresh tokens. Authorization: middleware validates JWT, checks ownership (user can delete own posts), role-based (admin can delete any). Pagination: limit/offset or cursor-based. Filtering: query params. Rate limiting: per-user. Status codes: 201 Created, 204 No Content for deletes, 403 Forbidden, 401 Unauthorized.',
     'technical', 'medium', 'organization', 1, 'custom', 20, true),
    
    (35, 'Your API serves millions of users across mobile apps,web clients, and third-party integrations. Compare URI versioning (/v1/), header versioning, and query parameter approaches. How would you manage a breaking change rollout without disrupting existing clients? What are the risks of maintaining too many versions?',
     'Versioning approaches compared: (1) URI versioning (/api/v1/users): most visible, explicit, simple routing, version in URL. Pros: clear, cacheable, easy testing. Cons: URL clutter. (2) Header versioning (Accept: application/vnd.api.v1+json): cleaner URLs, follows HTTP standards. Pros: same endpoint for all versions. Cons: harder to test in browser, caching complexity. (3) Query param (?v=1): flexible. Cons: easy to forget, cache issues. Trade-offs: URI versioning most common for developer experience, header versioning more RESTful but less practical. Migration challenges: (1) Detection problem - know which clients use which version. (2) Long tail problem - some clients never upgrade. (3) Testing burden - must test ALL version combinations. (4) Database schema changes affect all versions. Strategies: Maintain 2-3 versions maximum (current, previous, next deprecating). Use deprecation headers (Sunset: 2024-12-31) + response warnings. Track usage per version with analytics. Gradual rollout: Beta version for early adopters, sunset warnings months ahead, forced migration for security issues only. Risks of many versions: exponential testing complexity, bug fixes across versions, deployment coordination, team cognitive load. Best approach: Design for backward compatibility when possible, use feature flags for gradual rollouts, communicate deprecation early and often, provide migration tools/guides.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 8: GraphQL (5 questions)
    (36, 'What is GraphQL and how does it differ from REST?',
     'GraphQL is a query language for APIs where clients specify exactly what data they need. Differences from REST: (1) Single endpoint vs multiple endpoints, (2) client-specified response shape vs fixed responses, (3) no over/under-fetching, (4) strongly typed schema, (5) introspection built-in. Advantages: fewer requests, flexible queries, better mobile performance. Disadvantages: caching complexity, potential for expensive queries, learning curve. Use GraphQL when: clients need flexible data access, multiple platforms with different needs. Use REST when: simple CRUD, heavy caching requirements, public APIs.',
     'technical', 'easy', 'organization', 1, 'custom', 8, true),
    
    (37, 'Explain the N+1 query problem in GraphQL and how to solve it using DataLoader.',
     'N+1 problem: fetching list of posts (1 query) then authors for each post (N queries) = N+1 total. Example: query{posts{title author{name}}} executes 1 query for posts, then separate query per post for author. DataLoader solution: batching and caching layer. Collects all author IDs needed in single execution tick, makes one batched query (WHERE id IN [...]), caches results per request. Implementation: create DataLoader instance per request, use loader.load(id) instead of direct DB calls. Batches requests within same tick, deduplicates IDs, provides per-request caching.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (38, 'How would you implement authentication and authorization in GraphQL? Compare field-level vs query-level authorization.',
     'Authentication: validate JWT in context (middleware before resolvers), add user to context object. Authorization approaches: (1) Query-level: check permissions in resolver before execution, simple but coarse-grained. (2) Field-level: directive-based (@auth, @hasRole), granular control, can hide fields based on permissions. Implementation: custom directives that check context.user.role, throw AuthenticationError or return null for unauthorized fields. Best practice: combine both - query-level for main operations, field-level for sensitive data like emails, phone numbers. Use GraphQL Shield library for declarative permissions. Consider schema stitching for separating public and private schemas.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (39, 'Design a GraphQL schema for an e-commerce platform with products, users, orders, and reviews. Include mutations and subscriptions.',
     'Types: type User{id,email,orders:[Order]}, type Product{id,name,price,reviews:[Review],avgRating}, type Order{id,user:User,items:[OrderItem],status,total}, type Review{id,user:User,product:Product,rating,comment}. Queries: products(filter:ProductFilter,page:Int):ProductPage, product(id:ID):Product, myOrders:[Order]. Mutations: createOrder(input:OrderInput):Order, addReview(productId:ID,rating:Int,comment:String):Review, updateOrderStatus(id:ID,status:OrderStatus):Order. Subscriptions: orderUpdated(userId:ID):Order, newReview(productId:ID):Review. Input types for complex args. Use relay-style pagination with edges/nodes.',
     'technical', 'medium', 'organization', 1, 'custom', 20, true),
    
    (40, 'GraphQL APIs are vulnerable to malicious queries that could overwhelm your servers (deeply nested queries, circular references, expensive array fields). Compare different protection strategies: query depth limiting, complexity cost analysis, timeout limits, and query allowlisting. What are the trade-offs of each approach and how would you balance security with legitimate use cases?',
     'Protection strategies compared: (1) Query depth limiting: set maximum nesting level (e.g., 10 levels deep). Pros: simple, catches most abusive patterns. Cons: may block legitimate deep queries, doesn''t account for array multipliers. (2) Complexity cost analysis: assign cost to each field (expensive resolvers=higher cost), reject queries exceeding threshold. Pros: catches exponential queries (arrays), flexible per-field. Cons: requires cost calibration, maintenance overhead. (3) Timeout limits: kill queries exceeding time threshold. Pros: catches all slow queries regardless of structure. Cons: inconsistent (varies by load), poor UX (query sometimes works, sometimes doesn''t). (4) Query allowlisting: only predefined queries allowed in production. Pros: perfect security, optimal performance. Cons: loses GraphQL flexibility, requires deployment
 for new queries. Trade-offs: Depth limiting is easy but crude. Complexity analysis is accurate but requires tuning. Timeouts are unreliable. Allowlisting is secure but defeats GraphQL purpose. Hybrid approach: Use depth limiting (10-12) + complexity analysis with reasonable thresholds + timeouts as safety net. Disable introspection in production. Monitor query patterns, adjust costs based on actual resolver performance. Special cases: trusted internal tools get higher limits, public APIs get stricter limits. Real-world: combine multiple strategies, start permissive, tighten based on abuse patterns, provide query cost in dev tools for developers.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 9: Node.js (5 questions)
    (41, 'Explain the event loop in Node.js and how asynchronous I/O works.',
     'Node.js uses single-threaded event loop with non-blocking I/O. Event loop phases: (1) Timers - setTimeout/setInterval callbacks, (2) Pending callbacks - I/O callbacks deferred, (3) Idle/prepare - internal, (4) Poll - retrieve new I/O events, execute callbacks, (5) Check - setImmediate callbacks, (6) Close callbacks - socket.on("close"). Async I/O: when I/O operation called (file read, network), delegated to libuv thread pool, event loop continues, callback queued when operation completes. This enables high concurrency with single thread. Microtasks (Promise.then, process.nextTick) execute between phases.',
     'technical', 'easy', 'organization', 1, 'custom', 10, true),
    
    (42, 'Compare callbacks, promises, and async/await in Node.js. What is callback hell and how do you avoid it?',
     'Callbacks: functions passed as arguments, executed on completion, leads to nested "callback hell" (pyramid of doom). Promises: objects representing future values, chainable with .then(), better error handling with .catch(). Async/await: syntactic sugar over promises, write async code like synchronous, try/catch for errors. Callback hell example: readFile(fn1(writeFile(fn2(readFile...))))). Avoid by: (1) named functions instead of anonymous, (2) modularization, (3) use promises/async-await, (4) libraries like async.js. Modern Node.js prefers async/await for readability and maintainability.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (43, 'How would you handle CPU-intensive tasks in Node.js without blocking the event loop?',
     'Solutions: (1) Worker Threads - spawn worker threads using worker_threads module, communicate via message passing, share memory with SharedArrayBuffer. (2) Child Processes - spawn separate Node processes using child_process.fork(), inter-process communication. (3) Cluster module - distribute load across CPU cores, master process manages workers. (4) External job queue - Redis + Bull, offload to separate worker processes. (5) Native addons - write CPU-intensive parts in C++. Example: image processing, cryptographic operations, large data transformations. Use worker pool pattern with fixed number of workers to prevent resource exhaustion.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (44, 'Explain memory management and garbage collection in Node.js. How would you debug memory leaks?',
     'V8 uses generational garbage collection: new objects in Young Generation (Scavenge GC, fast, frequent), long-lived in Old Generation (Mark-Sweep-Compact, slower, infrequent). Memory leaks common causes: global variables, closures holding references, event listeners not removed, cache without TTL, timers not cleared. Debugging: (1) heap snapshots with Chrome DevTools - compare before/after, find detached DOM/objects, (2) --inspect flag, (3) clinic.js or heapdump modules, (4) process.memoryUsage() monitoring. Prevention: use WeakMap for caches, remove event listeners, clear timers, limit array/object growth, use streams for large data.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (45, 'You need to build a real-time chat system handling millions of concurrent users with features like typing indicators, presence, and message persistence. Discuss the architectural challenges of horizontal scaling WebSocket connections. How do you handle message routing between server instances, ensure message ordering, and manage connection failover?',
     'Scaling challenges: (1) Stateful connections - each WebSocket ties to specific server instance, makes load balancing complex. (2) Message routing - user A on server 1 needs message from user B on server 2. (3) Presence tracking - who''s online across all servers. (4) Ordering guarantees - messages may arrive out of order. Architectural approaches: WebSocket servers behind load balancer with sticky sessions (IP hash or cookie-based), pub/sub layer (Redis) for inter-server communication. When user sends message: server publishes to Redis channel, all servers subscribed receive it, servers emit to connected clients. Presence: Redis sorted sets with heartbeat timestamps, track per-server. Message ordering: sequence numbers + client-side buffering, or guarantee ordering in pub/sub (Redis Streams). Trade-offs: Sticky sessions reduce flexibility (can''t rebalance easily) but simpler. Consistent hashing for better distribution but complex failover. Redis pub/sub is fast but no delivery guarantees. Kafka provides ordering and persistence but higher latency. Failover: clients must detect disconnect and reconnect with exponential backoff. State reconciliation after reconnect (missed messages). Persistence: async write to DB via message queue to not block real-time delivery. Challenges: How to handle reconnections (resume from last message vs full sync), offline message delivery (push notifications), read receipts across servers, backpressure when clients slow. Alternative: Serverless WebSocket (AWS API Gateway) abstracts scaling but lose fine control. Service mesh for observability.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 10: Python (5 questions)
    (46, 'Explain Python''s GIL (Global Interpreter Lock) and its implications for multi-threading.',
     'GIL is a mutex preventing multiple threads from executing Python bytecode simultaneously in CPython. Implications: (1) CPU-bound multi-threaded programs don''t achieve parallelism, (2) I/O-bound programs still benefit (thread releases GIL during I/O), (3) multi-processing achieves true parallelism (separate processes, separate GIL). Workarounds: (1) multiprocessing module for CPU-bound tasks, (2) asyncio for I/O-bound concurrency, (3) alternative interpreters (Jython, IronPython) without GIL, (4) C extensions can release GIL. GIL simplifies memory management and C extension integration but limits CPU-bound parallelism.',
     'technical', 'easy', 'organization', 1, 'custom', 8, true),
    
    (47, 'Compare list comprehensions, generator expressions, and map/filter. When would you use each?',
     'List comprehension: [x*2 for x in range(10)] creates entire list in memory, readable, Pythonic. Generator expression: (x*2 for x in range(10)) lazy evaluation, memory-efficient for large datasets, returns generator object. Map/filter: map(lambda x:x*2, range(10)), functional style, also lazy in Python 3. Use list comprehension when: need list immediately, small datasets, better readability. Use generator when: large/infinite sequences, memory-constrained, one-time iteration. Use map/filter when: combining with other functional tools, passing to functions expecting iterables. Generators support pipeline processing without intermediate lists.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (48, 'Explain Python decorators. Implement a decorator for caching function results (memoization) and rate limiting.',
     'Decorators modify/enhance functions without changing code. Syntax: @decorator above function. Implementation uses closures/higher-order functions. Memoization decorator: def memoize(func): cache={}; def wrapper(*args): if args not in cache: cache[args]=func(*args); return cache[args]; return wrapper. Rate limiting: use time-based tracking per user/IP, store in dict {user: [timestamps]}, remove old timestamps, reject if count > limit. Use functools.wraps to preserve metadata. Advanced: class-based decorators with __call__, parametrized decorators (decorator factory), stacking decorators.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (49, 'How does Python''s garbage collection work? Explain reference counting and cycle detection.',
     'Python uses: (1) Reference counting - each object has ref count, incremented on assignment, decremented when references deleted, deallocate when reaches 0. Problem: circular references. (2) Cycle detector - generational GC finds unreachable cycles, runs periodically. Three generations (0,1,2), objects promoted if survive collection. gc module provides control. Manual: gc.collect(), disable with gc.disable() for performance-critical code. Identify cycles: gc.get_referrers(). Best practices: use context managers, explicitly delete large objects, avoid circular refs with weakref module.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (50, 'Your Python application has both I/O-bound operations (database queries, API calls) and CPU-intensive tasks (image processing, data analysis). Discuss the challenges of mixing synchronous and asynchronous code. How would you architect the application to leverage async for I/O while handling blocking operations? What are the risks and how do you prevent async performance degradation?',
     'Challenges of mixing sync/async: (1) Blocking calls in async context freeze event loop for all concurrent tasks. (2) Cannot directly await sync functions. (3) Different mental models and error handling. (4) Library ecosystem split between sync (Pillow, NumPy) and async (aiohttp, asyncpg). Architectural approaches: Use asyncio event loop for I/O-bound (web requests, DB), offload CPU-bound to ThreadPoolExecutor or ProcessPoolExecutor. run_in_executor bridges them - await loop.run_in_executor(pool, sync_function). Separate async and sync layers clearly. Trade-offs: ThreadPoolExecutor good for I/O-blocking libraries but limited by GIL for CPU. ProcessPoolExecutor bypasses GIL but has serialization overhead, better for heavy CPU. Async overhead not worth it for truly CPU-bound work. Risks: (1) Accidentally blocking: calling requests instead of aiohttp, file I/O without aiofiles. (2) Executor pool exhaustion: too many blocking tasks queued. (3) Memory growth: executor tasks hold references. Prevention: Use ProcessPoolExecutor with pool size = CPU cores, monitor task queue depth, set timeouts on executor calls, use async-native libraries where possible (asyncpg vs psycopg2, aiohttp vs requests). Testing: run_until_complete for tests, anyio for library compatibility. Real-world: FastAPI for async web, Celery for background jobs, prefer process pools for CPU work, async for concurrent I/O.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 11: Java (5 questions)
    (51, 'Explain the difference between JVM, JRE, and JDK.',
     'JVM (Java Virtual Machine): execution environment that runs Java bytecode, provides platform independence, includes JIT compiler, garbage collection. JRE (Java Runtime Environment): JVM + standard libraries (java.lang, java.util, etc.) + deployment tools, needed to run Java applications. JDK (Java Development Kit): JRE + development tools (javac compiler, debugger, javadoc, etc.), needed to develop Java applications. Relationship: JDK ⊃ JRE ⊃ JVM. Developers need JDK, end users need only JRE.',
     'technical', 'easy', 'organization', 1, 'custom', 5, true),
    
    (52, 'Explain Java memory model: heap, stack, and garbage collection algorithms.',
     'Stack: stores method frames, local variables, method call tracking, thread-specific, LIFO, limited size. Heap: stores objects and arrays, shared across threads, managed by GC. Method Area: class metadata, static variables. GC algorithms: (1) Serial GC - single thread, stop-the-world. (2) Parallel GC - multiple threads, throughput-focused. (3) CMS (Concurrent Mark-Sweep) - low-pause, concurrent phases. (4) G1 GC - divides heap into regions, predictable pause times, default in Java 9+. (5) ZGC/Shenandoah - ultra-low pause times (<10ms). Young generation (Eden, S0, S1) for new objects, Old generation for long-lived, collection triggered by allocation failure.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (53, 'Compare Java Streams API with traditional loops. When would you use each?',
     'Streams: functional, declarative, chainable operations (map/filter/reduce), lazy evaluation, parallel processing (.parallelStream()), cleaner for complex transformations. Traditional loops: imperative, more control, better for simple iterations, easier debugging, no overhead. Stream example: list.stream().filter(x->x>10).map(x->x*2).collect(). Use streams when: complex data transformations, potential for parallelism, functional style preference. Use loops when: simple iterations, need to break early, modifying external state, performance-critical (streams have overhead). Parallel streams good for CPU-intensive operations on large collections, but beware shared state.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (54, 'Explain the Java Executor framework and different thread pool types. How would you choose the right one?',
     'ExecutorService manages thread pools. Types: (1) newFixedThreadPool(n) - fixed n threads, bounded queue, predictable resources. (2) newCachedThreadPool() - creates threads as needed, reuses, good for many short tasks. (3) newSingleThreadExecutor() - guarantees sequential execution. (4) newScheduledThreadPool(n) - supports delayed/periodic tasks. (5) newWorkStealingPool() - fork-join pool, work stealing for parallel computations. Choose based on: Fixed for known concurrent operations, Cached for burst workloads, Scheduled for cron-like tasks, Work-stealing for recursive divide-conquer. Custom ThreadPoolExecutor for fine control over queue, rejection policy, thread factory.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (55, 'Design a thread-safe singleton pattern in Java. Compare different implementation approaches and discuss double-checked locking.',
     'Approaches: (1) Eager initialization: static instance created at class load, thread-safe but wastes memory if unused. (2) Synchronized method: getInstance() synchronized, thread-safe but slow. (3) Double-checked locking: check instance twice, synchronize only first time, requires volatile keyword to prevent reordering. (4) Bill Pugh (recommended): static inner class holds instance, lazy, thread-safe by class loader. (5) Enum (best): enum Singleton{INSTANCE}, prevents reflection/serialization attacks. Double-checked: if(instance==null){synchronized(Singleton.class){if(instance==null){instance=new Singleton();}}} volatile prevents partial construction visibility.',
     'technical', 'hard', 'organization', 1, 'custom', 20, true),

    -- Topic 12: Go (5 questions)
    (56, 'Explain goroutines and how they differ from traditional threads.',
     'Goroutines are lightweight concurrent functions managed by Go runtime. Differences from threads: (1) lightweight (2KB stack vs 1MB+ for threads), (2) multiplexed onto OS threads (M:N model), (3) cooperative scheduling by runtime, (4) cheap creation/destruction (can spawn millions). Goroutines scheduled by Go scheduler using work-stealing algorithm. Launch with "go func()". Communicate via channels (share memory by communicating). Advantages: massive concurrency, simple syntax. Managed stack grows/shrinks dynamically. Runtime uses GOMAXPROCS OS threads.',
     'technical', 'easy', 'organization', 1, 'custom', 7, true),
    
    (57, 'Explain channels in Go. What is the difference between buffered and unbuffered channels?',
     'Channels enable communication between goroutines. Unbuffered (ch:=make(chan int)): send blocks until receive happens, synchronous, guaranteed delivery. Buffered (ch:=make(chan int, 5)): send blocks only when buffer full, receive blocks when empty, asynchronous up to buffer size. Use unbuffered for: synchronization, guaranteed handoff. Use buffered for: decoupling sender/receiver, burst handling, pipeline stages. Close channel with close(ch) to signal completion. Range over channel: for v:=range ch. Select for multiple channels: select{case <-ch1: case <-ch2:}.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (58, 'How does Go handle memory management and garbage collection? What are common memory leak scenarios?',
     'Go uses concurrent tri-color mark-and-sweep GC with write barriers. Runs concurrently with application, minimizes pause times (<1ms). Allocations in heap if: escapes function scope, size unknown at compile time, too large for stack. Stack allocations preferred (no GC overhead). GC tuning: GOGC env variable (default 100%). Common leaks: (1) goroutines not terminating (blocked channels, infinite loops), (2) unclosed resources (files, connections), (3) global data structures growing unbounded, (4) timers not stopped, (5) capturing loop variables in closures. Debug: pprof for heap/goroutine profiling, runtime.ReadMemStats().',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (59, 'Explain Go interfaces and the concept of implicit implementation. How do empty interfaces work?',
     'Go interfaces define method sets. Types implement interfaces implicitly (no "implements" keyword) if they have all methods. Duck typing: "if it walks like a duck...". Advantages: loose coupling, flexibility, easy testing with mocks. Empty interface (interface{} or "any" in Go 1.18+) has zero methods, satisfied by any type, used for generic containers, reflection. Type assertion: v:=i.(string) extracts concrete type, panics if wrong. Type switch: switch v:=i.(type){case int: case string:}. Interfaces stored as (type, value) pair. Nil interface: both type and value are nil.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (60, 'Design a worker pool pattern in Go to process jobs concurrently with proper error handling and graceful shutdown.',
     'Implementation: (1) Job channel for incoming tasks, (2) Results channel for outputs, (3) Error channel for errors, (4) WaitGroup to track workers, (5) Context for cancellation. Code structure: spawn N workers as goroutines, each worker reads from job channel in loop, executes task, sends result. Main goroutine sends jobs, closes job channel when done, waits for workers. Graceful shutdown: use context.WithCancel(), workers check ctx.Done(), drain channels, handle in-flight jobs. Error handling: workers send errors to error channel, dedicated goroutine collects errors. Advanced: dynamic worker scaling, priority queues, rate limiting per worker. Use select for non-blocking sends/receives.',
     'technical', 'hard', 'organization', 1, 'custom', 25, true),

    -- Topic 13: SQL Databases (5 questions)
    (61, 'Explain the difference between INNER JOIN, LEFT JOIN, RIGHT JOIN, and FULL OUTER JOIN.',
     'INNER JOIN: returns rows where match in both tables. LEFT JOIN: all rows from left table + matching from right (NULL if no match). RIGHT JOIN: all rows from right table + matching from left. FULL OUTER JOIN: all rows from both tables, NULL where no match. Example: Users LEFT JOIN Orders returns all users even without orders. Use INNER when: both sides required. LEFT when: preserve left table (all users). RIGHT when: preserve right (rare, use LEFT instead). FULL OUTER when: need unmatched from both sides.',
     'technical', 'easy', 'organization', 1, 'custom', 7, true),
    
    (62, 'Explain how database transactions work and the use of COMMIT and ROLLBACK.',
     'Transaction: group of operations treated as single unit, follows ACID properties. BEGIN starts transaction, COMMIT makes changes permanent, ROLLBACK undoes changes. Example: bank transfer - debit account A, credit account B must both succeed or both fail. If error occurs, ROLLBACK ensures data consistency. Savepoints allow partial rollback: SAVEPOINT sp1, ROLLBACK TO sp1. Auto-commit mode: each statement is transaction. In application code, use try-catch: begin transaction, execute operations, commit on success, rollback on exception. Connection pooling must handle transaction state properly.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (63, 'How would you optimize a slow query? Explain the steps and tools you would use.',
     'Steps: (1) EXPLAIN/EXPLAIN ANALYZE to see query plan, identify seq scans, join types, row estimates. (2) Check for missing indexes on WHERE/JOIN columns. (3) Analyze statistics: ANALYZE table to update stats. (4) Rewrite query: avoid SELECT *, use covering indexes, limit result set early. (5) Check index usage: index on high-cardinality columns, avoid functions on indexed columns. (6) Partition large tables. (7) Optimize JOINs: order matters, filter early. (8) Use query hints if needed. Tools: pg_stat_statements, slow query log, pgBadger, execution plan visualizers. Consider: query vs schema optimization, denormalization for read-heavy workloads.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (64, 'Explain database indexing strategies: B-tree, Hash, GiST, GIN. When would you use each?',
     'B-tree: default, balanced tree, supports <, <=, =, >=, >, ORDER BY, range queries, most common. Hash: equality only (=), faster than B-tree for exact matches but no range support. GiST (Generalized Search Tree): extensible, used for geometric data, full-text, range types, supports KNN queries. GIN (Generalized Inverted Index): inverted index for composite values like arrays, JSONB, full-text search, faster lookups but slower updates. Use B-tree for: general purpose, range queries. Hash for: large equality-only queries (rarely needed). GiST for: spatial data (PostGIS). GIN for: JSONB queries, array contains, full-text search.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (65, 'Design a database schema and indexing strategy for a time-series data system handling millions of records per day.',
     'Schema: use time-bucket partitioning (daily/weekly tables), composite primary key (timestamp, device_id), denormalized for query performance. Columns: timestamp, device_id, metrics (JSON or columns). Partitioning: declarative partitioning on timestamp, automate partition creation. Indexes: B-tree on (device_id, timestamp) for device queries, BRIN index on timestamp for range scans (very compact for ordered data). Retention: drop old partitions, archive to cold storage. Optimization: TimescaleDB hypertables, continuous aggregates for pre-computed rollups. Compression for old partitions. Batch inserts, use COPY for bulk loads. Consider: downsampling strategies, separate raw and aggregated tables.',
     'technical', 'hard', 'organization', 1, 'custom', 25, true),

    -- Topic 14: NoSQL Databases (5 questions)
    (66, 'Compare SQL and NoSQL databases. When would you choose each?',
     'SQL: structured schema, ACID transactions, relational model, strong consistency, complex queries with JOINs, vertical scaling primarily. NoSQL: flexible schema, eventual consistency (usually), horizontal scaling, high throughput, specialized data models (document, key-value, column-family, graph). Choose SQL when: complex relationships, ACID required, structured data, complex queries. Choose NoSQL when: massive scale, schema evolution needed, specific data models (time-series, graphs), high write throughput, geographical distribution. Examples: PostgreSQL for transactional apps, MongoDB for content management, Cassandra for time-series, Neo4j for social graphs, Redis for caching.',
     'technical', 'easy', 'organization', 1, 'custom', 10, true),
    
    (67, 'Explain the CAP theorem and its implications for distributed databases. Provide examples.',
     'CAP: in distributed system, can only guarantee 2 of 3: Consistency (all nodes see same data), Availability (system always responds), Partition tolerance (works despite network failures). In practice, partition tolerance is mandatory (networks fail), so choose CP or AP. CP systems (HBase, MongoDB in strong mode): sacrifice availability during partitions, guarantee consistency. AP systems (Cassandra, DynamoDB): sacrifice strong consistency, always available, eventual consistency. Example: bank account (CP - need consistency), shopping cart (AP - availability matters). Modern systems offer tunable consistency (Cassandra: use quorum reads/writes).',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (68, 'Explain MongoDB indexing and aggregation pipeline. How do they differ from SQL?',
     'MongoDB indexes: similar to SQL (single-field, compound, multikey for arrays, text, geospatial, hashed). Created with db.collection.createIndex(). Compound index order matters for query coverage. Aggregation pipeline: sequence of stages - $match (filter), $group (GROUP BY), $sort, $project (SELECT), $lookup (JOIN), $unwind (array expansion). Example: db.collection.aggregate([{$match:{status:"A"}},{$group:{_id:"$category",total:{$sum:"$amount"}}}]). Difference from SQL: procedural stages vs declarative SQL, no native JOINs (use $lookup), denormalized data reduces JOIN needs, more flexible for complex transformations.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (69, 'How would you design a data model in Cassandra for a messaging application? Explain partition keys and clustering columns.',
     'Cassandra data modeling: query-first approach, denormalization essential. For messaging: (1) Messages table: partition key = conversation_id (groups messages together), clustering column = timestamp (DESC for newest first), columns = sender_id, message_text. Query patterns determine tables: getUserConversations might need separate table with partition key = user_id. Wide partitions: conversations grow over time, limit with bucketing (partition by conversation_id + month). Clustering columns determine sort order within partition. Secondary indexes on low-cardinality columns. Materialized views for alternate queries (controlled denormalization). No JOINs: embed or duplicate data.',
     'technical', 'medium', 'organization', 1, 'custom', 20, true),
    
    (70, 'Design a caching strategy using Redis for a high-traffic e-commerce site. Include cache invalidation, eviction policies, and data structures.',
     'Strategy: (1) Cache layers: L1 (application memory - LRU cache), L2 (Redis cluster). (2) Data structures: Strings for simple values, Hashes for objects (user:{id}:profile), Sorted Sets for leaderboards/ranking, Lists for recent items, Sets for tags/categories. (3) Patterns: Cache-aside (app manages), Read-through, Write-through, Write-behind. (4) TTL: product details (1 hour), cart (24 hours), session (30 min). (5) Invalidation: on update (delete key or publish event), version-based keys. (6) Eviction: maxmemory-policy=allkeys-lru. (7) High availability: Redis Sentinel or Cluster. (8) Prewarming: populate cache for popular items. Monitor hit rate, adjust TTLs.',
     'technical', 'hard', 'organization', 1, 'custom', 25, true),

    -- Topic 15: Microservices Architecture (5 questions)
    (71, 'What are microservices? How do they differ from monolithic architecture?',
     'Microservices: architectural style where application is collection of small, independent services, each running in own process, communicating via lightweight protocols (HTTP/gRPC). Each service: single business capability, independently deployable, owns its data. Monolith: single deployable unit, shared database, tightly coupled. Advantages: independent scaling, technology freedom, fault isolation, faster deployment. Disadvantages: distributed system complexity, network latency, data consistency challenges, operational overhead. Use microservices when: domain is complex, team is large, need independent scaling. Use monolith when: starting out, small team, simple domain.',
     'technical', 'easy', 'organization', 1, 'custom', 8, true),
    
    (72, 'Explain service discovery in microservices. Compare client-side and server-side discovery patterns.',
     'Service discovery: mechanism to locate service instances dynamically. Client-side discovery: client queries service registry (Consul, Eureka), gets available instances, uses load balancing algorithm to select one. Examples: Netflix Eureka. Server-side discovery: client makes request to load balancer/router, which queries registry and forwards request. Examples: Kubernetes Service, AWS ELB. Client-side: more control, no single point of failure in forwarding, client handles load balancing. Server-side: simpler client, centralized control, can use infrastructure load balancers. Health checks ensure only healthy instances returned.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (73, 'How would you handle distributed transactions in microservices? Explain the Saga pattern.',
     'Distributed transactions challenge: each service has own database, 2PC not practical (blocking, complexity). Saga pattern: sequence of local transactions, each service updates own database and publishes event/message for next step. Two approaches: (1) Choreography: each service listens for events, takes action, publishes events (decentralized, simple, but hard to track). (2) Orchestration: central coordinator directs saga, calls services (easier to understand, single point of failure). Compensation: for failures, execute compensating transactions in reverse order. Example: order saga - create order, reserve inventory, charge payment. If payment fails, release inventory, cancel order. Use status tracking, idempotent operations.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (74, 'Explain the API Gateway pattern. What problems does it solve and what are potential drawbacks?',
     'API Gateway: single entry point for clients, routes requests to appropriate microservices. Responsibilities: request routing, composition (aggregating multiple services), protocol translation (REST to gRPC), authentication/authorization, rate limiting, caching, monitoring, request/response transformation. Benefits: simplified client, reduced round trips (aggregation), centralized cross-cutting concerns, backend service evolution without client changes. Drawbacks: potential bottleneck, single point of failure (mitigate with clustering), increased latency, complexity. Examples: Kong, NGINX, AWS API Gateway, Spring Cloud Gateway. Advanced: BFF (Backend for Frontend) pattern - separate gateway per client type.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (75, 'Design a microservices architecture for an e-commerce platform. Include inter-service communication, data consistency, and failure handling.',
     'Services: UserService, ProductService, OrderService, PaymentService, InventoryService, NotificationService. Communication: synchronous (REST/gRPC) for queries, asynchronous (message queue - RabbitMQ/Kafka) for events. Data: each service owns database (polyglot persistence), eventual consistency. Order flow: (1) OrderService creates order (PENDING), publishes OrderCreated event. (2) InventoryService reserves stock, publishes InventoryReserved. (3) PaymentService charges, publishes PaymentCompleted. (4) OrderService updates to CONFIRMED. Failure handling: Saga pattern for rollback, circuit breaker (Hystrix/Resilience4j) for cascading failures, retries with exponential backoff, dead letter queues. Service mesh (Istio) for observability, mTLS, rate limiting.',
     'technical', 'hard', 'organization', 1, 'custom', 25, true),

    -- Topic 16: Message Queues (5 questions)
    (76, 'Explain the difference between message queues and publish-subscribe patterns.',
     'Message Queue: point-to-point, one producer to one consumer, message consumed once, queue stores messages until processed (e.g., RabbitMQ queues). Pub-Sub: one-to-many, publishers send to topic, multiple subscribers receive copy (e.g., Kafka topics). Queue: task distribution (load balancing workers), guaranteed processing, order possible. Pub-Sub: event broadcasting, multiple consumers need same data, scalable fan-out. Examples: Queue for job processing (one worker handles), Pub-Sub for user signup (email service, analytics service, CRM all notified). Some systems support both (RabbitMQ exchanges).',
     'technical', 'easy', 'organization', 1, 'custom', 7, true),
    
    (77, 'Compare RabbitMQ and Apache Kafka. When would you use each?',
     'RabbitMQ: message broker, supports multiple protocols (AMQP, MQTT, STOMP), complex routing (exchanges, bindings), message acknowledgments, low latency, limited message retention. Kafka: distributed streaming platform, append-only log, high throughput, message retention (time/size based), consumer offset control, replayable. Use RabbitMQ for: task queues, request/reply patterns, complex routing, low latency needs, traditional messaging. Use Kafka for: event streaming, log aggregation, real-time analytics, high throughput, need to replay messages, event sourcing. RabbitMQ is "smart broker, dumb consumer", Kafka is "dumb broker, smart consumer".',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (78, 'Explain message acknowledgment and delivery guarantees (at-most-once, at-least-once, exactly-once).',
     'At-most-once: fire and forget, no acknowledgment, message may be lost but never delivered twice. At-least-once: consumer acknowledges after processing, broker retries if no ack, may deliver duplicates (need idempotent processing). Exactly-once: message delivered and processed exactly once, hardest to achieve. Implementation: At-most-once - auto-ack before processing. At-least-once - manual ack after processing, use message IDs to detect duplicates. Exactly-once - requires transactional semantics, consumer stores processed message IDs in same transaction as business logic (Kafka transactions + idempotent producer). Most systems default at-least-once with idempotent consumers.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (79, 'How would you handle message ordering in a distributed message queue system?',
     'Challenges: parallel consumers break order, network delays, retries. Solutions: (1) Single consumer (limits throughput). (2) Partition by key (Kafka): messages with same key go to same partition, ordered within partition, parallel across partitions. (3) Message groups (RabbitMQ): group ID ensures messages in same group go to same consumer. (4) Sequence numbers: add sequence number, consumer reorders if needed. (5) Queue per entity: separate queue for each order/user maintains order. Trade-offs: strict ordering vs throughput. Best practice: design for eventual consistency, only order where business requires (e.g., state transitions).',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (80, 'Design a resilient async task processing system using message queues. Include retry logic, dead letter queues, and monitoring.',
     'Architecture: Producer → Queue → Consumer Workers. Components: (1) Main queue for new tasks, (2) Retry queue with delayed redelivery, (3) Dead Letter Queue (DLQ) for failed tasks after max retries, (4) Processing: consumer pulls message, processes with timeout, acks on success. (5) Retry logic: on failure, increment retry count in message headers, if < max_retries publish to retry queue with exponential backoff delay, else send to DLQ. (6) Monitoring: track queue depth, processing time, error rates, DLQ accumulation. (7) DLQ handling: alerts, manual review, optionally reprocess. (8) Idempotency: use message ID or business key to prevent duplicate processing. Use circuit breaker for external dependencies.',
     'technical', 'hard', 'organization', 1, 'custom', 25, true),

    -- Topic 17: Caching Strategies (5 questions)
    (81, 'Explain different caching strategies: cache-aside, read-through, write-through, write-behind.',
     'Cache-aside (lazy loading): app checks cache, if miss loads from DB and populates cache. Read-through: cache handles DB reads, transparent to app. Write-through: writes go to cache and DB synchronously, data always consistent. Write-behind (write-back): writes go to cache, async batch write to DB, faster writes but risk of data loss. Use cache-aside for: general purpose, control over cache logic. Read-through for: read-heavy, simplify app. Write-through for: consistency critical. Write-behind for: write-heavy, can tolerate temporary inconsistency. Most common: cache-aside for reads, write-through for writes.',
     'technical', 'easy', 'organization', 1, 'custom', 10, true),
    
    (82, 'What is cache invalidation? Explain strategies and the challenges involved.',
     'Cache invalidation: removing/updating stale data. Hardest problem in computer science. Strategies: (1) TTL/expiration: time-based, simple but may serve stale data. (2) Event-based: invalidate on updates, requires coordination. (3) Write-through: update cache on write, consistent. (4) Cache busting: version keys (user:123:v2), immutable. Challenges: distributed systems (invalidation across instances), race conditions, thundering herd (many requests on cache miss), stale data tolerance. Solutions: pub-sub for invalidation events, cache warming, short TTLs for frequently changing data, eventual consistency acceptance. "Only two hard things: cache invalidation and naming things."',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (83, 'Explain cache eviction policies: LRU, LFU, FIFO. When would you use each?',
     'LRU (Least Recently Used): evicts item unused longest, good temporal locality, common choice. LFU (Least Frequently Used): evicts item used least often, good for stable popular items, but recently added items disadvantaged. FIFO (First In First Out): evicts oldest item regardless of usage, simple but ignores access patterns. Others: Random (simple, surprisingly effective), LRU-K (considers K recent accesses), 2Q (two queues). Use LRU for: general purpose, bursty access patterns. LFU for: stable hotspots, long-term popularity. FIFO for: simple cases, circular buffers. Most caches use LRU approximations (Redis: LRU with sampling).',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (84, 'How would you implement a distributed cache? Discuss consistency, partitioning, and failure handling.',
     'Implementation: cluster of cache nodes, data partitioned across nodes. Partitioning: consistent hashing (minimal data movement on node add/remove), virtual nodes for better distribution. Replication: primary-replica for availability, async replication (eventual consistency). Consistency models: (1) Strong: quorum reads/writes (W+R>N), slower. (2) Eventual: async replication, faster, may read stale. Failure handling: (1) node failure: replicas serve, trigger rebuild, (2) network partition: quorum determines availability. Cache client: route requests to correct node (hash key), handle failover. Solutions: Redis Cluster, Memcached with consistent hash client, Hazelcast IMDG. Consider: gossip protocol for membership, read-repair for consistency.',
     'technical', 'medium', 'organization', 1, 'custom', 20, true),
    
    (85, 'Design a multi-level caching strategy for a content delivery platform. Include browser, CDN, application, and database layers.',
     'Layers: (1) Browser cache: static assets (JS, CSS, images), Cache-Control headers (max-age=86400, immutable), versioned filenames for busting. (2) CDN: edge caching (CloudFront, Akamai), cache HTML/API responses, Vary headers for personalization, Cache-Control/s-maxage. (3) Application cache: Redis/Memcached, LRU eviction, user sessions, API responses, TTL 5-60min. (4) Database query cache: MySQL query cache or app-level, TTL 1-5min. Invalidation: (1) Static assets: version URLs, (2) CDN: purge API on updates, (3) App cache: pub-sub events, (4) DB: invalidate on writes. Warming: pre-populate caches for popular content. Monitoring: hit rates per layer, optimize TTLs based on update frequency vs traffic.',
     'technical', 'hard', 'organization', 1, 'custom', 25, true),

    -- Topic 18: API Security (5 questions)
    (86, 'Explain the OAuth 2.0 authorization flow. What are the different grant types?',
     'OAuth 2.0: authorization framework for delegated access. Roles: Resource Owner (user), Client (app), Authorization Server (issues tokens), Resource Server (API). Grant types: (1) Authorization Code: most secure for web apps, involves redirect with code, exchange for token. (2) Implicit: deprecated, token in URL fragment, for SPAs (use PKCE instead). (3) Resource Owner Password: username/password to client, for trusted apps only. (4) Client Credentials: machine-to-machine, no user context. (5) Refresh Token: get new access token without user interaction. Recommended: Authorization Code + PKCE for all clients. Access tokens short-lived, refresh tokens for renewing.',
     'technical', 'easy', 'organization', 1, 'custom', 12, true),
    
    (87, 'What is JWT (JSON Web Token)? Explain its structure and security considerations.',
     'JWT: compact, URL-safe token for claims transmission. Structure: Header.Payload.Signature (base64url encoded). Header: algorithm (HS256/RS256), type. Payload: claims (iss, sub, aud, exp, iat + custom). Signature: HMAC or RSA signature for integrity. Use cases: stateless authentication, information exchange. Security: (1) Always verify signature, (2) Check exp (expiration), (3) Validate iss/aud, (4) Use HTTPS only, (5) Short expiration for access tokens, (6) Store securely (httpOnly cookies, not localStorage for XSS risk). Issues: no built-in revocation (use short TTL, maintain blocklist), token size (include minimal claims). Alternative: opaque tokens with server-side validation.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (88, 'Explain common API security vulnerabilities and how to prevent them (SQL injection, XSS, CSRF, etc.).',
     'Vulnerabilities: (1) SQL Injection: use parameterized queries/ORMs, never concatenate user input. (2) XSS (Cross-Site Scripting): sanitize output, use Content-Security-Policy headers, escape HTML. (3) CSRF: use CSRF tokens, SameSite cookies, verify Origin/Referer headers. (4) Broken Authentication: strong password policies, MFA, secure session management, account lockout. (5) Sensitive Data Exposure: encrypt at rest/transit (TLS), hash passwords (bcrypt), minimize data collection. (6) XXE: disable XML external entities, use JSON. (7) IDOR (Insecure Direct Object Reference): check authorization for every resource. (8) Rate limiting: prevent DoS/brute force. Use security headers, input validation, principle of least privilege.',
     'technical', 'medium', 'organization', 1, 'custom', 20, true),
    
    (89, 'How would you implement API key management and rotation for a public API with thousands of clients?',
     'Implementation: (1) Generate cryptographically secure random keys (UUID v4 or crypto.randomBytes). (2) Store hashed (SHA-256) in database, never plaintext. (3) Include metadata: client_id, created_at, expires_at, last_used, rate_limit_tier. (4) Authentication: client sends key in Authorization header (Bearer or X-API-Key), server hashes and looks up. (5) Rotation: support multiple active keys per client, set expiration warnings via headers (X-API-Key-Expiring), force rotation annually. (6) Revocation: soft delete (mark revoked), hard delete after grace period. (7) Monitoring: log usage, detect anomalies (unusual traffic, geography). (8) Tiers: different rate limits per plan. Security: audit logs, alert on suspicious activity, IP whitelisting option.',
     'technical', 'medium', 'organization', 1, 'custom', 20, true),
    
    (90, 'Design a comprehensive security strategy for securing microservices communication. Include authentication, authorization, encryption, and monitoring.',
     'Strategy: (1) mTLS (mutual TLS): service-to-service encryption and authentication, certificate-based identity, automatic with service mesh (Istio, Linkerd). (2) Service-level authentication: each service has identity (JWT), API gateway validates user, propagates context. (3) Authorization: (a) RBAC/ABAC at API gateway, (b) fine-grained at service level, (c) policy engine (OPA - Open Policy Agent). (4) API gateway: single entry point, terminates TLS, validates tokens, rate limiting. (5) Secrets management: vault (HashiCorp Vault, AWS Secrets Manager), dynamic secrets, automatic rotation. (6) Network segmentation: zero trust, segmented VPCs, firewall rules. (7) Monitoring: request tracing (Jaeger), audit logs, anomaly detection, SIEM integration. (8) Defense in depth: WAF, DDoS protection, vulnerability scanning.',
     'technical', 'hard', 'organization', 1, 'custom', 25, true),

    -- Topic 19: Server-Side Performance (5 questions)
    (91, 'What is the difference between vertical and horizontal scaling? When would you use each?',
     'Vertical scaling (scale-up): add more resources (CPU, RAM, storage) to existing machine. Advantages: simple, no code changes, strong consistency. Disadvantages: hardware limits, single point of failure, downtime for upgrades, expensive. Horizontal scaling (scale-out): add more machines to pool. Advantages: unlimited scaling, fault tolerance, cost-effective. Disadvantages: complexity (load balancing, data distribution), eventual consistency, stateless application required. Use vertical when: starting out, simple architecture, stateful operations, cost-effective for moderate scale. Use horizontal when: high availability needed, unpredictable load, cloud-native, large scale. Modern approach: horizontal for application tier, vertical for databases (with read replicas).',
     'technical', 'easy', 'organization', 1, 'custom', 10, true),
    
    (92, 'Explain connection pooling for databases. Why is it important and how do you configure it?',
     'Connection pooling: reusable set of database connections, avoids expensive connection creation overhead. Process: (1) pool creates min connections on startup, (2) app requests connection from pool, (3) use for queries, (4) return to pool (not close), (5) pool maintains up to max connections. Benefits: reduced latency (no connection handshake), limited connections (protect DB), connection reuse. Configuration: (1) min/max pool size: min = sustained load connections, max = peak + buffer (PostgreSQL ~100-200, MySQL ~150-300 per instance), (2) timeout: max wait for connection, (3) idle timeout: close idle connections, (4) validation query: test connection health. Tuning: monitor connection usage, avoid leaks (always close connections), use async/await or try-with-resources.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (93, 'How would you identify and fix N+1 query problems in ORM-based applications?',
     'N+1 problem: loading parent records (1 query) + separate query for each parent''s relationships (N queries). Example: load 100 users, then query posts for each user = 101 queries. Detection: (1) log SQL queries, (2) profiler tools (Django Debug Toolbar, Rails Bullet), (3) APM tools (New Relic), (4) slow API monitoring. Solutions: (1) Eager loading: load related data upfront (SQLAlchemy joinedload, Django select_related for FK, prefetch_related for M2M). (2) Batch loading: fetch all needed IDs, single WHERE IN query. (3) DataLoader pattern (GraphQL). (4) Denormalization: include needed data in parent table. (5) Caching. Example fix: User.query.options(joinedload(User.posts)).all() loads users and posts in 1-2 queries.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (94, 'Explain different types of load balancing algorithms and when to use each.',
     'Algorithms: (1) Round Robin: distribute requests sequentially, simple, fair if servers equal. (2) Weighted Round Robin: weight by server capacity, good for heterogeneous servers. (3) Least Connections: route to server with fewest connections, good for varying request durations. (4) Weighted Least Connections: combines weights and connections. (5) IP Hash: hash client IP, ensures same client → same server, good for sessions (but sticky sessions preferred). (6) Least Response Time: route to fastest server. (7) Random: surprisingly effective, simple. Use Round Robin for: similar servers, stateless apps. Least Connections for: long-lived connections, variable loads. IP Hash for: stickiness, but prefer cookie-based. Layer 4 (TCP) vs Layer 7 (HTTP): L7 can route by URL, headers, cookies.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (95, 'Design a high-performance backend system to handle 100,000 requests per second. Include architecture, database, caching, and scaling strategies.',
     'Architecture: (1) Load balancer (HAProxy, AWS ALB) with auto-scaling. (2) Stateless application servers (horizontal scaling, Docker/K8s). (3) Caching layer: Redis cluster for hot data (sessions, frequently accessed). (4) Database: PostgreSQL primary-replicas (write to primary, read from replicas), connection pooling (PgBouncer), partitioning for hot tables. (5) Async processing: message queue (Kafka) for background tasks. (6) CDN for static assets. Optimizations: (1) minimize DB queries (batch, cache), (2) database indexes, (3) denormalization for reads, (4) API response compression (gzip), (5) keep-alive connections, (6) use HTTP/2. Monitoring: metrics (Prometheus), tracing (Jaeger), logging (ELK), alerts. Scaling: horizontal app servers, vertical DB, read replicas, sharding if needed. Benchmark and load test.',
     'technical', 'hard', 'organization', 1, 'custom', 25, true),

    -- Topic 20: Backend Testing (5 questions)
    (96, 'Explain the testing pyramid. What are unit, integration, and end-to-end tests?',
     'Testing pyramid: many unit tests (base), fewer integration tests (middle), few E2E tests (top). Unit tests: test individual functions/methods in isolation, mock dependencies, fast, high coverage. Integration tests: test interaction between components (API + database), verify contracts, moderate speed. E2E tests: test entire system from user perspective, UI to database, slow, brittle, few critical paths. Ratio: 70% unit, 20% integration, 10% E2E. Benefits: unit tests find bugs early, fast feedback, integration verify contracts, E2E ensure real workflows work. Anti-pattern: ice cream cone (inverted pyramid, too many E2E).',
     'technical', 'easy', 'organization', 1, 'custom', 10, true),
    
    (97, 'How would you implement mocking in tests? Compare different mocking strategies.',
     'Mocking: replace dependencies with controlled test doubles. Types: (1) Mock: object with expectations, verifies interactions ("was this method called?"). (2) Stub: returns predefined responses, verifies state. (3) Spy: wraps real object, records calls. (4) Fake: simplified working implementation (in-memory DB). Strategies: (1) Dependency injection: pass dependencies, inject mocks in tests. (2) Testing libraries: Jest (jest.fn, jest.mock), Python unittest.mock, Mockito (Java). Example: mock external API, database, time.now(). Best practices: don''t over-mock (test behavior not implementation), prefer fakes for complex systems, verify important interactions, reset mocks between tests. Mock at boundaries (external services), use real implementations for internal components.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (98, 'Explain test-driven development (TDD). What are the benefits and challenges?',
     'TDD: write test before implementation. Cycle: (1) Red - write failing test, (2) Green - write minimal code to pass, (3) Refactor - improve code while keeping tests green. Benefits: (1) better design (testable code), (2) high coverage, (3) living documentation, (4) confidence in refactoring, (5) prevents over-engineering. Challenges: (1) learning curve, (2) slower initially, (3) hard for unclear requirements, (4) testing UI difficult. When to use: clear requirements, complex logic, refactoring legacy code. When not: prototyping, UI-heavy, exploration. Keys: write simple tests, incremental approach, refactor aggressively. TDD != 100% coverage goal, focus on business logic.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (99, 'How would you test database-dependent code? Discuss different approaches and trade-offs.',
     'Approaches: (1) Mocks: fast, isolated, but don''t test real SQL/constraints. (2) In-memory DB: (H2, SQLite) fast, but different behavior from production DB. (3) Test containers: real DB (Docker), accurate, slower. (4) Shared test DB: realistic but state management hard. Best practice: (1) Unit tests: mock repository layer. (2) Integration tests: real DB (test containers), test repositories with actual queries. (3) Use transactions: rollback after each test for isolation. (4) Test data: fixtures or factory libraries (FactoryBot, Faker). (5) Separate test DB from dev. Trade-offs: mocks (fast, less confidence) vs real DB (accurate, slower). Recommended: mock in unit tests, real DB in integration tests. Use database migrations in tests.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (100, 'Design a testing strategy for a microservices-based e-commerce system. Include contract testing, chaos engineering, and test environments.',
     'Strategy: (1) Unit tests (70%): each service, mock external dependencies. (2) Contract tests: verify API contracts between services (Pact), consumer-driven, catch breaking changes early. (3) Integration tests: service + database + message queue. (4) Component tests: single service with all dependencies (test containers). (5) E2E tests (<5%): critical user flows across services. (6) Contract tests: provider verifies consumer contracts. (7) Load/performance tests: simulate realistic load. (8) Chaos engineering: deliberately fail services (Chaos Monkey), test resilience, verify fallbacks. Environments: (1) local: Docker Compose, (2) dev: deployed services, (3) staging: production-like, (4) production: canary/blue-green deployments. CI/CD: tests in pipeline, deploy after passing. Monitor in production, feature flags for rollback.',
     'technical', 'hard', 'organization', 1, 'custom', 25, true),

    -- ============================================================================
    -- PART 3: Frontend Engineering Topics (Topics 21-35)
    -- ============================================================================

    -- Topic 21: JavaScript (5 questions)
    (101, 'Explain the difference between var, let, and const in JavaScript.',
     'var is function-scoped, hoisted to function top, and can be re-declared. let is block-scoped, hoisted but not initialized (temporal dead zone), cannot be re-declared in same scope. const is block-scoped like let but creates immutable binding (not immutable value for objects/arrays). Best practices: prefer const by default, use let when reassignment needed, avoid var. Example: const obj = {a: 1}; obj.a = 2 works (object mutable), but obj = {} fails (binding immutable). Block scope: variables in {} blocks only accessible within that block.',
     'technical', 'easy', 'organization', 1, 'custom', 5, true),
    
    (102, 'Explain JavaScript closures and provide a practical use case.',
     'Closure is a function that has access to its outer function''s scope even after the outer function has returned. Created when nested function references outer variables. Practical uses: (1) Data privacy/encapsulation - private variables via IIFE or module pattern. (2) Function factories - createMultiplier(n) returns function that multiplies by n. (3) Event handlers - preserving state in asynchronous callbacks. (4) Partial application and currying. Example: function counter() { let count = 0; return () => ++count; } creates private count variable. Closures maintain reference to outer scope, enabling powerful patterns but can cause memory leaks if not managed properly.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (103, 'What is the event loop in JavaScript? Explain how async operations work with call stack, callback queue, and microtask queue.',
     'Event loop enables asynchronous JavaScript execution. Call stack executes synchronous code. When async operation (setTimeout, fetch) starts, it''s delegated to Web APIs. Upon completion, callback goes to task queue (macrotasks). Microtask queue (promises, queueMicrotask) has higher priority. Event loop: (1) Execute all synchronous code in call stack, (2) Process all microtasks (promises), (3) Execute one macrotask (setTimeout, setInterval), (4) Repeat. Example: setTimeout(() => console.log(''timeout''), 0); Promise.resolve().then(() => console.log(''promise'')); console.log(''sync''); outputs: sync, promise, timeout. Understanding this is crucial for debugging async code and avoiding race conditions.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (104, 'Explain prototypal inheritance in JavaScript. How does it differ from classical inheritance?',
     'JavaScript uses prototype chain for inheritance. Every object has internal [[Prototype]] link (accessed via __proto__ or Object.getPrototypeOf). When accessing property, JS searches object, then its prototype chain until found or reaches null. Classical inheritance (Java/C++): classes are blueprints, objects are instances, based on class hierarchies. Prototypal: objects inherit directly from other objects, more flexible. Creation patterns: (1) Constructor functions with .prototype, (2) Object.create(), (3) ES6 classes (syntactic sugar over prototypes). Example: const animal = {eats: true}; const dog = Object.create(animal); dog.barks = true. Modern approach: use ES6 classes for clarity while understanding underlying prototype mechanism.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (105, 'Design a custom Promise implementation from scratch. Explain state management, chaining, and error handling.',
     'Custom Promise class needs: (1) States: pending, fulfilled, rejected. (2) Value/reason storage. (3) Handler queues for async resolution. Implementation: constructor takes executor(resolve, reject). Resolve/reject methods transition state (once only), store value, flush handlers. then(onFulfilled, onRejected) returns new Promise, queues handlers if pending, executes immediately if settled. Chain by resolving next Promise with handler return value. Catch is syntactic sugar for then(null, onRejected). Key challenges: (1) State immutability - once settled, cannot change. (2) Async handling - store callbacks if not yet resolved. (3) Chaining - each then returns new Promise. (4) Error propagation - rejected Promise without catch propagates to next catch. (5) Microtask queue - use queueMicrotask for spec compliance. This demonstrates deep understanding of async patterns.',
     'technical', 'hard', 'organization', 1, 'custom', 25, true),

    -- Topic 22: TypeScript (5 questions)
    (106, 'What are the main benefits of using TypeScript over JavaScript?',
     'TypeScript adds static typing to JavaScript, catching errors at compile-time rather than runtime. Key benefits: (1) Type safety - prevents type-related bugs, enforces contracts. (2) Better IDE support - autocomplete, refactoring, navigation. (3) Self-documenting code - types serve as inline documentation. (4) Safer refactoring - compiler catches breaking changes. (5) Modern features - interfaces, enums, generics, decorators. (6) Gradual adoption - .js files work in .ts projects. (7) Better for large codebases and teams. Trade-offs: additional build step, learning curve, verbose for simple scripts. Best for: complex applications, team projects, long-term maintenance.',
     'technical', 'easy', 'organization', 1, 'custom', 6, true),
    
    (107, 'Explain TypeScript generics and provide examples of their use in functions and classes.',
     'Generics enable writing reusable, type-safe code for multiple types. Function example: function identity<T>(arg: T): T { return arg; } preserves type. Array methods use generics: Array<T>, Promise<T>. Class example: class Box<T> { constructor(public value: T) {} }. Constraints: <T extends Comparable> restricts T to types with comparison. Multiple type parameters: Map<K, V>. Default types: <T = string>. Benefits: (1) Type safety without hardcoding, (2) Reusability, (3) Better inference. Real-world: API response wrapper: interface Response<T> { data: T; error?: string; }. Avoid over-engineering with too many generic parameters. Use when function/class works with multiple types while maintaining type relationships.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (108, 'What are utility types in TypeScript? Explain Partial, Pick, Omit, and Record with examples.',
     'Utility types transform existing types. Partial<T>: makes all properties optional - useful for update operations. Pick<T, K>: creates type with subset of properties. Omit<T, K>: creates type excluding specified properties. Record<K, V>: creates object type with keys K and values V. Examples: type User = {id: number; name: string; email: string;}; type PartialUser = Partial<User> allows {name: "John"}. type UserPreview = Pick<User, "id" | "name"> excludes email. type UserWithoutEmail = Omit<User, "email">. type StringMap = Record<string, string> for dictionaries. Others: Required<T>, Readonly<T>, ReturnType<T>, Parameters<T>. These eliminate boilerplate, maintain type safety, and make code more maintainable.',
     'technical', 'medium', 'organization', 1, 'custom', 10, true),
    
    (109, 'Explain the difference between interface and type in TypeScript. When should you use each?',
     'Both define object shapes but with differences. Interface: (1) Declaration merging - multiple declarations combine, (2) Only for object shapes, (3) extends keyword for inheritance, (4) Better error messages. Type: (1) More flexible - unions, intersections, primitives, tuples, (2) No declaration merging, (3) Uses & for intersection, | for union, (4) Can alias any type. Use interface when: extending existing types, public API (declaration merging useful), object-oriented patterns. Use type when: unions (type ID = string | number), tuples, complex transformations, utility type compositions. Modern convention: prefer interface for object shapes, type for everything else. Example: type Status = "active" | "inactive"; interface User extends BaseUser { status: Status; }. Both work similarly for most cases, consistency matters more.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (110, 'Design a type-safe event emitter system in TypeScript using advanced types. Support multiple event types with strict typing.',
     'Implementation: type EventMap = { message: { text: string; userId: number }; login: { username: string }; }. class TypedEventEmitter<T extends Record<string, any>> { private listeners: { [K in keyof T]?: Array<(data: T[K]) => void> } = {}; on<K extends keyof T>(event: K, handler: (data: T[K]) => void) { this.listeners[event] = [...(this.listeners[event] || []), handler]; } emit<K extends keyof T>(event: K, data: T[K]) { this.listeners[event]?.forEach(h => h(data)); } }. Usage: const emitter = new TypedEventEmitter<EventMap>(); emitter.on("message", (data) => { console.log(data.text); }); // data is correctly typed. Key concepts: mapped types, conditional types, keyof operator, indexed access types. This ensures compile-time safety: wrong event names or data shapes caught immediately. Extends to remove listeners, once(), type guards for event filtering.',
     'technical', 'hard', 'organization', 1, 'custom', 25, true),


    -- Topic 23: React (5 questions continuing frontend)
    (111, 'Explain the difference between props and state in React.',
     'Props are immutable data passed from parent to child components, similar to function parameters. Read-only from child''s perspective, flow down the component tree (unidirectional data flow). State is mutable data managed within a component, can change over time in response to user actions or network responses. Changes to state trigger re-renders. Use props for: configuring components, passing data down, callbacks. Use state for: data that changes over time, user input, component-specific data. Example: <UserProfile name={userName} /> - name is prop. Inside UserProfile, const [showDetails, setShowDetails] = useState(false) - showDetails is state. Modern React uses hooks (useState, useReducer) for state management.',
     'technical', 'easy', 'organization', 1, 'custom', 6, true),
    
    (112, 'What is the Virtual DOM? How does React''s reconciliation algorithm work?',
     'Virtual DOM is lightweight JavaScript representation of actual DOM. When state changes, React creates new virtual DOM tree, compares (diffs) with previous tree, calculates minimal changes needed, and updates only changed parts in real DOM. Reconciliation: (1) Element type differs - unmount old, mount new tree. (2) Same element type - update changed attributes only. (3) Component elements - instance stays, update props, trigger re-render. (4) Recursively reconcile children. Keys: help React identify which items changed, added, or removed in lists. Without keys, React uses index causing bugs when reordering. Benefits: improved performance by batching DOM updates, declarative programming model. React Fiber (v16+): incremental rendering, can pause/resume work, prioritize updates. Understanding reconciliation helps optimize with React.memo, useMemo, useCallback.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (113, 'Explain React hooks lifecycle. How do useEffect cleanup functions work?',
     'useEffect runs after render (by default). Dependency array controls when it runs: [] runs once (mount), [dep] runs when dep changes, no array runs every render. Cleanup function: returned function from useEffect, runs before effect re-runs and on unmount. Use for: clearing timers, canceling subscriptions, removing event listeners. Example: useEffect(() => { const timer = setTimeout(...); return () => clearTimeout(timer); }, []). Execution order: (1) Render phase, (2) React commits to DOM, (3) useLayoutEffect runs synchronously, (4) Browser paints, (5) useEffect runs asynchronously. On unmount/re-run: previous cleanup runs first, then new effect. Common patterns: data fetching with AbortController cleanup, WebSocket connection cleanup, resize listener cleanup. Understanding this prevents memory leaks and stale closures.',
     'technical', 'medium', 'organization', 1, 'custom', 12, true),
    
    (114, 'What are React render props and higher-order components (HOCs)? Compare them with hooks.',
     'Render Props: component takes function prop that returns React element, enables sharing logic. Example: <DataProvider render={(data) => <Display data={data} />} />. HOCs: functions that take component and return enhanced component. Example: withAuth(UserProfile) wraps authentication logic. Used for cross-cutting concerns: authentication, logging, error boundaries (pre-hooks era). Hooks advantages: (1) Simpler composition, no wrapper hell, (2) Easier to understand data flow, (3) No naming collisions, (4) Better TypeScript support, (5) Better tree shaking. When to still use: (1) Error boundaries (no hook equivalent), (2) Class component patterns, (3) Third-party libraries. Modern React prefers hooks (custom hooks like useAuth). HOCs/render props still valid but less common. Migration path: convert HOC logic to custom hooks.',
     'technical', 'medium', 'organization', 1, 'custom', 15, true),
    
    (115, 'Design a custom React hook for managing complex form state with validation, field-level errors, and submission handling.',
     'Implementation: function useForm<T>(initialValues: T, validate: (values: T) => Errors) { const [values, setValues] = useState(initialValues); const [errors, setErrors] = useState({}); const [touched, setTouched] = useState({}); const [isSubmitting, setSubmitting] = useState(false); const handleChange = (name: keyof T) => (e) => { setValues({...values, [name]: e.target.value}); }; const handleBlur = (name: keyof T) => () => { setTouched({...touched, [name]: true}); setErrors(validate(values)); }; const handleSubmit = async (onSubmit) => { setSubmitting(true); const validationErrors = validate(values); if (Object.keys(validationErrors).length === 0) await onSubmit(values); else setErrors(validationErrors); setSubmitting(false); }; return { values, errors, touched, handleChange, handleBlur, handleSubmit, isSubmitting }; }. Features: field tracking, validation on blur, show errors only after touch, async submission, TypeScript generics. Extend with: reset form, field arrays, async validation, custom validators.',
     'technical', 'hard', 'organization', 1, 'custom', 25, true),

    -- Topic 24: Vue.js (5 questions)
    (116, 'What is the Composition API in Vue 3 and how does it differ from Options API? When would you use each?',
     'Composition API organizes component logic by feature using setup() function. Options API organizes by option type (data, methods, computed). Composition API benefits: better code organization for complex components, easier logic reuse via composables, superior TypeScript support, better tree-shaking. Example: setup() { const count = ref(0); const increment = () => count.value++; return { count, increment }; }. Use Composition API for: complex components, shared logic across components, TypeScript projects. Use Options API for: simple components, teams familiar with Vue 2, rapid prototyping. Both supported in Vue 3, can mix in same project.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (117, 'Explain reactivity in Vue 3. How do ref() and reactive() differ? What are the gotchas?',
     'Vue 3 uses ES6 Proxy for reactivity. ref() wraps primitives or objects, accessed via .value in script (auto-unwrapped in templates). reactive() creates reactive proxy of objects only. Differences: ref needs .value, reactive does not; ref works with primitives, reactive only objects; destructuring reactive loses reactivity (use toRefs()). Gotchas: forgetting .value with ref, replacing entire reactive object breaks reactivity, reactive cannot track primitive types. Best practice: ref for primitives and single values, reactive for object state, toRefs() when returning from composable for destructuring.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (118, 'How would you implement a custom Vue directive for click-outside detection? Include lifecycle hooks and edge cases.',
     'Implementation: app.directive("click-outside", { mounted(el, binding) { el.clickOutsideEvent = (event) => { if (!(el === event.target || el.contains(event.target))) { binding.value(event); } }; document.addEventListener("click", el.clickOutsideEvent); }, unmounted(el) { document.removeEventListener("click", el.clickOutsideEvent); } }). Usage: <div v-click-outside="closeDropdown">. Edge cases: (1) Event timing - use nextTick or setTimeout to prevent immediate trigger, (2) Multiple nested elements with directive, (3) Touch events on mobile - add touchstart listener, (4) Iframe clicks - cannot detect without iframe cooperation. Improvements: accept options for event types, stopPropagation handling, conditional enabling.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (119, 'Compare Pinia and Vuex. What are the architectural differences and migration considerations?',
     'Pinia is Vue 3 official state management. Key differences: Pinia has no mutations (only actions), better TypeScript inference, modular by design (no single store), simpler API, supports Vue DevTools. Vuex structure: state, getters, mutations (synchronous), actions (async). Pinia: state, getters, actions (sync/async). Migration: mutations become actions, modules become separate stores, no namespacing needed (import specific stores). Pinia advantages: less boilerplate, automatic code splitting, better DX. Use Vuex for: existing large Vue 2 apps. Use Pinia for: new projects, Vue 3 apps, TypeScript projects. Migration strategy: gradual - create Pinia stores alongside Vuex, migrate module by module.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (120, 'Design a Vue 3 plugin for multi-tenant applications with runtime theme switching, i18n integration, and tenant-specific feature flags.',
     'Plugin structure: const tenantPlugin = { install(app, options) { const tenant = reactive({ id: null, theme: {}, locale: "en", features: {} }); const loadTenant = async () => { const data = await fetch(options.apiUrl + "/tenant").then(r => r.json()); Object.assign(tenant, data); applyTheme(tenant.theme); }; const applyTheme = (theme) => { Object.entries(theme).forEach(([key, value]) => { document.documentElement.style.setProperty(`--${key}`, value); }); }; const hasFeature = (feature) => tenant.features[feature] === true; app.provide("tenant", readonly(tenant)); app.provide("switchTheme", applyTheme); app.config.globalProperties.$tenant = tenant; app.config.globalProperties.$hasFeature = hasFeature; loadTenant(); } }. Usage: const tenant = inject("tenant"); if (tenant.features.darkMode) {...}. Integration: i18n instance receives tenant.locale, theme object updates CSS custom properties, feature flags control component rendering.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 25: Angular (5 questions)
    (121, 'Explain dependency injection in Angular. How does the hierarchical injector system work?',
     'Angular DI provides dependencies to classes via constructor injection. Hierarchical injector: Module injector (root), Component injector tree. Service provided in root creates singleton. Component-level provides creates instance per component. Resolution: searches upward from component to root. providedIn: "root" makes service tree-shakeable. Use @Injectable({ providedIn: "root" }) for singletons, component providers for isolated instances. Example: constructor(private userService: UserService) {}. Benefits: testability (easy mocking), loose coupling, reusability. Advanced: multi-providers for plugin systems, InjectionToken for non-class dependencies.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (122, 'What is Zone.js and how does it enable change detection? What are alternatives in modern Angular?',
     'Zone.js monkey-patches async APIs (setTimeout, promises, events) to track async operations, triggering change detection when tasks complete. Enables automatic change detection without manual triggering. Overhead: bundles size, runtime cost. Alternatives: Zoneless Angular (experimental) - manual change detection with signals, ChangeDetectorRef.markForCheck(), runOutsideAngular() for performance-critical code. OnPush strategy reduces Zone.js impact - components only check when inputs change or events fire. Future: Angular moving toward signals-based reactivity removing Zone.js dependency. For now: use OnPush, runOutsideAngular for heavy operations, await stable Angular signals API.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (123, 'How do you implement lazy loading with preloading strategies in Angular? Design a custom preloading strategy.',
     'Lazy loading: const routes = [{ path: "admin", loadChildren: () => import("./admin/admin.module").then(m => m.AdminModule) }]. Built-in strategies: NoPreloading (default), PreloadAllModules. Custom strategy: class SelectivePreloadingStrategy implements PreloadingStrategy { preload(route: Route, load: () => Observable<any>): Observable<any> { return route.data?.["preload"] ? load() : of(null); } }. Register: RouterModule.forRoot(routes, { preloadingStrategy: SelectivePreloadingStrategy }). Mark routes: { path: "reports", data: { preload: true }, loadChildren: ... }. Advanced: network-aware preloading, priority-based, analytics-driven (preload popular routes). Monitor with Router events, optimize bundle sizes with webpack-bundle-analyzer.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (124, 'Explain Angular Signals (v16+). How do they improve upon RxJS for state management?',
     'Signals: reactive primitive for fine-grained reactivity. API: signal(initialValue) creates signal, .set(value) or .update(fn) changes value, () reads value in templates. Computed signals: computed(() => count() * 2). Effects: effect(() => console.log(count())). Benefits over RxJS: simpler mental model (no operators), automatic dependency tracking, better performance (granular updates), no subscription management. Use signals for: component state, derived state. Use RxJS for: async operations, complex flows, HTTP requests. Migration: gradual - signals for local state, keep RxJS for async. toSignal() bridges RxJS to signals. Future: signals enable zoneless Angular, better compiler optimizations.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (125, 'Design an Angular micro-frontend architecture using Module Federation. Include shared dependencies, routing, and state management.',
     'Setup: Webpack Module Federation in angular.json. Host app: exposes shell, consumes remotes. Remote apps: expose modules. Config: new ModuleFederationPlugin({ name: "host", remotes: { admin: "admin@http://localhost:4201/remoteEntry.js" }, shared: { "@angular/core": { singleton: true, strictVersion: true } } }). Routing: loadChildren: () => loadRemoteModule({ remoteEntry: "...", remoteName: "admin", exposedModule: "./Module" }). State management: shared services via Module Federation shared scope or message bus (RxJS Subject, custom event bus). Challenges: version conflicts (shared dependencies), deployment (independent deploy but version coordination), auth (cross-app), styling (scoped CSS or shared design system). Solutions: semantic versioning contracts, CI/CD pipelines, shared auth library, CSS custom properties for theming.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 26: HTML/CSS (5 questions)
    (126, 'What is the CSS box model? Explain box-sizing: border-box vs content-box with practical examples.',
     'Box model: content, padding, border, margin. content-box (default): width/height apply to content only. border-box: width/height include padding and border. Example: div { width: 200px; padding: 20px; border: 5px; }. content-box: total width = 250px (200 + 40 + 10). border-box: total width = 200px (content shrinks to 150px). Best practice: *, *::before, *::after { box-sizing: border-box; } for predictable layouts. Use case: creating columns with percentage widths and padding without overflow. Modern frameworks default to border-box.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (127, 'Explain CSS Grid vs Flexbox. When should you use each? Provide a practical use case for CSS Grid.',
     'Flexbox: one-dimensional (row OR column). Grid: two-dimensional (rows AND columns). Use Flexbox for: component layouts, navigation, centering, distributing space along one axis. Use Grid for: page layouts, complex two-dimensional structures, overlapping elements. Grid example: responsive card layout - .container { display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 1rem; }. auto-fit creates as many columns as fit, minmax ensures minimum card width, 1fr distributes remaining space. This creates responsive grid without media queries. Combine both: Grid for overall layout, Flexbox for card internals.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (128, 'How do CSS custom properties (variables) enable dynamic theming? Implement a light/dark mode system.',
     'Custom properties defined with --, accessed via var(). Scope to :root for global or specific selectors for local. Theme implementation: :root { --bg: #fff; --text: #000; }  [data-theme="dark"] { --bg: #1a1a1a; --text: #fff; }. Usage: body { background: var(--bg); color: var(--text); }. JavaScript toggle: document.documentElement.setAttribute("data-theme", theme); localStorage.setItem("theme", theme). Init: respect user preference - const prefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches; const theme = localStorage.getItem("theme") || (prefersDark ? "dark" : "light"). Advantages: runtime changes, cascading inheritance, no preprocessor needed. Use for design tokens, responsive values.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (129, 'What are CSS containment and content-visibility? How do they improve rendering performance?',
     'CSS containment: contain property hints to browser what parts of page are independent, enabling optimizations. Types: size (dimensions don''t depend on children), layout (internal layout doesn''t affect external), paint (element doesn''t paint outside bounds), style (counters/quotes scoped). contain: layout paint improves performance for independent widgets. content-visibility: auto makes offscreen content skip rendering until needed (similar to virtual scrolling). Example: .card { content-visibility: auto; contain-intrinsic-size: 500px; }. contain-intrinsic-size provides size hint preventing layout shift. Benefits: faster initial render, better scroll performance, reduced CPU/GPU work. Use for: long lists, complex widgets, infinite scroll. Caveats: can affect focus navigation, accessibility announcements.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (130, 'Design a responsive CSS architecture using BEM methodology, CSS Modules, and CSS custom properties for a large-scale application.',
     'Architecture layers: (1) Reset/Normalize - consistent baseline. (2) Design tokens - CSS custom properties for colors, spacing, typography in :root. (3) Layout utilities - .container, .grid with spacing scales. (4) Components - BEM naming (.block__element--modifier) or CSS Modules (.module.css files with scoped classes). (5) Utilities - margin, padding, flexbox utilities. Structure: tokens.css (custom properties), layout.module.css, components/Button.module.css. BEM in modules: .button { } .button__icon { } .button--primary { }. Responsive: mobile-first with min-width queries. Build process: PostCSS for autoprefixer, cssnano for minification. Naming convention: components in PascalCase files (Button.module.css), utilities in kebab-case. Benefits: scoped styles (CSS Modules), clear naming (BEM), themeable (custom properties), maintainable for large teams.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 27: State Management (5 questions)
    (131, 'When do you need a state management library vs React Context? What are the trade-offs?',
     'Need state library when: many components share state, complex state logic, need middleware (logging, persistence), time-travel debugging, performance-critical updates. Context: built-in, lightweight, Re-renders all consumers on update. State libraries: Redux (predictable, DevTools, middleware), Zustand (simple hooks API), Jotai/Recoil (atomic state). Context appropriate for: theme, auth, i18n, low-frequency updates. Libraries for: shopping cart, complex forms, real-time data. Performance: Context causes re-renders of all consumers, libraries offer fine-grained subscriptions. Trade-off: Context is simpler but less performant for frequent updates. Modern approach: Context for static/infrequent, Zustand for simpler than Redux, Redux for complex apps needing ecosystem.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (132, 'Explain Redux middleware. How would you implement a custom middleware for API call logging and retry logic?',
     'Middleware: function that intercepts actions before they reach reducer. Signature: store => next => action => {}. Custom logging/retry middleware: const apiMiddleware = store => next => async action => { if (action.type.endsWith("/request")) { console.log("API Request:", action); let retries = 3; while (retries > 0) { try { next(action); const result = await action.payload(); store.dispatch({ type: action.type.replace("/request", "/success"), payload: result }); break; } catch (error) { retries--; if (retries === 0) store.dispatch({ type: action.type.replace("/request", "/failure"), error }); else await delay(1000 * (4 - retries)); } } } else next(action); }. Middleware execution order matters - logging before async. Redux Toolkit: createAsyncThunk handles this pattern.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (133, 'How do you implement optimistic updates with rollback in Redux? Handle concurrent updates and conflicts.',
     'Pattern: (1) Dispatch optimistic action - apply change immediately to local state. (2) Call API. (3) On success - update with server response. (4) On failure - rollback to previous state. Implementation: const optimisticSlice = createSlice({ reducers: { updateStart: (state, action) => { state.previous = current(state.data); state.data = action.payload; }, updateSuccess: (state, action) => { state.data = action.payload; delete state.previous; }, updateFailure: (state) => { state.data = state.previous; delete state.previous; } } }). Concurrent updates: track each operation with unique ID, store pending operations map, apply operations in sequence or last-write-wins. Conflict resolution: timestamp comparison, operational transformation (CRDTs), or manual conflict UI. Use immer for immutable updates, RTK Query handles this automatically with pessimistic/optimistic flags.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (134, 'Compare Zustand, Jotai, and Recoil. What are architectural differences and when to use each?',
     'Zustand: simple hooks API, flux-like state, no providers. Single or multiple stores. store = create(set => ({ count: 0, increment: () => set(s => ({ count: s.count + 1 })) })). Use: const count = useStore(s => s.count). Jotai: atomic state, bottom-up approach. atom(0) creates primitive atom. Use: const [count, setCount] = useAtom(countAtom). atoms compose. Recoil: similar to Jotai, Facebook-backed, more features (persistence, time-travel). selector for derived state. Use Zustand for: simple global state, prefer centralized store, no providers. Use Jotai for: distributed state, lots of derived state, prefer composition. Use Recoil for: complex async queries, need Facebook ecosystem. All avoid Context re-render issues. Performance: similar - subscribe only to used atoms/selectors. Learning curve: Zustand easiest, Jotai/Recoil atomic mindset.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (135, 'Design an offline-first state management architecture with sync queue, conflict resolution, and optimistic UI updates.',
     'Architecture: (1) Local state: IndexedDB for persistence. (2) Sync queue: operations pending upload - { id, type: "create|update|delete", entity, data, timestamp, retries }. (3) State layers: persisted (IndexedDB), optimistic (UI), server (source of truth). Implementation: middleware intercepts mutations, applies optimistically, queues for sync. Sync worker: processes queue when online, handles retries with exponential backoff. Conflict resolution strategies: Last-Write-Wins (timestamp), Operational Transform (CRDTs for concurrent edits), Three-Way Merge (compare local, server, base), Manual Resolution (present UI for conflicts). Example: CRDTs for collaborative text (Yjs library), LWW for simple updates. State shape: { entities: {}, queue: [], conflicts: [], syncStatus: { lastSync, syncing, errors } }. Libraries: Redux Offline, WatermelonDB, RxDB. Handle: network transitions, partial syncs, deleted entity operations, dependency ordering.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 28: Web Performance Optimization (5 questions)
    (136, 'What are Core Web Vitals (LCP, FID, CLS)? How do you measure and optimize them?',
     'LCP (Largest Contentful Paint): time for largest content element to render, target <2.5s. Optimize: optimize images, preload critical resources, minimize render-blocking CSS/JS. FID (First Input Delay): time from interaction to browser response, target <100ms. Optimize: code splitting, Web Workers for heavy tasks, reduce JavaScript execution time. CLS (Cumulative Layout Shift): unexpected layout shifts, target <0.1. Optimize: set image/video dimensions, avoid inserting content above existing, use transform for animations. Measure: Lighthouse, PageSpeed Insights, Chrome UX Report (real users), Web Vitals library. Tools: performance.measure() API, PerformanceObserver for custom metrics.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (137, 'Explain code splitting strategies in React/Webpack. Implement route-based and component-based code splitting.',
     'Route-based: const Home = lazy(() => import("./Home")); <Suspense fallback={<Loading />}><Routes><Route path="/" element={<Home />} /></Routes></Suspense>. Webpack creates separate chunk. Component-based: const HeavyChart = lazy(() => import("./HeavyChart")); use when component expensive and not always needed. Webpack config: optimization: { splitChunks: { chunks: "all", cacheGroups: { vendor: { test: /[\\/]node_modules[\\/]/, priority: -10 } } } }. Dynamic imports: button onClick: import("./module").then(mod => mod.init()). Prefetch: <link rel="prefetch" href="chunk.js"> or webpackPrefetch comment. Monitor: webpack-bundle-analyzer, lighthouse. Best practice: split at route level, lazy load below-fold, balance chunk size (too many = HTTP overhead).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (138, 'How do you optimize images for web performance? Compare different formats and loading strategies.',
     'Formats: WebP (25-35% smaller than JPEG), AVIF (50% smaller but limited support), JPEG for photos, PNG for transparency, SVG for icons/logos. Delivery: <picture><source type="image/avif" srcset="img.avif"><source type="image/webp" srcset="img.webp"><img src="img.jpg"></picture>. Responsive: srcset="small.jpg 480w, large.jpg 1920w" sizes="(max-width: 600px) 480px, 1920px" serves appropriate size. Loading strategies: lazy loading="{loading: ''lazy''}" for below-fold, priority with fetchpriority="high" for LCP image, blur-up placeholder (low-res initial, high-res lazy). CDN: image CDNs (Cloudinary, Imgix) with URL parameters for on-the-fly transforms. Modern frameworks: Next.js Image component handles optimization automatically. Always: set width/height, compress (ImageOptim), use modern formats with fallbacks.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (139, 'What are render-blocking resources? How do you eliminate them using async, defer, and resource hints?',
     'Render-blocking: CSS and synchronous JavaScript block rendering. Solutions: CSS - inline critical above-fold CSS in <head>, defer non-critical: <link rel="preload" href="style.css" as="style" onload="this.onload=null;this.rel=''stylesheet''">. JavaScript: async attribute (execute when downloaded, no order guarantee), defer (execute after HTML parsing, maintains order), type="module" (defers by default). Resource hints: dns-prefetch (resolve DNS early), preconnect (establish connection), prefetch (fetch for next navigation), preload (fetch for current page). Example: <link rel="preconnect" href="https://fonts.googleapis.com">. Critical path: identify with Lighthouse, inline critical CSS (tools: critical, critters), defer third-party scripts. Modern: HTTP/2 push deprecated, use 103 Early Hints.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (140, 'Design a performance optimization strategy for a complex React dashboard with real-time data, charts, and large tables.',
     'Optimizations: (1) Virtualization: react-window for tables rendering only visible rows. (2) Memoization: React.memo for expensive components, useMemo for calculations, useCallback for callbacks passed to children. (3) Code splitting: lazy load chart libraries, route-based splitting. (4) Data: implement pagination/infinite scroll, debounce real-time updates (batch every 100ms), use Web Workers for data processing. (5) Render optimization: avoid inline functions, split context (separate rarely-changing from frequently-changing), use state colocation (keep state close to where it''s used). (6) Bundle: tree-shake lodash (import specific functions), replace moment.js with date-fns. (7) Network: implement request deduplication, cache API responses, use SWR/React Query for smart caching. (8) Monitoring: implement performance budgets, use React DevTools Profiler, track key user flows with performance.mark/measure. Set budgets: LCP <2.5s, FID <100ms, bundle <300KB gzipped.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 29: Browser APIs (5 questions)
    (141, 'Compare localStorage, sessionStorage, and IndexedDB. When should you use each?',
     'localStorage: persistent key-value storage, 5-10MB, synchronous, survives browser restarts. sessionStorage: like localStorage but per-tab, cleared when tab closes. IndexedDB: async transactional database, 50MB+, stores complex objects. Use localStorage for: user preferences, theme, non-sensitive simple data. sessionStorage for: temporary view state, multi-step forms, preventing state persistence. IndexedDB for: offline apps, large datasets, structured data, file storage. Security: all vulnerable to XSS - never store sensitive data without encryption. Modern: Web Storage API being supplemented by Storage API for quota management, Cache API for HTTP responses. Best practice: feature detect (if (!localStorage) {...}), handle QuotaExceededError, encrypt sensitive data.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (142, 'Explain the Fetch API with AbortController. How do you handle timeouts and request cancellation?',
     'Fetch: const response = await fetch(url, options); const data = await response.json(). AbortController: const controller = new AbortController(); fetch(url, { signal: controller.signal }). Cancel: controller.abort() throws AbortError. Use cases: cancel on component unmount, cancel previous search request, implement timeout. Timeout: const timeout = (ms) => { const controller = new AbortController(); setTimeout(() => controller.abort(), ms); return controller.signal; }; fetch(url, { signal: timeout(5000) }). Better: Promise.race([fetch(), delay()]).  Error handling: if (!response.ok) throw new Error(response.status); catch handles network errors only, check response.ok  for HTTP errors. Modern:  use libraries (axios, ky) for better DX or fetch wrappers. Best practice: always handle errors, provide fallbacks, show appropriate UI states (loading, error, success).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (143, 'How does the Intersection Observer API work? Implement infinite scroll and lazy image loading.',
     'Intersection Observer: observes element visibility relative to viewport. API: const observer = new IntersectionObserver((entries) => { entries.forEach(entry => { if (entry.isIntersecting) loadMore(); }); }, { threshold: 0.5 }); observer.observe(element). Infinite scroll: observe sentinel element at list bottom, load more data when visible, append items, unobserve if no more data. Lazy images: <img data-src="actual.jpg" src="placeholder.jpg"> observe all images, when visible: img.src = img.dataset.src; observer.unobserve(img). Options: root (null=viewport), rootMargin ("-100px" for preload), threshold ([0, 0.5, 1] for percentage visibility). Benefits: performant (no scroll listeners), works with CSS transforms, handles iframe. Cleanup: observer.disconnect() on unmount. Advanced: track ad impressions, animate on scroll, pause offscreen videos.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (144, 'Explain Web Workers. How do you structure communication for CPU-intensive tasks?',
     'Web Workers: run JavaScript in background threads. Main thread: const worker = new Worker("worker.js"); worker.postMessage(data); worker.onmessage = (e) => console.log(e.data). Worker: self.onmessage = (e) => { const result = compute(e.data); self.postMessage(result); }. Communication: Structured Clone Algorithm copies data (slower for large data). Transferable objects (ArrayBuffer): zero-copy transfer ownership - postMessage(buffer, [buffer]). Limitations: no DOM access, no window/document, limited APIs. Use cases: image processing, data parsing, cryptography, large computations. Patterns: worker pool for parallel processing, Comlink library for RPC-style API. Modern: OffscreenCanvas for rendering in worker, SharedArrayBuffer for shared memory (requires cross-origin isolation). Structure: abstract worker creation behind service/hook, handle errors, terminate when done to free resources.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (145, 'Your progressive web app needs to work offline and handle poor network conditions gracefully. Discuss implementing a Service Worker caching strategy covering different approaches for static assets versus API calls, handling cache versioning during deployments, implementing background sync for failed requests, and notifying users when updates are available',
     'Service Worker lifecycle: install → activate → fetch interception. Install: cache critical assets - self.addEventListener("install", e => { e.waitUntil(caches.open("v1").then(cache => cache.addAll(["/", "/app.js"]))); self.skipWaiting(); }). Activate: cleanup old caches - caches.keys().then(keys => Promise.all(keys.filter(k => k !== "v1").map(k => caches.delete(k)))). Fetch strategies: (1) Cache-first: static assets, (2) Network-first: API (cache as backup), (3) Stale-while-revalidate: serve cached, update in background. Background Sync: self.addEventListener("sync", e => { if (e.tag === "sync-posts") e.waitUntil(syncPosts()); }). Register: registration.sync.register("sync-posts"). Versioning: increment version on deploy, activate cleans old. Update notification: postMessage to clients about new version. Use Workbox for production (recipes for common patterns). Handle: offline page, precache critical routes, runtime caching for API.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),


    -- Topic 30: Responsive Design (5 questions)
    (146, 'What is mobile-first design? Compare mobile-first vs desktop-first CSS approaches.',
     'Mobile-first: design for smallest screen first, progressively enhance for larger screens. CSS: base styles for mobile, use min-width media queries to add complexity. Example: .container { width: 100%; } @media (min-width: 768px) { .container { width: 750px; } }. Desktop-first: opposite, uses max-width media queries, often results in overrides. Benefits of mobile-first: forces content prioritization, better performance (mobile doesn''t download desktop CSS), aligns with mobile-majority traffic, simpler cascades (adding vs overriding). Implementation: define breakpoints (320px, 768px, 1024px, 1440px), use flexible units (rem, %, vw), test on actual devices. Modern tools: CSS Grid/Flexbox for layout, container queries for component-level responsiveness. Best practice: design system with mobile constraints ensures focused UX.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (147, 'Explain CSS Grid vs Flexbox for responsive layouts. When should you use each?',
     'Flexbox: 1-dimensional (row or column), content-first (size based on content). Use for: navigation bars, centering, equal-height cards, small-scale layouts. Example: .container { display: flex; flex-wrap: wrap; gap: 1rem; } .item { flex: 1 1 200px; }. Grid: 2-dimensional (rows and columns), layout-first (explicit track sizing). Use for: page layouts, complex grids, overlapping elements. Example: .container { display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 1rem; }. Responsive patterns: auto-fit/auto-fill for dynamic columns, grid-template-areas for semantic layout shifts. Combine both: Grid for page structure, Flexbox for components. Modern: subgrid for nested grids, container queries for component responsiveness. Best practice: Grid for 2D layouts, Flexbox for 1D, both support gap property, avoid frameworks for simple layouts.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (148, 'How do you handle images responsively? Explain srcset, sizes, and the picture element.',
     'srcset: defines image sources with widths. <img src="default.jpg" srcset="small.jpg 400w, medium.jpg 800w, large.jpg 1600w">. Browser selects based on viewport. sizes: hints to browser about display size. sizes="(max-width: 600px) 100vw, 50vw" means full width on small screens, half on large. Together: <img srcset="..." sizes="..." src="fallback.jpg">. Picture element: art direction (different crops/images). <picture><source media="(min-width: 1024px)" srcset="wide.jpg"><source media="(min-width: 768px)" srcset="square.jpg"><img src="tall.jpg"></picture>. Also for format selection: <source type="image/webp" srcset="img.webp">. Responsive considerations: aspect ratios, object-fit (cover/contain), loading="lazy", fetchpriority for LCP images. CSS: background-image with image-set() or media queries. Best practice: always include alt, set width/height to prevent CLS, compress images, use CDN for transforms.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (149, 'What are container queries? How do they differ from media queries and when should you use them?',
     'Container queries: style elements based on parent container size, not viewport. CSS: .container { container-type: inline-size; } @container (min-width: 400px) { .card { display: flex; } }. Media queries: based on viewport/device. Difference: container queries enable truly reusable components that adapt to their context, media queries are global. Use cases: design systems (card component adapts whether in sidebar or main area), grid items that reflow based on column width, reusable widgets. Syntax: container-name for targeting specific containers, @container name (width > 500px) {}. Container types: size (both dimensions, expensive), inline-size (preferred, only width). Limitations: can''t query own size (circular dependency), can''t use container-queried element as container. Browser support: modern browsers (2023+), use @supports. Best practice: prefer inline-size type, combine with Grid auto-fit for powerful responsive patterns.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (150, 'Your team needs to build a responsive dashboard that works across all devices from mobile phones to ultra-wide monitors. Discuss your approach to layout strategy covering mobile-first versus desktop-first decisions, using CSS Grid and Flexbox for different breakpoints, handling the sidebar on mobile devices, implementing fluid typography, and ensuring the layout is maintainable',
     'HTML structure: <div class="dashboard"><aside class="sidebar"></aside><main class="main"><header></header><div class="widgets"></div></main></div>. Mobile-first CSS: .dashboard { display: grid; grid-template-areas: "header" "widgets" "sidebar"; } .sidebar { grid-area: sidebar; } .main { grid-area: 1 / 1; display: grid; grid-template-areas: "header" "widgets"; }. Tablet: @media (min-width: 768px) { .widgets { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 1rem; } }. Desktop: @media (min-width: 1024px) { .dashboard { grid-template-columns: 250px 1fr; grid-template-areas: "sidebar main"; } .sidebar { position: sticky; top: 0; height: 100vh; } }. Widgets container queries: .widget-container { container-type: inline-size; } @container (max-width: 400px) { .widget { /* stacked layout */ } }. Responsive utilities: clamp() for fluid typography (font-size: clamp(1rem, 2vw, 1.5rem)), CSS custom properties for theme, gap for spacing. Accessibility: ensure focus indicators, keyboard navigation, proper heading hierarchy. Test: mobile (320px), tablet (768px), desktop (1440px), ultra-wide (1920px+).',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 31: Build Tools (5 questions)
    (151, 'What is the difference between Webpack and Vite? When would you choose each?',
     'Webpack: mature bundler, uses Node.js, bundles everything before serving, highly configurable, large ecosystem. Development: slower start (bundles all), hot reload okay. Production: excellent code splitting, tree shaking, caching. Vite: modern build tool, uses esbuild (Go-based, 10-100x faster), ES modules in dev, Rollup for production. Development: instant server start (no bundling), lightning-fast HMR, native ESM. Production: similar to Webpack (Rollup-based). Choose Webpack: complex build requirements, extensive plugin ecosystem needed, legacy project, need fine-grained control. Choose Vite: new projects, want fast DX, modern browsers, React/Vue/Svelte projects. Migration: Vite simpler config, better DX, but Webpack more battle-tested for edge cases. Modern trend: Vite/esbuild/swc for development speed, turbopack emerging. Both support: code splitting, env variables, CSS modules, TypeScript.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (152, 'Explain tree shaking in JavaScript bundlers. What makes code tree-shakeable?',
     'Tree shaking: dead code elimination, removes unused exports. Requires: (1) ES modules (import/export), not CommonJS (require). (2) Side-effect free code. (3) Production mode with minification. Example: // utils.js: export const used = () => {}; export const unused = () => {}; // main.js: import { used } from "./utils"; - unused is removed. Webpack config: mode: "production", optimization: { usedExports: true, sideEffects: false }. Package.json: "sideEffects": false or ["*.css"] to mark files with side effects. Problems: default exports less shakeable than named, mutations, global scope pollution. Debugging: check bundle analyzer, use /* #__PURE__ */ comment for function calls. Libraries: lodash-es (tree-shakeable) vs lodash (not), date-fns vs moment. Best practices: prefer named exports, avoid side effects in modules, configure sideEffects in package.json, use ESLint to catch CommonJS.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (153, 'How do you configure multiple environments (dev, staging, production) in a modern build pipeline?',
     'Environment variables: .env.development, .env.staging, .env.production files. Vite: VITE_API_URL accessed via import.meta.env.VITE_API_URL. Webpack: DefinePlugin: new webpack.DefinePlugin({ "process.env.API_URL": JSON.stringify(process.env.API_URL) }). Access: process.env.API_URL. Different configs: webpack.dev.js, webpack.prod.js, webpack.common.js merged with webpack-merge. Scripts: package.json: "build:staging": "NODE_ENV=staging webpack --config webpack.prod.js". Runtime config: window.__CONFIG__ injected via script tag for truly dynamic config (no rebuild). Security: never commit secrets (.env in .gitignore), use CI/CD secrets, validate env vars at build. Feature flags: separate from env, use services like LaunchDarkly or build simple system. TypeScript: declare module for type safety. Modern: tools like dotenv-vault for secrets management, Vite modes (--mode staging).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (154, 'What are source maps? Explain different source map types and their trade-offs.',
     'Source maps: files (.map) that map minified/transpiled code back to original source for debugging. Types: (1) eval: fastest rebuild, no source map file, shows transpiled code. (2) source-map: separate .map file, slowest build, full original source. (3) cheap-module-source-map: faster, no column mappings, shows original source. (4) inline-source-map: map embedded in bundle (large). (5) hidden-source-map: like source-map but no reference in bundle (for error reporting). (6) nosources-source-map: map without source content (security). Webpack: devtool: "eval-cheap-module-source-map" (dev), "source-map" (prod). Trade-offs: build speed vs debugging quality vs bundle size. Production: use source-map, upload to error tracking (Sentry), don''t serve publicly (expose source). Development: eval-cheap-module-source-map for speed. Security: nosources-source-map if exposing maps. Best practice: different configs per environment, use with error tracking, exclude maps from public path.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (155, 'Design a production-ready Webpack/Vite configuration with optimization, caching, code splitting, and monitoring.',
     'Webpack production config: mode: "production", optimization: { splitChunks: { chunks: "all", cacheGroups: { vendor: { test: /node_modules/, name: "vendors", priority: 10 }, common: { minChunks: 2, priority: 5 } } }, runtimeChunk: "single", minimize: true, minimizer: [new TerserPlugin({ extractComments: false })] }. Caching: output: { filename: "[name].[contenthash].js" }, cache: { type: "filesystem" }. Plugins: new BundleAnalyzerPlugin(), new CompressionPlugin({ algorithm: "gzip" }), new WorkboxPlugin() for PWA. Entry: multiple entries for different sections. Module rules: babel-loader with caching, css-loader with modules, image assets. Vite equivalent: build: { rollupOptions: { output: { manualChunks: (id) => { if (id.includes("node_modules")) return "vendor"; } } }, chunkSizeWarningLimit: 1000 }. Monitoring: bundle-analyzer, lighthouse CI, performance budgets. CI/CD: fail build if budget exceeded, automated visual regression tests. Environment: different configs per env, feature flags, error tracking integration.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 32: Frontend Testing (5 questions)
    (156, 'Compare unit testing, integration testing, and E2E testing in frontend. What should each cover?',
     'Unit tests: test individual functions/components in isolation. Tools: Jest, Vitest. Coverage: utility functions, hooks, component logic without external dependencies. Example: test calculateTotal() returns correct sum. Fast, many tests. Integration tests: test component interactions, API calls (mocked), state management. Tools: React Testing Library, Jest. Coverage: form submissions, data fetching, user flows within component tree. Example: test search component fetches and displays results. E2E tests: test full user flows in real browser. Tools: Playwright, Cypress. Coverage: critical paths (login, checkout), cross-browser, real API. Example: test user can complete purchase. Slow, fewer tests. Testing pyramid: many unit (70%), some integration (20%), few E2E (10%). Best practices: test behavior not implementation, avoid testing library internals, mock external dependencies in unit/integration, use real APIs in E2E or dedicated test environment.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (157, 'How do you test React components with React Testing Library? Explain best practices for queries and assertions.',
     'React Testing Library: render(<Component />); screen.getByRole("button", { name: /submit/i }); fireEvent.click(button); expect(screen.getByText(/success/i)).toBeInTheDocument(). Query priority: (1) getByRole (accessibility), (2) getByLabelText (forms), (3) getByPlaceholderText, (4) getByText, (5) getByTestId (last resort). Variants: getBy (throw if not found), queryBy (return null), findBy (async, wait). User events: @testing-library/user-event preferred over fireEvent (more realistic). Example: await userEvent.click(button); await userEvent.type(input, "text"). Async: await waitFor(() => expect(screen.getByText(/loaded/i)).toBeInTheDocument()). Best practices: test user behavior not implementation, avoid testing state directly, use accessible queries, test error states, setup/teardown properly. Mocking: jest.mock for modules, MSW for API mocking. Avoid: shallow rendering, testing implementation details, querySelector by class.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (158, 'Explain API mocking strategies for frontend tests. Compare MSW, jest.mock, and manual mocks.',
     'MSW (Mock Service Worker): intercepts requests at network level. Setup: handlers = [rest.get("/api/users", (req, res, ctx) => res(ctx.json([...])))]; server = setupServer(...handlers); beforeAll(() => server.listen()); afterEach(() => server.resetHandlers()); afterAll(() => server.close()). Benefits: same code for tests and development, works with any request library, no changes to app code. jest.mock: mock module imports. jest.mock("./api", () => ({ fetchUsers: jest.fn(() => Promise.resolve([])) })). Use before imports. Benefits: simple, good for unit tests. Cons: couples tests to implementation. Manual mocks: __mocks__ folder, automatic replacement. Good for testing libraries. Axios mock adapter: specialized for axios. Choose: MSW for integration/E2E (realistic), jest.mock for unit tests (simple), mock adapters for library-specific. Best practices: reset mocks between tests, test error states, match production responses, use TypeScript for type safety.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (159, 'How do you write E2E tests with Playwright? Explain page objects, fixtures, and parallelization.',
     'Basic test: import { test, expect } from "@playwright/test"; test("login", async ({ page }) => { await page.goto("/login"); await page.fill("[name=email]", "user@test.com"); await page.click("button[type=submit]"); await expect(page).toHaveURL("/dashboard"); }). Page Object Model: class LoginPage { constructor(page) { this.page = page; } async login(email, pw) { await this.page.fill("[name=email]", email); ... } }. Use: const login = new LoginPage(page); await login.login(...). Fixtures: extend base test with custom fixtures - test.extend({ authenticatedPage: async ({ page }, use) => { await login(page); await use(page); } }). Parallelization: runs tests in parallel by default, test.describe.configure({ mode: "parallel" }), workers in config. Selectors: prefer data-testid or accessible selectors, chain: page.locator("form").locator("button"). Actions: auto-wait for actionability. Screenshots/videos: automatically on failure. Best practices: avoid sleeps (use waitForSelector), isolate tests (independent state), use beforeEach for auth.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (160, 'Design a comprehensive testing strategy for a complex React application with auth, real-time features, and third-party integrations.',
     'Testing layers: (1) Unit: test utilities, hooks, reducers (70% coverage). Tools: Vitest, Testing Library. Fast feedback. (2) Integration: component trees, forms, state management (20%). MSW for API mocking, test actual user flows. (3) E2E: critical flows (login, purchase, onboarding) (10%). Playwright for real browsers, test environment with seeded data. Auth testing: unit test auth utilities, integration test login/logout/refresh flow with mocked API, E2E test full OAuth flow in staging. Real-time: mock WebSocket in integration (create mock socket), E2E test with real connection (test environment). Third-party: unit test with jest.mock, integration test with service mocks/sandboxes (Stripe test mode), E2E against test accounts. CI/CD: unit tests on every PR, integration on merge, E2E nightly or on deploy to staging. Performance: lighthouse CI, bundle size checks. Visual regression: Percy or Chromatic. Monitoring: error tracking (Sentry), RUM (Real User Monitoring). Code coverage: aim 80% overall, 100% for critical paths. Best practices: parallelize tests, retry flaky tests, use test data builders, maintain test environment.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 33: CSS Frameworks (5 questions)
    (161, 'Compare Tailwind CSS, Bootstrap, and Material-UI. When would you choose each?',
     'Tailwind: utility-first, no predefined components, highly customizable via config, smaller bundle (purges unused), steep learning curve, consistent design system. Use: custom designs, small teams, design system flexibility, modern projects. Bootstrap: component library, predefined styles, faster prototyping, larger bundle, looks "Bootstrap-y", harder deep customization. Use: rapid prototyping, admin panels, traditional websites, less design resources. Material-UI: React component library, Material Design, rich components with logic, TypeScript support, large bundle. Use: React apps, need complex components (autocomplete, data grid), Material Design aesthetic. Trade-offs: Tailwind=most control/smallest bundle vs Bootstrap=fastest start/generic look vs MUI=rich components/large bundle. Modern: Tailwind dominates, headless UI for components. Best practice: use CSS framework for consistency, customize theme, purge unused in production, combine with custom CSS for unique needs.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (162, 'How does Tailwind CSS purging/tree-shaking work? Optimize a production build.',
     'Tailwind generates thousands of utility classes, purging removes unused. Tailwind v3+: JIT (Just-In-Time) mode default, generates only used classes. Configuration: content: ["./src/**/*.{js,jsx,ts,tsx}"], scans files for class names. Purging: safelist: ["bg-red-500"] for dynamic classes, blocklist: ["container"] to exclude. Dynamic classes: avoid string concatenation - use safelist or full class names. Production optimization: (1) JIT mode (default in v3), (2) configure content paths correctly, (3) minimize config (extend only needed), (4) use @layer for custom CSS, (5) enable CSS minification. Build: Vite/Webpack automatically minifies. Bundle size: before purge ~3MB, after ~10KB. Debugging: npx tailwindcss -o output.css --watch to inspect output. Best practices: avoid dynamic class generation (bg-[${color}]), use safelist for truly dynamic, configure content paths precisely, use @layer utilities for custom, monitor bundle size.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (163, 'Explain CSS-in-JS vs traditional CSS. Compare styled-components, Emotion, and CSS Modules.',
     'CSS-in-JS: write CSS in JavaScript, scoped styles, dynamic based on props, runtime or build-time. styled-components: const Button = styled.button`color: ${props => props.primary ? "blue" : "gray"};`. Runtime styling, theming support. Emotion: similar to styled-components, better performance, css prop. CSS Modules: .button { color: blue; }, import styles from "./Button.module.css", <button className={styles.button}>. Build-time, scoped via hash. Traditional CSS: global scope, requires methodology (BEM), separate files. Trade-offs: CSS-in-JS pros = scoping, dynamic styles, colocation; cons = runtime cost, larger bundles, server-rendering complexity. CSS Modules: pros = scoped, build-time, framework-agnostic; cons = no dynamic styles, separate files. Modern trend: shift to zero-runtime CSS-in-JS (Vanilla Extract, Panda CSS) or utility frameworks (Tailwind). Best practice: CSS Modules for static, styled-components for dynamic/themed, Tailwind for new projects, avoid old global CSS.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (164, 'How do you implement a design system with Tailwind CSS? Customize theme and create reusable components.',
     'Tailwind config customization: theme: { extend: { colors: { primary: { 50: "#...", 500: "#...", 900: "#..." }, fontFamily: { sans: ["Inter", ...] }, spacing: { 72: "18rem" } } }. Design tokens: define in config, use in templates. Component patterns: (1) Utility composition: const btnBase = "px-4 py-2 rounded"; const btnPrimary = btnBase + " bg-primary-500". (2) @layer components in CSS: @layer components { .btn { @apply px-4 py-2 rounded; } .btn-primary { @apply btn bg-primary-500; } }. (3) React components: const Button = ({ variant }) => <button className={clsx("btn", variant === "primary" && "btn-primary")}>. Plugins: custom plugins for complex patterns. Typography: @tailwindcss/typography plugin. Forms: @tailwindcss/forms for consistent inputs. Variants: extend variants for custom states. Documentation: Storybook with Tailwind components. Best practices: centralize config, use @layer, create component library, document patterns, use design tokens, integrate with design tools (Figma plugins), setup linter for class order.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (165, 'Design a theming system supporting light/dark modes, multiple color schemes, and user preferences with Tailwind and CSS variables.',
     'Approach: CSS variables + Tailwind + localStorage. CSS variables: :root { --color-primary: 220 95% 55%; } .dark { --color-primary: 220 90% 65%; }. Tailwind config: colors: { primary: "hsl(var(--color-primary))" }. Usage: <div className="bg-primary">. Dark mode: tailwind.config.js: darkMode: "class". Toggle: <html class="dark">. React: const [theme, setTheme] = useState(localStorage.getItem("theme") || "light"); useEffect(() => { document.documentElement.classList.toggle("dark", theme === "dark"); localStorage.setItem("theme", theme); }, [theme]). Multiple themes: data attributes - <html data-theme="ocean">. CSS: [data-theme="ocean"] { --color-primary: 200 90% 50%; }. Tailwind plugin: generate variants for each theme. System preference: const systemTheme = window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light"; listen to changes. Component: <ThemeProvider> context for theme state. Advanced: interpolate between themes with CSS transitions, respect prefers-reduced-motion, sync across tabs (storage event), persist per-user in backend. Accessibility: ensure contrast ratios (WCAG AA), test with color blindness simulators, provide manual override.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),


    -- Topic 34: Web Accessibility (5 questions)
    (166, 'What are WCAG guidelines? Explain the four POUR principles and their importance.',
     'WCAG (Web Content Accessibility Guidelines): standards for accessibility. Levels: A (minimum), AA (standard, legal requirement in many jurisdictions), AAA (enhanced). POUR principles: (1) Perceivable: information must be presentable to users in ways they can perceive - alt text for images, captions for videos, sufficient color contrast, text alternatives. (2) Operable: UI components and navigation must be operable - keyboard accessible, sufficient time to interact, no seizure-inducing content, navigable structure. (3) Understandable: information and operation must be understandable - readable text, predictable behavior, input assistance, error identification. (4) Robust: content must be robust enough for assistive technologies - valid HTML, ARIA for complex widgets, compatible with current/future tools. Compliance benefits: legal requirements, larger audience (15% population), better SEO, improved UX for all. Testing: automated tools (axe, Lighthouse), manual keyboard testing, screen reader testing.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (167, 'How do you implement keyboard navigation in complex components (dropdown, modal, tabs)? Explain focus management.',
     'Keyboard navigation essentials: Tab (next), Shift+Tab (previous), Enter/Space (activate), Esc (close), Arrow keys (navigate within). Dropdown: toggle with Enter/Space, navigate options with Up/Down arrows, select with Enter, close with Esc. Implementation: useEffect(() => { const handleKey = (e) => { if (e.key === "Escape") close(); if (e.key === "ArrowDown") focusNext(); }; document.addEventListener("keydown", handleKey); return () => removeEventListener(...); }, []). Modal: trap focus within modal - focus first element on open, cycle Tab within modal, return focus to trigger on close. Library: focus-trap-react. Tabs: role="tablist", role="tab", arrow keys to switch, Enter/Space to activate, aria-selected. Focus management: ref.current.focus(), tabindex="-1" for programmatic focus, visible focus indicators (outline), skip links for navigation. Best practices: test with keyboard only (unplug mouse), follow ARIA Authoring Practices patterns, maintain tab order, provide visible focus, handle focus restoration.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (168, 'Explain ARIA attributes and when to use them. What are common misuses?',
     'ARIA (Accessible Rich Internet Applications): attributes to enhance accessibility. When to use: complex widgets without HTML equivalents (autocomplete, tree view), dynamic content, custom controls. Roles: role="button" (make div clickable), role="alert" (announce changes), role="dialog", role="tabpanel". Properties: aria-label (provide name), aria-labelledby (reference label), aria-describedby (additional description), aria-required, aria-invalid, aria-disabled. States: aria-expanded (collapsible content), aria-selected, aria-checked, aria-hidden. Live regions: aria-live="polite" (announce when convenient), "assertive" (immediate). Common misuses: (1) using ARIA instead of semantic HTML (<button> not <div role="button">), (2) aria-label on non-interactive elements, (3) aria-hidden on focusable elements, (4) incorrect role hierarchy, (5) missing keyboard support. First rule of ARIA: don''t use ARIA - prefer semantic HTML. Second rule: don''t change native semantics. Testing: screen readers (NVDA, JAWS, VoiceOver), browser DevTools accessibility tree.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (169, 'How do you ensure proper color contrast and support for color blindness? Explain testing tools and techniques.',
     'Color contrast: WCAG AA requires 4.5:1 for normal text, 3:1 for large text (18pt+ or 14pt+ bold), 3:1 for UI components. AAA: 7:1 for normal text. Tools: browser DevTools (contrast ratio in color picker), WebAIM Contrast Checker, Lighthouse audit. Implementation: use CSS variables for consistent colors, test during design, automated checks in CI. Color blindness: 8% of men, 0.5% of women. Types: deuteranopia (green), protanopia (red), tritanopia (blue), achromatopsia (total). Support: (1) never rely only on color - add icons, patterns, labels, (2) sufficient contrast, (3) test with simulators (Chromatic Vision Simulator). Patterns: use shapes + colors in charts, underline links, icons with text labels. Testing: Chrome DevTools (Rendering > Emulate vision deficiencies), Who Can Use tool, manual testing. Best practices: design with high contrast from start, use color-blind safe palettes, provide alternative representations, automate contrast checks, test with actual users.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (170, 'Design an accessible data table with sorting, filtering, and pagination. Ensure screen reader support and keyboard navigation.',
     'Semantic markup: <table><caption>Users List</caption><thead><tr><th scope="col">Name<button aria-label="Sort by name">↓</button></th></tr></thead><tbody>...</tbody></table>. Sorting: button in header, aria-sort="ascending" on th, announce with aria-live. Implementation: <th aria-sort={sortColumn === "name" ? sortDirection : "none"}><button onClick={sort("name")} aria-label={`Sort by name ${sortDirection === "asc" ? "descending" : "ascending"}`}>. Filtering: <label for="filter-name">Filter by name</label><input id="filter-name">, announce results count with aria-live="polite" region. Pagination: <nav aria-label="Pagination"><ul><li><button aria-label="Go to page 1" aria-current={currentPage === 1 ? "page" : undefined}>1</button></li></ul></nav>. Keyboard: Tab through controls, Enter/Space to activate, focus management on page change. Screen reader: table caption describing data, scope on headers, summary of current state (Page 1 of 10, 5 results), aria-busy during loading. Responsive: on mobile, card layout with aria-describedby to associate labels. Loading states: aria-busy="true", skeleton with aria-label="Loading". Advanced: allow row selection with aria-selected, action menu with aria-haspopup, virtual scrolling with aria-rowcount/aria-rowindex for large datasets.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 35: UI/UX Principles (5 questions)
    (171, 'Explain the key principles of user-centered design. How do they apply to frontend development?',
     'User-centered design: design process focused on end users throughout. Principles: (1) Understand users: research, personas, user journeys. Frontend: load user preferences, accessibility, responsive design. (2) Iterative design: prototype, test, refine. Frontend: component design systems, A/B testing, feature flags. (3) Early and continuous user involvement: usability testing, feedback loops. Frontend: analytics, error tracking, feedback forms. (4) Consider whole user experience: not just UI but emotions, context. Frontend: loading states, error messages, micro-interactions. (5) Multidisciplinary teams: designers, developers, researchers collaborate. Key applications: (1) Accessibility: WCAG compliance, keyboard navigation, (2) Performance: optimize for slow connections, show loading indicators, (3) Feedback: toast notifications, form validation, (4) Consistency: design system, predictable patterns, (5) Error handling: clear messages, recovery options. Best practices: test with real users, measure key metrics (task success, time on task), prioritize mobile experience, minimize cognitive load.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (172, 'What are loading states and skeleton screens? Implement them effectively in a React application.',
     'Loading states: feedback that content is loading. Types: (1) Spinner: simple circular indicator, (2) Skeleton screen: placeholder mimicking content structure, (3) Progress bar: shows percentage, (4) Shimmer effect: animated skeleton. Benefits: perceived performance improvement, reduces frustration, sets expectations. Skeleton implementation: const Skeleton = () => <div className="animate-pulse"><div className="h-4 bg-gray-300 rounded w-3/4"></div><div className="h-4 bg-gray-300 rounded w-1/2 mt-2"></div></div>. Usage: {loading ? <Skeleton /> : <Content data={data} />}. Progressive loading: show skeleton, load critical content first, lazy load rest. Best practices: (1) match content structure (if showing card, skeleton should be card-shaped), (2) use for expected waits >300ms, (3) don''t overuse (simple spinners for quick loads), (4) combine with optimistic UI for mutations, (5) provide fallback for errors. Accessibility: aria-busy="true" on loading container, announce completion with aria-live. Libraries: react-loading-skeleton, react-content-loader. Modern: Suspense for React: <Suspense fallback={<Skeleton />}><LazyComponent /></Suspense>.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (173, 'Explain micro-interactions and their role in UX. Provide examples of effective implementations.',
     'Micro-interactions: small, single-purpose interactions providing feedback. Components: (1) Trigger: initiates interaction, (2) Rules: what happens, (3) Feedback: user perceives it, (4) Loops/Modes: meta rules. Examples: (1) Button hover: background color change, subtle scale/shadow, (2) Like animation: heart scales up, color fills, particle effect, (3) Form validation: checkmark appears, field border turns green, (4) Pull to refresh: icon rotates, snaps back, (5) Toggle switch: smooth slide animation, (6) Toast notification: slides in, auto-dismiss, (7) Drag and drop: item follows cursor, drop zone highlights. Implementation: CSS: transition: all 0.3s ease; transform: scale(1.05); Framer Motion: <motion.button whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}. Best practices: (1) subtle (don''t distract), (2) quick (<300ms), (3) purposeful (provide feedback or guide), (4) consistent with brand, (5) respect prefers-reduced-motion. Guidelines: ease-in-out for natural feel, provide haptic feedback on mobile, use spring animations for elasticity. Testing: ensure don''t block interaction, test performance (avoid jank), validate accessibility impact.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (174, 'How do you design and implement effective error states and recovery mechanisms?',
     'Error state components: (1) Error message: clear, non-technical language, explain what happened, (2) Recovery action: retry button, navigation to safe state, (3) Visual indicator: icon, color (not only color), (4) Context: preserve user input when possible. Types: (1) Inline validation: immediate field-level feedback, <input aria-invalid="true" aria-describedby="email-error"><span id="email-error" role="alert">Invalid email</span>. (2) Form submission error: summary at top, link to invalid fields, preserve entered data, (3) Network error: "Unable to connect. Check your connection and try again" + Retry button, (4) 404: "Page not found. Try searching or go to home", (5) 500: "Something went wrong. We''re working on it" + error ID for support. Implementation: Error Boundary: componentDidCatch or react-error-boundary library, fallback UI with recovery. Network: try-catch in fetch, show error state, retry logic with exponential backoff. Offline: detect with navigator.onLine, queue actions for sync, show offline indicator. Best practices: (1) empathetic tone, (2) avoid technical jargon, (3) provide actionable solution, (4) log errors (Sentry), (5) preserve user work, (6) test error states, (7) progressive enhancement. Advanced: predictive error prevention, smart defaults, autocorrect, confirmation for destructive actions.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (175, 'Design a comprehensive form with complex validation, multi-step flow, autosave, and excellent UX including error handling and accessibility.',
     'Architecture: React Hook Form or Formik for state management, Zod for validation, multi-step with state machine (XState). Multi-step: const [step, setStep] = useState(1); <ProgressIndicator current={step} total={4} />; validate step before advancing. Validation: schema with Zod, real-time validation on blur, show errors below fields, summary at submits. Autosave: const { watch } = useForm(); useEffect(() => { const subscription = watch((value) => debounce(saveToLocal, 500)(value)); return () => subscription.unsubscribe(); }, [watch]). Resume: load from localStorage on mount, show notification "Draft restored". Error handling: inline for field errors, toast for save errors, Error Boundary for crashes, optimistic UI for submission. UX enhancements: (1) clear field on icon click, (2) password strength meter, (3) confirm password with realtime match indicator, (4) smart defaults, (5) contextual help tooltips, (6) loading state on submit with disabled form, (7) success confirmation. Accessibility: (1) labels for all inputs, (2) aria-describedby for errors/hints, (3) aria-invalid, (4) fieldset/legend for groups, (5) role="alert" for errors, (6) focus management between steps, (7) keyboard navigation. Mobile: appropriate input types (email, tel, number), autocomplete attributes, avoid too many fields per step. Testing: validate each step, test autosave, test recovery from errors, test with screen reader.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 36: Linux/Unix (5 questions)
    (176, 'Explain the Linux file system hierarchy. What are the purposes of /etc, /var, /usr, /home, /tmp?',
     '/etc: system configuration files (network, services, user accounts), e.g., /etc/passwd, /etc/nginx/nginx.conf. /var: variable data that changes during operation - logs (/var/log), caches, spool queues, databases. /usr: user binaries and read-only data - /usr/bin (commands), /usr/lib (libraries), /usr/share (shared data). Primary applications. /home: user home directories, personal files. /home/username/. /tmp: temporary files, cleared on reboot, world-writable. Other: / (root), /bin (essential binaries), /sbin (system binaries), /boot (bootloader), /dev (devices), /proc (process info), /sys (kernel), /mnt, /media (mount points). FHS (Filesystem Hierarchy Standard) defines structure. Best practices: application configs in /etc, logs in /var/log, user data in /home, never write to /usr manually (package manager territory). Docker: understand for volume mounts, config injection. Development: config typically /etc/appname/ or /opt/appname/etc.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (177, 'How do Linux file permissions work? Explain chmod, chown, and special permissions (setuid, setgid, sticky bit).',
     'Permissions: read (r=4), write (w=2), execute (x=1) for user, group, others. ls -l: -rwxr-xr-- (file type, user, group, others). chmod: change mode. Numeric: chmod 755 file (rwxr-xr-x). Symbolic: chmod u+x,g-w file. Recursive: chmod -R. chown: change owner. chown user:group file. Special permissions: (1) setuid (4): execute as file owner, chmod u+s or 4755, e.g., passwd command. (2) setgid (2): execute as group owner, chmod g+s or 2755, on directory new files inherit group. (3) sticky bit (1): only owner can delete files (e.g., /tmp), chmod +t or 1755. Display: ls -l shows s (setuid/setgid) or t (sticky). Security: be cautious with setuid root (security risk), avoid 777 (world writable). Defaults: umask controls default permissions (umask 022 → 755 dirs, 644 files). Use cases: web files need readable by www-data, scripts need executable, shared directories use setgid.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (178, 'Explain process management in Linux. How do you use ps, top, htop, kill, systemctl?',
     'ps: list processes. ps aux (all processes, UNIX style), ps -ef (full format). Output: PID, USER, CPU%, MEM%, COMMAND. Filter: ps aux | grep nginx. top/htop: real-time process monitor. top interactive, htop more user-friendly (colors, mouse). Commands in top: k (kill), r (renice), M (sort by memory). kill: send signals. kill PID (SIGTERM, graceful), kill -9 PID (SIGKILL, force), kill -HUP PID (reload config). killall: by name. systemctl: manage systemd services. systemctl start/stop/restart service, systemctl enable/disable (boot), systemctl status, journalctl -u service (logs). Background: command & (background), nohup (persist after logout), disown. Monitor: pgrep, pidof. Jobs: jobs, fg, bg. Performance: nice/renice (priority -20 to 19, lower = higher priority). Debugging: strace (syscalls), lsof (open files). Best practices: graceful shutdown before kill -9, check logs (journalctl), understand service dependencies, use systemctl for services not manual killing.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (179, 'How do you debug networking issues in Linux? Explain netstat, ss, tcpdump, curl, dig.',
     'netstat (deprecated): network stats. netstat -tuln (listening TCP/UDP ports), netstat -r (routing). ss: modern replacement. ss -tuln, ss -s (summary). tcpdump: packet capture. sudo tcpdump -i eth0 (capture interface), tcpdump port 80 (filter), -w file.pcap (save), -r file.pcap (read). Wireshark GUI for analysis. curl: HTTP client. curl -I url (headers), curl -v (verbose, shows handshake), curl --trace-ascii - (full trace). Test APIs, check connectivity. dig: DNS lookup. dig domain.com (A records), dig MX domain.com, dig @8.8.8.8 (specific DNS server), dig +trace (full resolution path). nslookup: alternative. ping: test connectivity. traceroute: path to host. netcat (nc): network Swiss army knife, nc -l 8080 (listen), nc host 8080 (connect). nmap: port scanning. ip: ip addr (IPs), ip route (routing table). iptables/nft: firewall rules. Debugging flow: (1) ping for connectivity, (2) dig for DNS, (3) telnet/nc for port open, (4) curl for HTTP, (5) tcpdump for packet analysis, (6) check firewall (iptables -L). Tools: mtr (combines ping+traceroute), iftop (bandwidth), lsof -i (network files).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (180, 'Design a bash script for automated deployment that handles rollback, health checks, and notifications.',
     '#!/bin/bash\nset -euo pipefail # exit on error, undefined var, pipe failure\nROLLBACK_TAG="previous"\nSERVICE="myapp"\nHEALTH_URL="http://localhost:8080/health"\nSLACK_WEBHOOK="..."\n\ndeploy() {\n  echo "Deploying new version..."\n  docker pull myapp:latest || { notify "Pull failed"; exit 1; }\n  docker tag myapp:${SERVICE} myapp:${ROLLBACK_TAG} # backup current\n  docker tag myapp:latest myapp:${SERVICE}\n  docker-compose up -d --no-deps ${SERVICE}\n  check_health || { rollback; exit 1; }\n  notify "Deployment successful"\n}\n\ncheck_health() {\n  for i in {1..30}; do\n    if curl -sf ${HEALTH_URL} > /dev/null; then\n      echo "Health check passed"\n      return 0\n    fi\n    echo "Waiting for service... ($i/30)"\n    sleep 2\n  done\n  echo "Health check failed"\n  return 1\n}\n\nrollback() {\n  echo "Rolling back..."\n  docker tag myapp:${ROLLBACK_TAG} myapp:${SERVICE}\n  docker-compose up -d --no-deps ${SERVICE}\n  notify "Rollback completed"\n}\n\nnotify() {\n  curl -X POST ${SLACK_WEBHOOK} -H "Content-Type: application/json" -d "{\"text\":\"$1\"}"\n}\n\nmain() {\n  deploy\n}\n\nmain "$@"\n\nBest practices: use set -e, trap for cleanup, logging, idempotency, validate inputs, use functions, timeout on waits.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),


    -- Topic 37: Shell Scripting (5 questions)
    (181, 'What are the differences between bash, sh, zsh, and fish shells? When would you use each?',
     'sh (Bourne Shell): POSIX compliant, minimal features, available everywhere. Use for: portable scripts (#!/bin/sh), minimal environments. bash (Bourne Again Shell): most common, superset of sh, arrays, functions, rich scripting. Default on most Linux. Use for: general scripting, system administration. zsh: powerful interactive shell, better completion, plugins (Oh My Zsh), globbing, spelling correction. Use for: developer interactive shell, advanced features. fish (Friendly Interactive Shell): user-friendly, auto-suggestions, Web config, not POSIX. Use for: modern interactive experience. Script portability: #!/bin/sh for max portability, #!/bin/bash for bash features, avoid fish for scripts (not widely installed). Feature differences: bash has [[  ]] test, arrays; sh has [ ] test only. Modern: zsh default on macOS, bash on Linux. Best practices: use shellcheck for linting, bash for automation scripts, zsh/fish for interactive, specify shebang explicitly.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (182, 'Explain bash scripting best practices: error handling, strict mode, argument parsing, and function design.',
     'Strict mode: set -euo pipefail at top. -e (exit on error), -u (error on undefined variable), -o pipefail (pipeline fails if any command fails). Error handling: trap for cleanup - trap "rm -f tempfile" EXIT. Check return codes: if ! command; then error; fi or command || error. Functions: func() { local var=$1; echo "result"; } call with func arg, capture with result=$(func arg). Arguments: while getopts "h:u:p:" opt; do case $opt in h) host=$OPTARG;; esac; done. Shift for positional. Validation: [[ -z "$var" ]] && { echo "Missing arg"; exit 1; }. Quoting: always quote variables "$var" to handle spaces, use "${var}" for clarity. Arrays: arr=("a" "b"); echo "${arr[@]}". Testing: use [[ ]] not [ ] for strings, [[ -f file ]] for file checks. Logging: log() { echo "[$(date)] $*" >&2; }. Idempotency: check before action. Documentation: header comment, usage function. Best practices: shellcheck linting, keep scripts focused (single responsibility), extract to functions, validate inputs, provide defaults, use readonly for constants.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (183, 'How do you parse and process text in bash using grep, sed, awk, cut, and regex?',
     'grep: search text. grep "pattern" file, -i (case insensitive), -v (invert), -r (recursive), -E (extended regex), -o (only matching). Example: grep -oE "[0-9]+" extracts numbers. sed: stream editor. sed "s/old/new/g" (substitute), sed -n "10,20p" (print lines 10-20), sed "/pattern/d" (delete matching lines), -i (in-place). Example: sed "s/foo/bar/g" file. awk: text processing language. awk "{print $1}" (first column), awk -F: "{print $2}" (custom delimiter), awk "$3 > 100" (filter), awk "BEGIN{sum=0} {sum+=$1} END{print sum}" (sum column). cut: extract columns. cut -d: -f1 (delimiter : field 1), cut -c1-10 (characters 1-10). Regex: grep -E "(foo|bar)", [0-9]+ (digits), [a-zA-Z] (letters), .* (any), ^ (start), $ (end). Pipelines: cat file | grep error | awk "{print $1}" | sort | uniq -c. Modern alternatives: ripgrep (rg), jq for JSON, sd for sed. Best practice: use awk for complex processing, grep for searching, sed for simple substitutions, combine with pipes for powerful workflows.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (184, 'Explain process substitution, command substitution, and here documents in bash. Provide practical examples.',
     'Command substitution: execute command, use output. Syntax: $(command) or `command` (deprecated). Example: now=$(date +%s), files=$(ls *.txt). Nesting: outer=$(echo "inner=$(date)"). Process substitution: treat command output as file. Syntax: <(command) or >(command). Example: diff <(ls dir1) <(ls dir2) compares directory listings. Use: when command expects file but you have output - while read line; do ... done < <(command). Advanced: comm <(sort file1) <(sort file2). Here documents: multi-line input. Syntax: command <<EOF\nline1\nline2\nEOF. Example: cat <<EOF > file.txt\nHello\nWorld\nEOF. Variables: expand by default, use <<''EOF'' to prevent. SQL: mysql <<EOF\nSELECT * FROM users;\nEOF. Here strings: <<< "string" shorter than echo "string" |. Example: grep pattern <<< "$var". Practical: generate config files with variable substitution, process command output in loops, compare live outputs. Best practices: use $(  ) for command substitution, process substitution for parallel processing, here docs for multi-line strings/configs.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (185, 'Create a bash script for log analysis that finds errors, generates statistics, and sends alerts based on thresholds.',
     '#!/bin/bash\nset -euo pipefail\n\nLOGFILE="${1:-/var/log/app.log}"\nERROR_THRESHOLD=10\nEMAIL="admin@example.com"\nTEMP_DIR=$(mktemp -d)\ntrap "rm -rf $TEMP_DIR" EXIT\n\nanalyze_logs() {\n  local errors=$TEMP_DIR/errors.txt\n  local stats=$TEMP_DIR/stats.txt\n  \n  # Extract errors from last hour\n  local since=$(date -d "1 hour ago" +%s)\n  awk -v since=$since ''{\n    split($1, dt, ":"); \n    timestamp = mktime(dt[1]" "dt[2]" "dt[3]" 0 0 0");\n    if (timestamp >= since && /ERROR|FATAL/) print\n  }'' "$LOGFILE" > "$errors"\n  \n  local error_count=$(wc -l < "$errors")\n  \n  # Generate statistics\n  {\n    echo "=== Log Analysis $(date) ==="\n    echo "Total errors: $error_count"\n    echo "Error breakdown:"\n    grep -oE "ERROR:[^:]*" "$errors" | sort | uniq -c | sort -rn | head -10\n    echo "Top IPs with errors:"\n    awk ''{print $2}'' "$errors" | sort | uniq -c | sort -rn | head -5\n  } > "$stats"\n  \n  cat "$stats"\n  \n  # Alert if threshold exceeded\n  if [[ $error_count -gt $ERROR_THRESHOLD ]]; then\n    send_alert "$error_count" "$stats"\n  fi\n}\n\nsend_alert() {\n  local count=$1\n  local stats_file=$2\n  echo "ALERT: $count errors detected" | mail -s "Alert: High Error Count" -A "$stats_file" "$EMAIL"\n  # Or Slack: curl -X POST $SLACK_WEBHOOK -d "{\\"text\\":\\"$count errors\\"}" \n}\n\nmain() {\n  [[ ! -f "$LOGFILE" ]] && { echo "Log file not found: $LOGFILE"; exit 1; }\n  analyze_logs\n}\n\nmain "$@"\n\nEnhancements: rotation handling, pattern config file, historical trending, JSON output.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 38: Docker Fundamentals (5 questions)
    (186, 'Explain Docker architecture: images, containers, layers, and the differences from VMs.',
     'Docker architecture: Client-server. Docker client talks to Docker daemon (dockerd) which manages containers. Registry stores images (Docker Hub). Components: (1) Images: read-only templates with app + dependencies, built from Dockerfile. (2) Containers: runnable instances of images, isolated with namespaces and cgroups. (3) Volumes: persistent data storage. Layers: images are layers stacked together (UnionFS). Each Dockerfile instruction creates layer. Layers are cached and shared between images. Example: FROM ubuntu (layer 1), RUN apt-get update (layer 2), COPY app (layer 3). VMs vs Docker: VMs include full OS (GB size, minutes to start), Docker shares host kernel (MB size, seconds to start). VMs provide stronger isolation, Docker more lightweight. Use VMs for: different OSes, stronger isolation. Docker for: microservices, CI/CD, consistent environments. Isolation: Docker uses kernel namespaces (PID, network, mount), cgroups (resource limits). Best practice: one process per container, use official images, multi-stage builds to reduce size.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (187, 'How do you write an optimized Dockerfile? Explain layer caching, multi-stage builds, and security best practices.',
     'Optimized Dockerfile principles: (1) Order instructions by change frequency (base image → dependencies → code). (2) Minimize layers (combine RUN commands). (3) Use .dockerignore. (4) Multi-stage builds. Example:\nFROM node:18-alpine AS builder\nWORKDIR /app\nCOPY package*.json ./\nRUN npm ci --only=production\nCOPY . .\nRUN npm run build\n\nFROM node:18-alpine\nWORKDIR /app\nCOPY --from=builder /app/dist ./dist\nCOPY --from=builder /app/node_modules ./node_modules\nUSER node\nEXPOSE 3000\nCMD ["node", "dist/index.js"]\n\nLayer caching: Docker caches unchanged layers. Put stable layers first (dependencies before code). Invalidated by any change in that layer or above. Security: (1) use specific versions not latest, (2) run as non-root user, (3) scan with docker scan, (4) minimal base (alpine), (5) no secrets in layers (use build args with caution or secrets management). .dockerignore: exclude node_modules, .git, tests. Best practices: COPY package.json before code (cache deps), use npm ci not npm install, clean cache (RUN apt-get update && install && rm -rf /var/lib/apt/lists/*), use ARG for build-time vars, ENV for runtime.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (188, 'Explain Docker networking modes (bridge, host, overlay, none). When should you use each?',
     'Bridge (default): private internal network, containers get IP (172.17.x.x), communicate via IPs or container names (with custom network), NAT to external. Create: docker network create mynet. Use: isolated app stack. Commands: docker run --network mynet. Container DNS: containers on same custom bridge resolve by name. Host: container uses host network directly, no isolation, best performance, can bind to any port. Use: high-performance networking, need localhost access. docker run --network host. None: no networking, fully isolated. Use: batch jobs, security. Overlay: multi-host networking for swarm/k8s, containers across hosts communicate. Use: cluster deployments. bridge_nf: legacy. Macvlan: assign MAC address, container appears as physical device. Use: legacy apps needing direct L2 access. Port mapping: -p 8080:80 (host:container). Multiple networks: docker network connect. Troubleshooting: docker network inspect, check with docker exec container ping other. Best practices: use custom bridges (not default), don''t use host in production unless necessary, overlay for orchestration.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (189, 'How do you manage data persistence with Docker volumes, bind mounts, and tmpfs? Compare their use cases.',
     'Three types: (1) Volumes: managed by Docker, stored in /var/lib/docker/volumes/, best for persistence. Create: docker volume create myvol. Use: docker run -v myvol:/app/data. Benefits: managed by Docker, work on all platforms, can be shared, backup/restore easy. Use for: databases, app state. (2) Bind mounts: map host path to container. docker run -v /host/path:/container/path or --mount type=bind,source=/host,target=/container. Benefits: direct host access, good for development (code changes reflected). Cons: host-dependent, permission issues. Use for: development (mount source code), config injection. (3) tmpfs: memory only, lost on stop. docker run --tmpfs /app/cache. Use for: sensitive data (not persisted), temp files. Read-only: docker run -v myvol:/data:ro. Named vs anonymous: named volumes persist, anonymous (created without name) harder to manage. Management: docker volume ls, docker volume inspect, docker volume prune. Best practices: volumes for production data, bind mounts for development, avoid storing in container filesystem (lost on removal), backup volumes regularly, use volume drivers for cloud storage.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (190, 'Design a Docker Compose setup for a microservices app with database, caching, load balancer, and proper networking.',
     'version: "3.8"\n\nservices:\n  postgres:\n    image: postgres:15-alpine\n    environment:\n      POSTGRES_DB: mydb\n      POSTGRES_USER: user\n      POSTGRES_PASSWORD_FILE: /run/secrets/db_password\n    volumes:\n      - postgres_data:/var/lib/postgresql/data\n    networks:\n      - backend\n    secrets:\n      - db_password\n    healthcheck:\n      test: ["CMD", "pg_isready", "-U", "user"]\n      interval: 10s\n      timeout: 5s\n      retries: 5\n\n  redis:\n    image: redis:7-alpine\n    command: redis-server --appendonly yes\n    volumes:\n      - redis_data:/data\n    networks:\n      - backend\n\n  api:\n    build:\n      context: ./api\n      target: production\n    depends_on:\n      postgres:\n        condition: service_healthy\n      redis:\n        condition: service_started\n    environment:\n      DATABASE_URL: postgres://user@postgres/mydb\n      REDIS_URL: redis://redis:6379\n    networks:\n      - backend\n      - frontend\n    deploy:\n      replicas: 3\n      restart_policy:\n        condition: on-failure\n\n  nginx:\n    image: nginx:alpine\n    ports:\n      - "80:80"\n    volumes:\n      - ./nginx.conf:/etc/nginx/nginx.conf:ro\n    networks:\n      - frontend\n    depends_on:\n      - api\n\nnetworks:\n  frontend:\n  backend:\n\nvolumes:\n  postgres_data:\n  redis_data:\n\nsecrets:\n  db_password:\n    file: ./secrets/db_password.txt\n\nBest practices: health checks, depends_on, separate networks, secrets management, named volumes, resource limits (add deploy.resources).',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 39: Container Orchestration (5 questions)
    (191, 'What is container orchestration? Compare Docker Swarm, Kubernetes, and when to use each.',
     'Container orchestration: automated deployment, scaling, networking, and management of containers. Features: scaling, self-healing, load balancing, rolling updates, service discovery. Docker Swarm: native Docker orchestration, simple setup, built into Docker, declarative services. Pros: easy learning curve, good for small-medium deployments. Cons: less features than K8s, smaller ecosystem. Kubernetes (K8s): industry standard, complex but powerful, huge ecosystem, cloud-agnostic. Pros: advanced features (auto-scaling, operators), large community, production-grade. Cons: steep learning curve, operational complexity. Managed services: ECS (AWS), AKS (Azure), GKE (Google) abstract complexity. Choose Docker Swarm: small team, simpler requirements, already using Docker, quick setup. Choose K8s: large scale, need advanced features, hybrid/multi-cloud, production enterprise apps. ECS: AWS-native, simpler than K8 for AWS. Modern trend: Kubernetes dominates, Swarm for specific simple cases, serverless (Fargate, Cloud Run) abstracts further. Best practice: start simple (Swarm/ECS), migrate to K8s as complexity grows.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (192, 'Explain Kubernetes architecture: control plane, nodes, pods, services. How do they interact?',
     'Control Plane components: (1) API Server (kube-apiserver): frontend for K8s, REST API, all communication goes through it. (2) etcd: distributed key-value store, stores cluster state. (3) Scheduler (kube-scheduler): assigns pods to nodes based on resources. (4) Controller Manager: runs controllers (replication, endpoints, namespace). (5) Cloud Controller: integrates with cloud providers. Node (worker) components: (1) kubelet: agent on each node, ensures containers running, reports to control plane. (2) kube-proxy: network proxy, implements Services, handles load balancing. (3) Container runtime: Docker, containerd, CRI-O. Resources: (1) Pod: smallest unit, one or more containers, shared network/storage, ephemeral. (2) Service: stable endpoint for pods, load balances, types: ClusterIP (internal), NodePort (external on node IP), LoadBalancer (cloud LB). (3) Deployment: manages ReplicaSets, rolling updates. (4) ConfigMap/Secrets: configuration. Flow: kubectl → API Server → etcd (store) → Scheduler (assign) → kubelet (run). Service discovery: CoreDNS resolves service names. Best practice: understand control plane for troubleshooting, pods are ephemeral (design for it).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (193, 'How do you deploy applications to Kubernetes? Explain Deployments, StatefulSets, and DaemonSets.',
     'Deployment: stateless apps, manages ReplicaSets, rolling updates, rollback. YAML: apiVersion: apps/v1, kind: Deployment, spec: replicas: 3, strategy: RollingUpdate. Updates: kubectl set image deployment/app app=image:v2 or edit YAML and apply. Rollback: kubectl rollout undo. Use for: web apps, APIs, stateless workers. StatefulSet: stateful apps, stable network identity (pod-0, pod-1), ordered deployment/scaling, persistent volumes per pod. Example: databases (though operators better). YAML: serviceName for headless service. Scaling: ordered (0→1→2). Updates: rolling or onDelete. Use for: databases, distributed systems needing stable identity. DaemonSet: runs pod on every node (or subset), for node-level tasks. Example: log collectors (Fluentd), monitoring (node-exporter), network (CNI). Updates: automatically to new nodes. Use for: cluster-wide system services. Job: run to completion. CronJob: scheduled jobs. Comparison: Deployment (stateless, most common), StatefulSet (stateful, complex), DaemonSet (per-node), Job (batch). Best practices: use Deployments for most apps, StatefulSets for databases (or use operators), DaemonSets for infrastructure, define resources (limits/requests).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (194, 'Explain Kubernetes networking: ClusterIP, NodePort, LoadBalancer, Ingress. How do you expose services?',
     'Service types: (1) ClusterIP (default): internal IP, accessible only within cluster. DNS: service-name.namespace.svc.cluster.local. Use: internal communication (backend to database). (2) NodePort: exposes on each node''s IP on static port (30000-32767). External access: <NodeIP>:<NodePort>. Use: development, testing, non-production. (3) LoadBalancer: cloud provider LB, external IP. Best for production external access on cloud. (4) ExternalName: CNAME to external service. Ingress: L7 load balancer, routes HTTP(S) to services, single entry point, host/path-based routing. Requires Ingress Controller (nginx, traefik). Example: apiVersion: networking.k8s.io/v1, kind: Ingress, rules: host: app.com, paths: /api → service:api, / → service:frontend. TLS termination, virtual hosts. Network policies: firewall rules between pods. CNI plugins: Calico, Flannel, Weave. Service mesh (Istio, Linkerd): advanced routing, mTLS, observability. Best practices: ClusterIP for internal, Ingress+LoadBalancer for production external access, avoid NodePort in production, use Network Policies for security, DNS for service discovery.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (195, 'You need to deploy a microservice to Kubernetes with zero-downtime deployments, auto-scaling based on CPU/memory, and secret management. Discuss the trade-offs between different update strategies (RollingUpdate vs Recreate vs Blue/Green vs Canary). How would you configure health checks to prevent bad deployments, and what are the considerations for resource requests vs limits?',
     'Update strategies compared: (1) RollingUpdate: gradually replaces old pods, zero downtime, maxSurge/maxUnavailable control rollout speed. Pros: safe, default. Cons: both versions run simultaneously (compatibility issues). (2) Recreate: kills all old pods then creates new. Pros: simple, no version mixing. Cons: downtime. (3) Blue/Green: full environment switch. Pros: instant rollback, testing in production. Cons: double resources, DNS/LB switch complexity. (4) Canary: gradual traffic shift (5% → 50% → 100%). Pros: risk mitigation, real user testing. Cons: requires service mesh, complex routing. Health checks: Liveness probe restarts unhealthy containers (aggressive, use for deadlocks). Readiness probe removes from service (use for dependencies). Startup probe for slow-starting apps. Trade-offs: aggressive probes cause restart loops, lenient probes leave unhealthy pods in rotation. Resources: requests (guaranteed, used for scheduling), limits (maximum, OOMKilled if exceeded). Set requests = typical usage, limits = burst capacity. Too low requests = poor scheduling. Too high = resource waste. No limits = noisy neighbors. Secrets: Kubernetes Secrets (base64, not encrypted at rest by default), external secret managers (Vault, AWS Secrets Manager) for rotation and audit. ConfigMaps for non-sensitive config. Consider: init containers for setup, pod disruption budgets for availability, HPA scaling metrics (CPU vs custom metrics), resource quotas per namespace.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),


    -- Topic 40: CI/CD (5 questions)
    (196, 'What is the difference between Continuous Integration, Continuous Delivery, and Continuous Deployment?',
     'Continuous Integration (CI): automatically build and test code changes on every commit to shared repository. Catches integration issues early, requires automated tests, build server (Jenkins, GitHub Actions). Continuous Delivery (CD): extends CI by automatically deploying to staging/pre-production environments, ready for production release but requires manual approval. Continuous Deployment: fully automated - every passing change automatically deployed to production without manual intervention. Progression: CI < Delivery < Deployment (increasing automation). Use CI for: all projects (minimum). CD for: most production apps (safety net). Continuous Deployment for: high-maturity teams, non-critical services, feature-flagged deployments. Benefits: faster feedback, reduced risk (small changes), consistent deployments.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (197, 'Explain different deployment strategies: Blue/Green, Canary, Rolling, and Recreate. When would you use each?',
     'Blue/Green: two identical environments, switch traffic from blue (old) to green (new), instant rollback by switching back. Use for: critical services, database migrations, major versions. Pros: zero downtime, quick rollback. Cons: double resources, database sync complexity. Canary: deploy to small subset (5%), gradually increase (25%, 50%, 100%), monitor metrics, rollback if issues. Use for: risk-averse deployments, user-facing changes. Pros: real-world testing, limited blast radius. Cons: complex routing, extended deployment time. Rolling: gradually replace instances one-by-one or in batches. Use for: standard deployments, stateless services. Pros: no extra resources, built-in to K8s. Cons: mixed versions during rollout. Recreate: stop all old, start all new. Use for: development, incompatible versions. Pros: simple. Cons: downtime. Modern trend: canary with automated rollback based on metrics (error rate, latency).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (198, 'How would you implement automated testing in a CI/CD pipeline? Discuss the testing pyramid and parallel execution.',
     'Testing pyramid: many unit tests (fast, isolated, 70%), some integration tests (moderate speed, test interactions, 20%), few E2E tests (slow, full system, 10%). CI/CD integration: commit triggers build, run unit tests (< 5 min), run integration tests (< 15 min), deploy to staging, run E2E tests, deploy to production. Parallel execution: split tests into groups (test sharding), run on multiple agents, combine results. Tools: test parallelization (Jest sharding, pytest-xdist), containerized test environments (Docker), test results caching. Fast feedback: fail fast on unit tests, run expensive tests on main branch only, flaky test quarantine. Quality gates: minimum code coverage (80%), no critical vulnerabilities, passing tests required for merge. Advanced: contract testing for microservices, visual regression tests, performance tests in pipeline.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (199, 'Explain trunk-based development vs GitFlow. Compare branch strategies and their impact on CI/CD.',
     'Trunk-based: developers commit directly to main (trunk) frequently (daily), short-lived feature branches (< 2 days), feature flags for incomplete features, requires strong CI/CD and automated testing. GitFlow: structured branching with main, develop, feature, release, hotfix branches, longer-lived branches, explicit release process. Trunk-based pros: simple, fast feedback, encourages small changes, easier CI/CD. Cons: requires discipline, feature flags needed, broken main impacts everyone. GitFlow pros: clear release process, parallel versions, safer for junior teams. Cons: merge overhead, delayed integration, complex CI/CD across branches. CI/CD impact: Trunk-based enables continuous deployment (always deployable main), GitFlow better for scheduled releases (release branches). Modern trend: trunk-based for web/cloud, GitFlow for versioned products. Hybrid: trunk-based with release branches for long-term support.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (200, 'Your company needs to implement CI/CD for a monorepo containing 20 microservices with different tech stacks (Node.js, Python, Go). Discuss strategies for efficient build caching, selective service deployment based on changes, and managing shared dependencies. What are the trade-offs between monorepo vs multi-repo for CI/CD?',
     'Monorepo CI/CD challenges: (1) Build time - building everything on every commit is slow. (2) Change detection - which services changed. (3) Shared dependencies - one change affects many services. (4) Resource usage - running all tests expensive. Solutions: Affected service detection using git diff to identify changed paths, build dependency graph, only build/test affected services and their dependents. Build caching: hash-based caching (nx, turborepo), cache Docker layers, shared dependency caching (node_modules, pip cache). Parallel builds: matrix strategy to build services concurrently, separate pipelines per service. Shared dependencies: lock versions in workspace, automated dependency updates (Dependabot), integration tests when shared code changes. Deployment: deploy only changed services, use feature flags for coordinated releases, canary deployment for risky changes. Monorepo vs multi-repo trade-offs: Monorepo pros: atomic commits across services, code reuse easy, consistent tooling. Cons: complex CI/CD, repository size, slower clones. Multi-repo pros: simple CI/CD per repo, clear ownership, independent versioning. Cons: dependency hell, code duplication, cross-repo changes difficult. Modern tools: Nx/Turborepo for monorepos bring computation caching making monorepo builds competitive with multi-repo. Decision factors: team size, service interdependence, change frequency patterns.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 41: Monitoring and Observability (5 questions)
    (201, 'What is the difference between monitoring, metrics, logging, and tracing? How do they complement each other?',
     'Monitoring: tracking system health and performance over time, alerting on issues. Metrics: numerical measurements (CPU, latency, request rate), aggregated time-series data, efficient storage. Logging: discrete events with context (errors, requests), searchable text, debug-level detail. Tracing: tracking requests across distributed systems, shows call paths and timing. Three pillars of observability: metrics (what is broken), logs (why it broke), traces (where it broke). Complementary: metrics alert on high error rate, logs show error details,traces reveal which service failed in call chain. Example: metric shows latency spike, trace identifies slow database query, log shows specific slow query SQL. Modern: unified platforms (Datadog, New Relic), correlated by request ID, context propagation across services. Use metrics for: dashboards, alerts. Logs for: debugging, auditing. Traces for: distributed debugging, performance optimization.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (202, 'Explain the RED and USE methods for monitoring. When would you apply each?',
     'RED method (for services): (1) Rate - requests per second, (2) Errors - failed request rate, (3) Duration - latency/response time. Focus on user-visible metrics. USE method (for resources): (1) Utilization - % busy (CPU, disk), (2) Saturation - queue depth/wait time, (3) Errors - error count. Focus on infrastructure. RED for: application services, APIs, microservices, user-facing systems. USE for: infrastructure (servers, databases, queues), capacity planning. Example: RED for web API (requests/sec, error rate, p95 latency). USE for database server (CPU utilization, queue depth, connection errors). Both together: RED identifies service issues, USE finds resource bottlenecks. Modern additions: Four Golden Signals add Saturation to RED. SLIs (Service Level Indicators) based on these metrics inform SLOs. Combine with business metrics (signups, revenue) for complete picture.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (203, 'How do you design effective alerts that minimize false positives and alert fatigue? Explain SLOs and error budgets.',
     'Alert design principles: (1) Alert on symptoms (user impact) not causes (disk space), (2) Make alerts actionable (know what to do), (3) Set appropriate thresholds (avoid noise), (4) Use multiple data points (avoid transient spikes). Techniques: moving averages, percentiles (p95, p99) instead of max, grace periods, flap detection. Alert fatigue: too many alerts = ignored alerts. Solutions: consolidate related alerts, escalation tiers, acknowledge/snooze capabilities, retrospective analysis to tune thresholds. SLO (Service Level Objective): target for reliability (99.9% uptime, p95 latency < 200ms). SLA (agreement) vs SLI (measurement) vs SLO (target). Error budget: allowed downtime (99.9% = 43 mins/month). Exceeding budget triggers response: freeze launches, focus on reliability. Benefits: balances feature velocity and reliability, quantifies acceptable risk. Alert strategy: page on SLO violations (user impact), ticket on resource issues (proactive). Advanced: multi-window alerts (5min and 1hr), ML-based anomaly detection.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (204, 'Compare pull-based (Prometheus) vs push-based (StatsD, CloudWatch) monitoring. What are the architectural differences and trade-offs?',
     'Pull-based (Prometheus): monitoring server scrapes metrics from targets at intervals, targets expose /metrics endpoints. Pros: centralized control (scrape interval, targets), service discovery integration, simpler targets (just expose endpoint), easier to add/remove services. Cons: requires network access to all targets, targets must be discoverable, scrape interval limits granularity. Push-based (StatsD, CloudWatch): applications push metrics to collection service. Pros: works behind NAT/firewalls, applications control when to send, batch metrics, short-lived jobs easier. Cons: applications need monitoring config, network issues drop metrics, harder to discover what''s being monitored. Hybrid:Prometheus with Pushgateway for batch jobs, metrics in both pull for infrastructure and push for applications. Trade-offs: Pull better for service discovery in K8s, microservices. Push better for serverless, edge, batches. Network topology: pull requires monitoring server to reach services (VPN/mesh), push works through firewalls. Cardinality: pull makes target scraping the bottleneck (good), push can overwhelm collector. Modern: OpenTelemetry provides unified API supporting both push and pull.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (205, 'You''re experiencing performance degradation in a distributed microservices system (10+ services). Your monitoring shows increased latency but no clear errors. Describe your debugging approach using observability tools. How would you correlate metrics, logs, and traces to identify the root cause? What signals would you look for?',
     'Systematic debugging approach: (1) Start with user impact - which endpoints affected, error rates, latency percentiles (p50/p95/p99). (2) Use distributed tracing - find traces with high duration, identify slow service in call chain, look for sequential vs parallel call patterns. (3) Correlate with metrics - for identified slow service check: CPU/memory utilization (resource exhaustion), request rate (traffic spike), dependency latency (downstream issue), queue depth (saturation). (4) Dive into logs - filter by slow trace IDs, look for errors/warnings, check for retry loops or timeouts. Patterns to investigate: Sudden increase in p99 but not p50 suggests outliers (cache misses, expensive queries). All percentiles up suggests resource saturation. Specific endpoint slow suggests code issue. All endpoints slow suggests infrastructure (DB, network). Common root causes: DB connection pool exhausted (check connection metrics), cache invalidation (check hit rates), deployment just occurred (check version), resource limits hit (check container throttling), external API slowdown (check dependency latency), memory leaks (check heap usage trend). Tools usage: Jaeger/Zipkin for traces → identify slow span, Prometheus for metrics → resource utilization, Loki/ELK for logs → error details. Correlation keys: trace ID, span context, request ID propagated through headers. Advanced: Compare current metrics with historical baseline, check for cascading failures (timeout increases causing retry storms), use flamegraphs for CPU profiling. Prevention: Implement circuit breakers, proper timeouts, resource limits, gradual rollouts.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),


    -- Topic 42: Logging (5 questions)
    (206, 'What are the differences between structured and unstructured logging? Why is structured logging preferred in modern systems?',
     'Unstructured: plain text messages, human-readable, hard to parse ("User jdoe logged in from 192.168.1.1"). Structured: key-value pairs or JSON, machine-parseable, consistent format ({"user": "jdoe", "ip": "192.168.1.1", "event": "login"}). Structured logging advantages: (1) Easy filtering/aggregation (find all logins by user), (2) Efficient storage in log management systems, (3) Enables metrics extraction, (4) Consistent across services, (5) Better for automated analysis. Implementation: use logging libraries with structured support (Winston, Logrus, structlog), include standard fields (timestamp, level, service, request_id). Best practices: use consistent field names, avoid sensitive data, include trace/span IDs for correlation, log at appropriate levels (DEBUG, INFO, WARN, ERROR). Modern: JSON logs to stdout, collected by log shipper (Fluentd, Vector), stored in centralized system (Elasticsearch, Loki).',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (207, 'Explain log levels (DEBUG, INFO, WARN, ERROR, FATAL). When should you use each and how do you manage log verbosity in production?',
     'Log levels: (1) DEBUG: detailed diagnostic info for development, verbose. (2) INFO: general informational messages, key events (startup, shutdown, state changes). (3) WARN: potentially harmful situations, degraded mode, fallback used. (4) ERROR: error events that allow app to continue. (5) FATAL/CRITICAL: severe errors causing shutdown. Usage: DEBUG for troubleshooting (disabled in prod), INFO for operational insight (enabled in prod), WARN for attention needed, ERROR for failures, FATAL for end states. Production verbosity: default to INFO, enable DEBUG for specific services/modules dynamically, use sampling for high-volume (1% of DEBUG logs). Dynamic log levels: change without restart via API/config, temporary DEBUG for problem investigation. Volume management: rate limiting (max logs/sec), log sampling (only log 1% of frequent events), conditional logging (log only when error threshold exceeded). Cost: logs are expensive (storage, indexing), balance detail vs cost. Best practice: log sparingly in hot paths, aggregate similar events, use counters instead of individual logs where possible.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (208, 'How do you implement log aggregation in a distributed system? Compare ELK stack vs Splunk vs Cloud-native solutions.',
     'Log aggregation pattern: apps log to stdout → shipper collects → central storage → query/visualization. ELK Stack (Elasticsearch, Logstash, Kibana): open-source, Logstash collects/transforms, Elasticsearch stores/indexes, Kibana visualizes. Pros: flexible, powerful search, free. Cons: resource-intensive ES, complex scaling, maintenance overhead. Splunk: commercial, powerful query language (SPL), excellent visualization, machine learning. Pros: enterprise features, support, easy setup. Cons: expensive, proprietary. Loki (& Grafana): labels-based indexing (not full-text), cost-efficient, integrates with Prometheus. Pros: cheaper, simpler, good for metrics+logs correlation. Cons: limited full-text search. Cloud-native: CloudWatch (AWS), Cloud Logging (GCP), Azure Monitor. Pros: integrated, managed, auto-scaling. Cons: vendor lock-in, cost at scale, limited customization. Modern approach: Fluentd/Fluent Bit as shipper (lightweight, pluggable), choice of backend based on needs. Considerations: log volume (cost), retention period (compliance), query patterns (full-text vs labels), integration with existing tools.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (209, 'What is log correlation in distributed systems? How do you implement request tracing across multiple services?',
     'Log correlation: connecting logs from different services for the same request to trace execution flow. Implementation: (1) Correlation ID (request ID, trace ID) generated at entry point, propagated through all service calls via headers (X-Request-ID, X-Trace-ID), included in all log entries. (2) Include correlation ID in structured logs: {"trace_id": "abc123", "span_id": "xyz", "message": "..."}. (3) Query all logs by trace_id to see full request flow. Standards: W3C Trace Context for header propagation, OpenTelemetry for unified approach. Challenges: ensuring ALL services propagate ID (middleware/interceptors help), legacy services without correlation support, async/background jobs (maintain parent trace ID). Additional context: user ID, session ID, tenant ID for multi-dimensional filtering. Distributed tracing: extends correlation with timing, dependencies, causality (Jaeger, Zipkin). Benefits: debug cross-service issues, performance analysis, identify bottlenecks. Best practice: use instrumentation libraries (auto-propagation), log at service boundaries (entry/exit), include both trace and span IDs for detailed tracing.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (210, 'Your logging infrastructure is becoming expensive - storing 100TB/month of logs costing $10K/month. Discuss strategies to reduce log volume and costs while maintaining observability. How would you decide what to keep, what to sample, and what to discard? What are the risks?',
     'Cost reduction strategies analyzed: (1) Log level tuning: shift DEBUG to WARN in production saves 60-70%, use dynamic levels for targeted debugging. (2) Sampling: log 1% of successful requests (200 OK), 100% of errors. Reduces volume significantly while catching issues. (3) Filtering: drop noisy logs (health checks, static assets, known bot traffic). (4) Aggregation: instead of logging each event, aggregate (log "1000 successful logins" vs 1000 individual lines). (5) Retention tiers: hot (7 days, full search) → warm (30 days, compressed) → cold (1 year archive, cheaper storage → delete. (6) Field reduction: remove verbose fields (full request bodies), keep essential fields only. Decision framework: Always log: all errors (4xx, 5xx), security events (authentication, authorization), business-critical events (transactions, user actions). Sample heavily: successful routine operations (1-10%), verbose debug logs. Never log: sensitive data (PII, secrets), high-volume health checks (or aggregate). Techniques: Smart sampling: sample based on latency (log slow requests 100%, fast requests 1%), error-based (log request if any service in chain errored). Log levels per service (noisy service at WARN, critical service at INFO). Metrics instead of logs: convert repetitive logs to metrics (counters for event counts, histograms for latency). Risks: Missing critical debugging info when needed, sampling bias (may miss rare but important events), over-aggressive filtering hides issues. Mitigation: Test sampling in staging first, log error context even with sampling, structured tags allow emergency filter override, keep full logs short-term (24 hrs) before sampling. Real-world: 70-90% cost reduction possible with thoughtful strategy, balance cost vs debugging capability, use tags for dynamic verbosity.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 43: Infrastructure as Code (5 questions)
    (211, 'What is Infrastructure as Code? Compare declarative vs imperative approaches.',
     'Infrastructure as Code (IaC): managing infrastructure through code files rather than manual configuration. Benefits: version control, reproducibility, automation, documentation, peer review. Declarative: describe desired end state, tool figures out how to achieve it (Terraform, CloudFormation, Kubernetes YAML). Example: "3 web servers in us-east-1". Tool creates, updates, or deletes as needed. Imperative: explicit step-by-step commands to achieve state (Ansible playbooks with tasks, scripts). Example: "create server 1, create server 2, create server 3". Declarative pros: idempotent (safe to rerun), tool handles dependencies, clearer intent. Cons: less control over order, debugging harder. Imperative pros: precise control, easier to understand execution, better for complex procedures. Cons: not inherently idempotent, must track state manually. Modern trend: declarative for infrastructure (Terraform), imperative for configuration/deployment (Ansible). Best practice: use declarative when possible, imperative for specific workflows.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (212, 'Explain Terraform state and why it''s important. How do you manage state in a team environment?',
     'Terraform state: tracks mapping between configuration and real resources, stores metadata, enables drift detection. Without state, Terraform doesn''t know what it created. Local state problems: file on developer''s machine, no sharing, concurrent modifications cause conflicts, state loss catastrophic. Remote state solutions: (1) Terraform Cloud/Enterprise: hosted, locking, versioning, collaboration. (2) S3 + DynamoDB: S3 stores state, DynamoDB provides locking, encryption at rest. (3) Azure Blob, GCS: cloud storage with locking. State locking prevents concurrent modifications. Best practices: (1) always use remote backend for teams, (2) enable versioning (state history), (3) encrypt state (contains sensitive data like passwords), (4) limit access (IAM), (5) separate state per environment (dev, prod), (6) use workspaces or separate directories for isolation. State management: terraform state commands for inspection, import existing resources, move/remove resources carefully, never edit state file manually. Backup: automated backups before destructive operations.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (213, 'Compare Terraform, CloudFormation, Pulumi, and CDK. When would you choose each?',
     'Terraform: vendor-agnostic (AWS, Azure, GCP, 1000+ providers), HCL language, mature ecosystem, state management. Pros: multi-cloud, huge community, reusable modules. Cons: HCL learning curve, state complexity. CloudFormation: AWS-native, JSON/YAML, deep AWS integration, no state files (AWS manages). Pros: native AWS support, no extra tools, StackSets for multi-account. Cons: AWS-only, verbose YAML, slower updates than Terraform, limited drift detection. Pulumi: real programming languages (TypeScript, Python, Go), same multi-cloud provider ecosystem as Terraform. Pros: familiar languages, better testing, complex logic easy. Cons: newer, smaller community, mixing infrastructure and application logic risky. CDK (Cloud Development Kit): Higher-level constructs, compiles to CloudFormation, programming languages. Pros: reusable constructs,AWS best practices built-in. Cons: AWS-only, abstraction overhead. Choose Terraform for: multi-cloud, mature tools/modules, declarative preference. CloudFormation for: AWS-only, tight AWS integration, no external tools. Pulumi for: prefer programming languages, complex logic, strong typing. CDK for: AWS-only, application developers doing infrastructure. Modern: Terraform dominates multi-cloud, CloudFormation for AWS purists, CDK/Pulumi growing for developer experience.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (214, 'How do you test Infrastructure as Code? Discuss unit testing, integration testing, and policy validation.',
     'Testing pyramid for IaC: (1) Static analysis/Linting: syntax validation (terraform validate), style (tflint), security (tfsec, Checkov). Fast, catch basic errors. (2) Unit tests: test modules in isolation with mocked providers. Tools: Terratest, pytest for Pulumi. Test: module outputs for given inputs, edge cases. (3) Policy validation: enforce rules (naming, tagging, encryption). Tools: OPA (Open Policy Agent), Sentinel (Terraform), AWS  Config. Example: deny public S3 buckets, require encryption. (4) Plan testing: run terraform plan against real provider APIs (dry-run), validate changes. (5) Integration testing: deploy to test environment, validate infrastructure works (APIs accessible, security groups correct). Tools: Terratest, InSpec, serverspec. (6) Smoke tests: basic functionality post-deployment. Challenges: cost of provisioning real resources, cleanup (orphaned resources), test environment isolation. Best practices: test modules separately, use terraform workspaces for test isolation, automate teardown, test drift detection, validation in CI/CD. Advanced: mutation testing for policies, contract testing between modules.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (215, 'You need to migrate existing manually-created infrastructure (100+ resources across AWS: VPCs, EC2, RDS, S3) to Terraform management. Discuss your migration strategy. How do you handle terraform import, minimize risk, and ensure business continuity? What are the challenges of state drift?',
     'Migration strategy phases: (1) Discovery & Documentation: audit all resources using AWS Config/resource tagging, document dependencies, identify resource owners. (2) Prioritization: start with stateless resources (security groups, IAM) before stateful (databases, S3), group by environment/service, low-risk first (dev before prod). (3) Import approach: Write Terraform config matching existing resources → terraform import for each resource → verify terraform plan shows no changes. Challenges: Import only adds to state (doesn''t generate config), must write config manually, resource dependencies complex, some resources can''t be imported (recreate needed). Risk mitigation: Read-only practice runs (plan only), test in lower environments first, maintain rollback plan (manual console access), schedule maintenance windows for stateful resources, use feature flags to switch traffic if needed. State drift: manually created resources not in Terraform, manual console changes override IaC, resources deleted outside Terraform. Handling drift: Regular drift detection (terraform plan in CI), alerts on drift, strict IAM policies (only Terraform can modify), break-glass procedures for emergencies with post-incident state sync. Tools: terraformer for automated config generation from existing infrastructure, driftctl for comprehensive drift detection. Migration chunks: Small batches (10-20 resources), test each batch, automated validation, gradual ownership transfer. Challenges: Resources with hard-coded IDs/ARNs in apps, lack of resource tagging (ownership unclear), stateful services (downtime risk), multi-account/region complexity. Best practice: Document everything, communicate with teams, maintain backup state files, don''t modify resources during migration window, celebrate small wins.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),


    -- Topic 44: Configuration Management (5 questions)
    (216, 'Compare configuration management tools: Ansible, Chef, Puppet, Salt. When would you use each?',
     'Ansible: agentless (SSH), YAML playbooks, push-based, simple. Pros: easy setup, no agents, idempotent, good for orchestration. Cons: slower (SSH overhead), limited scalability. Chef: agent-based, Ruby DSL, pull-based, code-centric. Pros: powerful, good for complex logic, version control. Cons: steep learning curve, requires infrastructure (Chef server). Puppet: agent-based, declarative DSL, pull-based, mature. Pros: strong model consistency, good for large fleets, compliance. Cons: complex, resource-intensive. Salt: agent-based, Python, event-driven, fast. Pros: very fast, scalable, flexible. Cons: smaller community. Choose Ansible for: cloud provisioning, orchestration, small-medium scale, quick wins. Chef/Puppet for: large enterprise fleets, compliance-heavy, complex configurations. Salt for: real-time, high-performance needs. Modern trend: Ansible dominates for cloud, containers reduce need for configuration management (immutable infrastructure), IaC tools (Terraform) overlap with CM.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (217, 'What is configuration drift and how do you prevent/detect it? Discuss immutable vs mutable infrastructure.',
     'Configuration drift: servers diverge from desired state over time due to manual changes, partial failures, incomplete automation. Causes: emergency fixes via SSH, automated updates, disk fills, manual troubleshooting. Problems: inconsistent behavior, hard to debug, compliance violations, deployment failures. Prevention/Detection: (1) Regular configuration checks (Ansible check mode, Puppet noop), (2) Alert on drift, (3) Immutable infrastructure (no changes, replace instead), ( 4) Strong IAM policies (prevent manual changes), (5) Configuration versioning, (6) Compliance scanning (InSpec, AWS Config). Mutable infrastructure: servers updated in-place (traditional approach). Pros: resource efficiency, gradual updates. Cons: drift risk, complex state management, harder rollback. Immutable infrastructure: never modify, deploy new instances with changes, terminate old. Pros: no drift, predictable, easy rollback, consistent. Cons: more resources during deploy, slower updates, stateful data complexity. Modern approach: containers are inherently immutable, servers as immutable, databases as stateful exceptions, use IaC for all changes, golden images (Packer) for base instances.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (218, 'Explain the concept of desired state configuration. How does it differ from procedural configuration?',
     'Desired state: declare what end state should be, tool ensures it matches, idempotent (safe to rerun). Example: "Ensure nginx installed and running". Tool checks current state, takes action only if needed. Procedural: step-by-step instructions, order matters, not automatically idempotent. Example: "apt-get install nginx, systemctl start nginx". Running twice might error or duplicate. Desired state advantages: (1) Self-healing - run periodically, converges to desired state, (2) Idempotence - safe retries, (3) Drift correction - deviations fixed automatically, (4) Simpler mental model - declare intent not steps. Tools: Ansible (mostly declarative modules), Puppet, Chef (desired state), Kubernetes (reconciliation loops). Limitations: some operations inherently procedural (multi-step migrations, database updates), complex dependencies need careful ordering. Best practice: prefer desired state for infrastructure, procedural for one-time operations or complex workflows, use proper modules (not shell commands) for idempotence.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (219, 'How do you manage application configuration across multiple environments (dev, staging, production)? Compare different approaches: environment variables, config files, config servers.',
     'Approaches comparison: (1) Environment variables: 12-factor app pattern, simple, platform-agnostic (Docker, Lambda). Pros: simple, secure (not in code), container-friendly. Cons: no hierarchy, no types (all strings), scattered in deployment configs. (2) Config files: JSON/YAML per environment, bundled or external. Pros: structure/hierarchy, human-readable, can version. Cons: secrets risky in files, deployment complexity. (3) Config servers: centralized (Spring Cloud Config, Consul), apps fetch at startup. Pros: centralized management, dynamic updates, audit trail. Cons: dependency (must be up), network calls, complexity. (4) Kubernetes ConfigMaps/Secrets: mounted as env vars or files. Pros: K8s-native, versioned, decoupled. Cons: K8s-specific. Best practices: Separate config layers - app defaults < environment overlays < secrets (externalized). Use config servers for: large number of apps/services, dynamic config updates, centralized governance. Use env vars for: simple deployments, containers, cloud functions. Never: hardcode secrets, commit production configs to repo. Modern: combination approach - structure in config files, secrets in vault, overrides via env vars, feature flags for runtime behavior.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (220, 'Your microservices architecture has configuration scattered across environment variables, config files, Kubernetes ConfigMaps, and a legacy database table. Teams are struggling with config sprawl - finding which service uses which config, tracking changes, and ensuring consistency. Design a strategy to consolidate and govern configuration. What are the trade-offs between centralization vs decentralization?',
     'Config sprawl challenges: discoverability (where is config X?), consistency (dev/prod parity), security (secrets mixed with config), versioning (who changed what when), validation (typos cause outages). Consolidation strategy: (1) Audit current state - inventory all config sources, identify overlap/duplication, classify by type (app config, feature flags, secrets, infrastructure). (2) Define taxonomy - config levels (global, service, environment), naming conventions, ownership model. (3) Migration path:Phase 1: Secrets to dedicated vault (HashiCorp Vault, AWS Secrets Manager) - centralized, rotates, audited. Phase 2: Static service config to config server or ConfigMaps - versioned, per-environment. Phase 3: Dynamic config/feature flags to dedicated system (LaunchDarkly, Split.io). Phase 4: Deprecated legacy sources. Trade-offs analyzed: Centralized (config server) pros: single source of truth, easy audit, policy enforcement, change management. Cons: single point of failure, latency, blast radius of bugs affects all services, team autonomy reduced. Decentralized (per-service) pros: team autonomy, service isolation, no shared dependencies. Cons: inconsistency, duplication, harder governance, discovery challenging. Hybrid approach recommended: Centralized secrets management (security critical), decentralized application config (team autonomy), shared infrastructure config (consistency), feature flags system (dynamic runtime). Governance: Config schema validation (prevent typos), required fields enforcement, change approvals for production, config-as-code in Git (GitOps), automated testing of config changes. Rollout: Gradual migration (one service at a time), maintain backwards compatibility during transition, document config locations in service catalog, training for teams on new patterns. Success metrics: Mean time to find config value, config-related outages reduced, time to add/change config.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 45: Secrets Management (5 questions)
    (221, 'Why shouldn''t secrets be stored in code or environment variables? What are the risks?',
     'Risks of secrets in code: (1) Version control exposure - Git history retains forever, public repos leak to world, internal repos accessible to all developers. (2) Copy/paste propagation - secrets duplicated across projects. (3) No rotation - changing secret requires code deploy. (4) Audit trail - who accessed secret unknown. Environment variables risks: (1) Process listing - visible via /proc, ps commands. (2) Logs - often accidentally logged. (3) Crash dumps - included in error reports. (4) Child processes inherit. (5) Container images - baked into layers. Real-world breaches: GitHub secret scanning finds thousands daily, AWS keys in public repos used for crypto mining, database dumps with passwords. Best practices: Secrets in dedicated secret managers (Vault, AWS Secrets Manager), short-lived credentials when possible, principle of least privilege, encrypt at rest, audit access. What''s a secret: passwords, API keys, private keys, tokens, connection strings, encryption keys. Grey area: non-sensitive config can be in env vars/config files.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (222, 'Compare cloud-native secrets managers (AWS Secrets Manager, Azure Key Vault, GCP Secret Manager) with HashiCorp Vault. What are the trade-offs?',
     'Cloud-native (AWS Secrets Manager, Azure Key Vault, GCP Secret Manager): managed service, tight cloud integration, auto-scaling, simple setup, encryption with cloud KMS, native IAM integration. Pros: no infrastructure to manage, integrated with cloud services (RDS auto-rotation), high availability built-in, pay-per-use. Cons: vendor lock-in, multi-cloud harder, limited custom policies, cost per operation. HashiCorp Vault: self-hosted or Vault Cloud, multi-cloud, advanced features (dynamic secrets, encryption-as-a-service, SSH CA), flexible backends, powerful policy engine. Pros: multi-cloud/on-prem, dynamic secret generation, enterprise features (namespaces, replication), fine-grained policies. Cons: operational overhead (HA, unsealing, backups), learning curve, need infrastructure. Use cloud-native for: single cloud, simple use cases, want managed service, tight cloud integration. Use Vault for: multi-cloud, advanced secret workflows (dynamic DB credentials), complex policies, on-prem or hybrid. Hybrid: Vault with cloud secret backends, cloud-native for cloud-specific services. Key features comparison: rotation (all support), dynamic secrets (Vault wins), audit (all good), cost (Vault cheaper at scale for self-hosted).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (223, 'Explain dynamic secrets vs static secrets. How do dynamic secrets improve security?',
     'Static secrets: fixed credentials, manually rotated, shared. Example: database password "myPassword123". Problems: long-lived (large breach window), rotation disruptive (update everywhere), access tracking hard (shared credential). Dynamic secrets: generated on-demand, short-lived (auto-expire), unique per accessor. Example: Vault generates PostgreSQL credentials valid for 1 hour when requested. Security improvements: (1) Minimal blast radius - compromised credential expires soon, only grants access to requester. (2) Automatic revocation - expired credentials auto-deleted in target system. (3) Auditability - know exactly who accessed what and when. (4) Just-in-time access - credentials created only when needed. (5) No rotation pain - credentials naturally expire and renew. Implementation: Vault database secrets engine, AWS STS temporary credentials, ephemeral certificates. Use cases: database access (generate DB user per app instance), cloud credentials (temporary AWS keys), SSH access (one-time certificates). Challenges: application must handle renewal/expiration (lease renewal), backend must support API-driven credential creation, not all systems support (legacy apps). Best practice: use dynamic for new systems, static for legacy with automated rotation.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (224, 'How do you bootstrap secrets in a new application instance? Explain the "chicken and egg" problem and solutions.',
     'Chicken-and-egg problem: application needs credentials to fetch its secrets from secret manager, but how does it get those initial credentials securely? Solutions: (1) Instance metadata: Cloud instance profiles (IAM roles) - EC2/ECS autoget AWS credentials via metadata API, no config needed. GCP/Azure equivalent. Pros: no secrets to deploy. Cons: cloud-specific. (2) Init containers: Kubernetes init container gets secrets using pod service account, populates for main container. (3) Wrapped tokens: Vault wrapping - one-time-use token with limited scope provided at deploy time, app unwraps to get actual credentials. (4) Platform integration: Kubernetes service accounts + Vault auth, automatically authenticated. (5) Hardware security: TPM, secure enclave for boot secrets. Bad solutions to avoid: environment variables in deployment scripts (logged), baked into images (exposed), plain text files on disk. Best practices: Leverage cloud/platform identity (IAM roles, service accounts), minimize bootstrap secret scope and lifetime, rotate bootstrap method if exposed, audit bootstrap access. Modern: service mesh (Istio) provides identity with mTLS, workload identity in clouds maps K8s service accounts to cloud IAM.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (225, 'Your organization has 200+ applications using hundreds of database credentials, API keys, and certificates. Many credentials haven''t been rotated in years and are shared across multiple apps. Design a secrets management migration plan that minimizes risk and business disruption. How do you prioritize which secrets to migrate first? What are the failure modes to plan for?',
     'Risk assessment first: Criticality - production vs dev, customer impact. Exposure - how many apps share credential, logged anywhere, in Git history. Age - last rotation, compliance violations. Privilege - broad access vs limited. Output: risk matrix scoring each credential. Migration prioritization: Phase 1 (High Risk, Low Disruption): Shared production DB passwords (high impact), public git leaks (immediate threat), overprivileged service accounts (blast radius). Phase 2 (Medium Risk): API keys for payment/auth services, SSL/TLS certificates expiring soon, cloud access keys. Phase 3 (Lower Risk): development environment secrets, internal tooling, well-scoped credentials. Migration approach per credential type: (1) Database secrets: create new DB user with same permissions → update app to use dynamic secrets → verify → delete old user. (2) API keys: generate new key → deploy with fallback to old → verify → revoke old. (3) Certificates: provision new cert → deploy both → switch → remove old. Safety measures: Parallel running - new secret alongside old (grace period), automated rollback triggers (error rate spike), phased rollout (canary deployments), maintenance windows for critical services. Failure modes to handle: Secret manager outage (cache last-known good secrets locally), network issues (retry with backoff), app bugs reading new format (validation in staging), certificate mismatch (SAN coverage), rotation breaking legacy integrations (discovery phase is critical). Communication: Stakeholder notification (maintenance windows), runbooks for each migration, on-call coverage during migration, post-migration validation. Success criteria: All production secrets in secret manager (6 months), automated rotation enabled (< 90 day max lifetime), access audit trail, zero shared credentials. Avoid: Big bang migration, weekend deploys without support, skipping testing, no rollback plan.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 46: Service Mesh (5 questions)
    (226, 'What is a service mesh? What problems does it solve in microservices architectures?',
     'Service mesh: dedicated infrastructure layer for service-to-service communication in microservices, uses sidecar proxies (Envoy) alongside each service, control plane manages configuration. Problems solved: (1) Service discovery - services find each other dynamically. (2) Load balancing - client-side LB, advanced routing. (3) Resilience - retries, timeouts, circuit breaking. (4) Observability - automatic metrics, traces, logs. (5) Security - mTLS between services, authorization policies. (6) Traffic management - canary, A/B testing, mirroring. Without service mesh: each service implements these (duplication, language-specific libraries, inconsistency). With service mesh: offloaded to proxies (language-agnostic, consistent, centralized). Components: Data plane (sidecars handle traffic), control plane (configures proxies, collects telemetry). Popular: Istio, Linkerd, Consul Connect. Trade-offs: complexity (extra containers, networking), latency (proxy hop), resource overhead (sidecar per pod). Use when: many microservices, polyglot services, need fine-grained traffic control, observability gaps.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (227, 'Compare Istio, Linkerd, and Consul service meshes. When would you choose each?',
     'Istio: feature-rich, powerful, complex, Envoy-based. Features: advanced traffic management, extensive policy engine, multi-cluster, VM support. Pros: comprehensive, mature, strong ecosystem (Google/IBM). Cons: resource-heavy, complex, steep learning curve. Linkerd: simplest, lightweight, secure-by-default, custom Rust proxy. Features: automatic mTLS, basic routing, simple, good performance. Pros: easy setup, low overhead, excellent docs, opinionated (fewer choices). Cons: fewer features, less flexibility. Consul: HashiCorp, service discovery first, mesh add-on, multi-datacenter focus. Features: service catalog, KV store, multi-cloud/on-prem. Pros: works with VMs and containers, mature service discovery, multi-DC. Cons: less K8s-native, complexity for just mesh features. Choose Istio for: complex traffic scenarios, need full features, team can handle complexity, multi-cluster. Choose Linkerd for: simplicity priority, resource-constrained, faster adoption, Kubernetes-only. Choose Consul for: hybrid VM/container environments, multi-datacenter, already using HashiCorp stack. Modern trend: Linkerd for simple use cases, Istio for enterprise complex needs, eBPF-based meshes emerging (Cilium) for even less overhead.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (228, 'Explain how mutual TLS (mTLS) works in a service mesh. What are the benefits over API keys or shared secrets?',
     'mTLS: both client and server authenticate via certificates, encrypted connection, identity verification. Service mesh mTLS: (1) Control plane acts as CA, issues certificates to each workload identity, (2) Sidecar proxy presents certificate, verifies peer certificate, (3) Automatic rotation (short-lived certs). Example: Service A calls Service B → A''s sidecar presents cert → B''s sidecar validates cert against CA → establishes mTLS connection. Benefits over API keys: (1) No secret distribution - certs issued automatically to running pods. (2) Strong cryptographic identity - can''t be stolen/shared easily. (3) Automatic rotation - short TTL (hours/days), no manual renewal. (4) Encryption in transit - built in, not separate concern. (5) Fine-grained authorization - identity-based policies (Service A can only call endpoints X, Y). (6) Audit - exactly which service (identity) made request. API keys problems: static secrets, manual distribution, rotation pain, often shared, easily leaked. mTLS challenges: Certificate management complexity (service mesh abstracts this), clock skew can cause validation failures, debugging harder (encrypted). Implementation: Istio/Linkerd handle automatically, SPIFFE/SPIRE for identity standards, cert rotation transparent to apps.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (229, 'How does traffic splitting for canary deployments work in a service mesh? Explain request routing and metrics-based rollback.',
     'Canary deployment: gradually shift traffic from stable to new version while monitoring. Service mesh implementation: (1) Deploy new version alongside old (both running). (2) Configure traffic split via mesh (90% → v1, 10% → v2). (3) Monitor metrics (error rate, latency, custom business metrics). (4) Gradually increase (50/50, then 80/20, then 100% v2). (5) Rollback if issues (change routing back to v1). Routing mechanisms: Header-based (test users get v2), percentage (random 10%), geo/region. Metrics collection: Service mesh auto-collects per-version metrics (request rate, error rate, latency percentiles). Advanced: automated rollback - if v2 error rate > threshold, auto-route back to v1 (Flagger, Argo Rollouts). Benefits vs traditional: no load balancer changes, per-request granularity (not instance replacement), instant rollback (routing change, not redeployment), works with any deployment (K8s, VMs). Challenges: database schema compatibility (both versions access same DB), state synchronization, cost (both versions running), long-running connections (stick to one version). Best practice: start small (1%), monitor closely, automate rollback, have explicit success criteria.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (230, 'You''re considering adopting a service mesh for your 50-microservice architecture but are concerned about complexity, performance overhead, and operational burden. Discuss the trade-offs. How would you evaluate whether your organization is ready? What incremental adoption strategy would minimize risk?',
     'Service mesh trade-offs analyzed: Benefits: Uniform observability (traces/metrics for all services language-agnostic), automated mTLS (security without app changes), traffic control (canaries, retries, circuit breaking without code), centralized policy (consistent across services). Costs: Complexity (another system to learn/maintain), performance overhead (proxy hop adds latency ~1-5ms, resource consumption for sidecars), operational burden (manage control plane, upgrade sidecars, debug networking), debugging difficulty (extra layer of abstraction). Readiness evaluation criteria: Service count (> 10-20 services benefit more), polyglot environment (mesh removes need for per-language libraries), observability gaps (hard to trace issues), security requirements (mTLS needed), traffic management needs (canaries, A/B tests), team maturity (can handle complexity?), existing pain points (would mesh solve them?). Red flags for not ready: Small number of services (<5), monolith-first (add complexity without benefit), team already overwhelmed, no platform engineering team, unclear requirements. Incremental adoption strategy: Phase 1 - Observability only: Deploy service mesh in "metrics only" mode (no mTLS,no routing changes),validate telemetry useful, build confidence. Phase 2 - Non-critical services: Pick 2-3 low-traffic internal services, enable full mesh features, learn operational patterns, develop runbooks. Phase 3 - mTLS rollout: Enable mTLS for service-to-service communication, monitor for certificate issues, validate encryption working. Phase 4 - Traffic management: Use canary deployments on select services, validate automated rollback, train teams. Phase 5 - Expand gradually: Add more services over months, mandatory for new services, migrate legacy on timeline. Risk mitigation: Parallel testing (mesh and non-mesh services coexist), easy opt-out (remove sidecar annotation), dedicated platform team ownership, extensive monitoring of mesh itself, regular chaos testing, alternative exit strategy costs (what if we need to remove it?). Success metrics: Mean time to detect issues (improved?), deployment confidence/frequency, security posture, cross-team consistency. Decision framework: if observability+security+traffic needs > complexity+overhead costs → adopt. Otherwise, wait or use simpler alternatives (ingress controller, separate monitoring tools).',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),


    -- Topic 47: GitOps (5 questions)
    (231, 'What is GitOps? How does it differ from traditional CI/CD?',
     'GitOps: operational model where Git is single source of truth for infrastructure and application config, changes made via Git commits, automated agents sync desired state to clusters. Core principles: (1) Declarative - everything described declaratively (K8s YAML, Terraform). (2) Versioned - Git history is audit trail. (3) Immutable - changes via new commits, not manual edits. (4) Pulled - agents in cluster pull changes from Git. (5) Reconciliation - continuous sync to match Git state. Traditional CI/CD: Push-based (CI system pushes to production), often imperative scripts, credentials in CI system. GitOps: Pull-based (cluster agent pulls from Git), declarative configs, credentials stay in cluster. Example workflow: Developer commits deployment YAML to Git → ArgoCD/Flux detects change → applies to cluster → cluster matches Git state. Benefits: audit trail (Git log), easy rollback (git revert), disaster recovery (rebuild from Git), security (no external push access needed), collaboration (PRs for changes). Tools: Flux, ArgoCD, Jenkins X. Use cases: Kubernetes deployments, infrastructure as code, multi-cluster management.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (232, 'Compare GitOps tools: ArgoCD vs Flux. What are the key differences?',
     'ArgoCD: CNCF graduated, rich UI, multi-cluster first-class, app-centric. Features: web UI, SSO, RBAC, ApplicationSet for multi-cluster, sync waves, hooks, health assessment. Pros: excellent UX, powerful visualization, built-in RBAC, active community. Cons: more complex, heavier weight. Flux: CNCF graduated, GitOps Toolkit (modular), lightweight, CLI-first. Features: Helm+Kustomize support, notification system, image automation, multi-tenancy, progressive delivery (Flagger). Pros: lightweight, composable, integrates with existing tools, notification-driven. Cons: no built-in UI, CLI-heavy. Key differences: UI (Argo has excellent UI, Flux CLI-first but UI exists via Weave GitOps), multi-cluster (Argo central control plane, Flux distributed per-cluster), architecture (Argo monolithic, Flux modular toolkit), opinionated (Argo opinionated, Flux flexible). Choose ArgoCD for: teams want UI, centralized multi-cluster management, Application abstraction useful. Choose Flux for: lightweight preference, existing CD needs, notification integrations, flexibility. Both: excellent Helm/Kustomize support, multi-tenancy, good documentation. Trend: Argo popular for ease-of-use, Flux for flexibility, some using both (Argo UI + Flux backend).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (233, 'Explain pull-based vs push-based deployment models. What are the security implications of each?',
     'Push-based (traditional CI/CD): CI system pushes changes to production. Flow: Git commit → CI builds → CI authenticates to cluster → CI deploys. Examples: Jenkins, GitHub Actions, GitLab CI pushing to K8s. Security concerns: (1) CI needs cluster credentials (high-value target). (2) Credentials stored in CI (secrets sprawl). (3) External access to cluster required (firewall holes). (4) Who can trigger CI can deploy (broad access). (5) Audit trail in CI logs (separate from cluster). Pull-based (GitOps): Agent in cluster pulls changes from Git. Flow: Git commit → Agent polls Git → Agent applies to cluster. Examples: ArgoCD, Flux. Security benefits: (1) No cluster credentials outside cluster (nothing to steal). (2) Only outbound connections from cluster (no firewall ingress). (3) Git is gate - RBAC on Git repo controls deployments. (4) Audit in Git commits (perfect trail). (5) Principle of least privilege - agent only needs cluster access it already has. Attack scenarios: Push-based: compromise CI → deploy malicious code. Pull-based: compromise Git repo → malicious deployed (but Git audit + protected branches mitigate), compromise agent (but inside cluster already). Best practice: GitOps pull for production, push-based for preview environments (acceptable risk). Hybrid: CI builds images/charts, GitOps deploys them.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (234, 'How do you handle secrets in GitOps when your config is stored in Git? Discuss different approaches.',
     'Problem: GitOps requires config in Git, but can''t store secrets in Git plaintext. Solutions: (1) Sealed Secrets (Bitnami): encrypt secrets with cluster public key, commit encrypted to Git, controller in cluster decrypts with private key. Pros: simple, encrypted at rest in Git. Cons: rotation requires re-encryption, tight coupling to cluster. (2) SOPS (Mozilla): encrypt YAML files with age/PGP/cloud KMS, commit encrypted, FluxCD decrypts on apply. Pros: multiple encryption backends, granular (encrypt values not keys). Cons: key management, decryption key needed in cluster. (3) External Secrets Operator: define secret as pointer to external secret manager (Vault, AWS Secrets Manager), controller fetches at runtime, injects into cluster. Pros: secrets never in Git, central management, rotation easy. Cons: dependency on external system, more complex. (4) Git-crypt: encrypt entire repo or paths. Pros: transparent. Cons: coarse-grained, key distribution. Best practices: prefer External Secrets Operator (separates concerns, enterprise-grade), use Sealed Secrets for simplicity, never commit plaintext, audit Git access carefully, automate secret rotation, encrypt backups. Anti-pattern: Git submodules for secrets (still in Git somewhere), assuming private repo is secure (insider threat, accidental public).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (235, 'Your team practices GitOps but developers are frustrated by slow deployment times - it takes 5 minutes from Git commit to deployment in the cluster. Your GitOps agent polls Git every 2 minutes and has a 3-minute reconciliation time. How do you reduce this delay? What are the trade-offs between polling interval, webhook triggers, and reconciliation performance?',
     'Current bottleneck analysis: 2-minute poll interval + 3-minute reconciliation = 5 minutes minimum (worst case 7min if commit just after poll). Developer impact: slow feedback loop, context switching, reduced productivity, avoiding small iterative changes. Solutions evaluated: (1) Reduce poll interval (2min → 30sec): Pros: faster detection. Cons: increased API calls to Git, higher load, still polling delay. Improvement: 30sec-3.5min (better). (2) Webhook triggers (Git notifies agent immediately): Pros: instant detection, efficient. Cons: need ingress to cluster (security concern for production), firewall complexity, webhook reliability. Improvement: 0-3min detection. (3) Optimize reconciliation (3min → 1min): parallel resource apply, reduce health check timeouts, more efficient diffing. Pros: direct time savings. Cons: requires code changes, careful testing to not break reliability. Improvement: -2min. (4) Progressive sync (apply CRDs first → Deployments → wait for health): prevents cascading retries. (5) Lazy sync (only changed resources): reduces work. Combined approach recommendation: Production: Webhook for instant notification + keep 1min polling as fallback + optimize reconciliation to ~1min = worst case 2min. Staging/Dev: aggressive polling (15sec) + fast reconciliation (skip some health checks) = 30sec deployment. Trade-offs considered: Speed vs reliability (faster reconciliation might skip important validations), security (webhooks open ingress), load (frequent polling costs API rate limits), complexity (webhook setup and monitoring). Edge case handling: Webhook failures (polling catches eventually), concurrent commits (queue them), large changesets (may take longer inherently), cluster under load (reconciliation slower). Additional improvements: Image pull optimization (cache registry locally), parallel multi-cluster sync, progressive delivery (start sync during build), local dev environments (Tilt,Skaffold for instant local feedback). Avoid: removing health checks just for speed (reliably wrong is worse), so-frequent polling it causes issues, skipping Git for "urgent" changes (breaks GitOps model). Success metrics: P50/P95/P99 commit-to-deploy time, false positive deploy failures, developer satisfaction.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 48: Disaster Recovery (5 questions)
    (236, 'Define RTO and RPO. How do they drive disaster recovery planning?',
     'RTO (Recovery Time Objective): maximum acceptable downtime, how long can business tolerate being down. Example: RTO 4 hours means must restore within 4 hours of disaster. RPO (Recovery Point Objective): maximum acceptable data loss, how old can recovered data be. Example: RPO 1 hour means can lose up to last hour of data. Business drives technical decisions: E-commerce RTO 5min/RPO 0 (immediate failover, synchronous replication). Internal tools RTO 24hr/RPO 4hr (daily backups acceptable). RTO determines: infrastructure redundancy (hot standby vs cold backup), automation level (automatic failover vs manual), geographic distribution, cost. RPO determines: backup frequency (continuous, hourly, daily), replication model (synchronous, asynchronous), retention policy. Relationship: stricter requirements = higher cost. RTO 0 requires active-active multi-region, RPO 0 requires synchronous replication. Disaster recovery tiers: Tier 0 (RTO/RPO near-zero): mission-critical, multi-region active-active, synchronous. Tier 1 (RTO hours/RPO minutes): hot standby, async replication. Tier 2 (RTO day/RPO hours): warm standby, backup/restore. Tier 3 (RTO weeks/RPO days): cold backup, manual rebuild. Planning process: (1) business defines acceptable RTO/RPO per system, (2) technical designs solution to meet SLA, (3) cost-benefit analysis, (4) regular testing to validate.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (237, 'Describe hot, warm, and cold disaster recovery strategies. When would you use each?',
     'Cold standby: backups stored, infrastructure not running, manual recovery. Process: disaster → provision infrastructure → restore from backup → reconfigure → test → resume. RTO: days-weeks, RPO: hours-days. Cost: low (storage only). Use for: non-critical systems, cost-sensitive, rare access. Example: archive data, internal reports. Warm standby: infrastructure running minimal capacity, ready to scale up, data replicated with lag. Process: disaster → scale up capacity → switch DNS/traffic → validate. RTO: hours-days, RPO: minutes-hours. Cost: medium (pay for minimal infra). Use for: balance between cost and recovery, business can tolerate hours down. Example: corporate applications, moderate traffic sites. Hot standby (active-passive): full capacity running idle in DR site, near real-time replication, automatic/fast failover. Process: disaster → failover traffic (DNS/load balancer). RTO: minutes-hours, RPO: seconds-minutes. Cost: high (duplicate infrastructure idle). Use for: critical systems, low tolerance, regulatory requirements. Example: financial systems, healthcare. Active-Active (no standby): traffic served from multiple regions simultaneously, seamless failover. RTO: near-zero (automatic), RPO: near-zero (synchronous replication). Cost: highest (full duplicate + complexity). Use for: mission-critical, global users, zero tolerance. Example: Netflix, payment processing. Hybrid: tier systems by criticality - hot for critical, warm for important, cold for archive.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (238, 'What is a disaster recovery drill/test? Why is it important? How often should you run them?',
     'DR drill: simulated disaster to test recovery procedures, validate RTO/RPO achievable, train team. Importance: (1) Backups might be corrupt (discover before real disaster). (2) Procedures outdated (infrastructure changed). (3) Team unfamiliar (who does what?). (4) Assumptions wrong (takes longer than expected). (5) Dependencies unknown (missing configs, credentials). Real story: many companies discover backup failures during disasters, not drills. Types of drills: (1) Tabletop: team walks through procedures, no actual recovery, quick. (2) Parallel test: restore to separate environment, verify functionality, no production impact. (3) Full failover: actual switch to DR site, real traffic, highest confidence but risky. (4) Partial: test components in isolation (database restore, network failover). Frequency: Critical systems (RTO < 1hr): quarterly minimum. Important systems: semi-annual. Less critical: annual. After major changes (migration, architecture update): immediately. Best practices: scheduled AND unplanned drills (test readiness), document outcomes, track time, identify gaps, update runbooks, make drill process easy (frequent practice), automate where possible, executive sponsorship (needs time/resources). Metrics: actual RTO/RPO achieved vs target, number of issues found, mean time to detect failover needed, team confidence level. Common failures discovered: database restore missing transaction logs, DNS still pointing to failed region, credentials not replicated, monitoring not set up in DR, insufficient capacity in DR region.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (239, 'How do you handle database disaster recovery? Compare backup/restore, replication, and distributed databases.',
     'Strategy comparison: (1) Backup/Restore: periodic backups to S3/object storage, restore to new instance. RTO: hours (provision + restore), RPO: backup frequency (hours). Pros: simple, cheap, works for any DB. Cons: slow, data loss, downtime. Use for: acceptable hours downtime. (2) Asynchronous replication: continuous copy to standby (read replica), promote on failure. RTO: minutes (promotion + validation), RPO: seconds-minutes (replication lag). Pros: faster than backup, standby can serve reads. Cons: replication lag (data loss), split-brain risk, manual failover complexity. Use for: RTO < 1hr, acceptable small data loss. Example: PostgreSQL streaming replication, MySQL async replication. (3) Synchronous replication: transaction committed to both primary and standby. RTO: minutes (failover), RPO: zero (no data loss). Pros: no data loss, strong consistency. Cons: latency (cross-region), availability impact (if standby down). Use for: zero data loss acceptable latency. Example: PostgreSQL synchronous replication, SQL Server Always On. (4) Distributed databases: data replicated across regions inherently, automatic failover. RTO: seconds (automatic), RPO: zero. Pros: resilient by design, automatic, global distribution. Cons: complex, eventual consistency trade-offs, cost. Example: CockroachDB, Cassandra, DynamoDB Global Tables. Backup best practices: automated daily, test restores monthly, multiple retention policies, offsite storage, encrypted. Replication: monitor lag, test failover, automate where possible. Additional: write-ahead logs for point-in-time recovery, active-active for zero downtime (complex).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (240, 'A major cloud region outage has taken down your primary region. Walk through your disaster recovery response from detection to full recovery. What challenges might you encounter during actual failover that don''t appear in tests? How do you balance speed vs correctness when your business is losing money every minute?',
     'DR incident response phases: Phase 1 - Detection and Declaration (0-15min): Automated monitoring alerts (multi-region health checks), incident commander appointed, assess scope (full region vs specific services), declare disaster (authorized person), communicate to stakeholders (customers, executives, teams). Challenges: false positive determination (regional issue vs infra issue), communication delays (waiting for certainty vs acting fast), unclear ownership (who declares disaster?). Phase 2 - Initial Failover (15-45min): Activate runbook/automation, DNS cutover to DR region (change TTL beforehand, note propagation delay), database failover (promote read replica or switch connection string), validate connectivity to dependencies (external APIs, third-party services), smoke test critical paths (can user login? checkout? search?). Challenges manifested: DNS caching (users still hitting dead region for minutes), stale connection pools (apps cached old DB endpoint), certificate mismatches (forgot to provision SSL cert in DR), insufficient capacity (autoscaling not warmed up), API rate limits (third parties block sudden new-IP traffic), secrets/configs not replicated (app crashes on startup), cold caches (everything slow without cache warmth). Phase 3 - Validation and Monitoring (45min-2hr): Load testing (can DR handle full production load?), validate data consistency (is replicated data current?), enable full monitoring (metrics, logs, traces in DR), customer communications (status page, emails), escalation paths ready. Hidden challenges: Database replication lag (how far behind?), in-flight transactions lost (customer submitted order that disappeared), data corruption (replication bug surfaced under load), cascading failures (one team''s failover breaks dependencies), monitoring itself in failed region (blind spots). Phase 4 - Full recovery and stabilization (2hr+): Capacity scaling (add more instances), debugging new issues (unique to DR), parallel investigation of primary region (when to fail back?), runbook updates (what did we learn?). Speed vs correctness trade-offs: Pressure to rush (executives asking ETA, customers complaining, revenue lost), risks of rushing (failed failover worse than waiting, data corruption permanent, incomplete validation breaks more things). Decision framework: Tier 0 (payment, auth): automated failover, pre-validated, high confidence → fast. Tier 1 (core features): semi-automated, validation checks → balanced. Tier 2 (nice-to-have): can wait for careful validation → correctness. Practical mitigations: Pre-authorized failover for critical systems (commander doesn''t wait for approval), automated validation (health checks return green/red instantly), phased cutover (1% traffic → validate → 100%), ability to quickly rollback (keep primary configuration ready), dedicated war room (all teams coordinated), practice under pressure (chaos days). Challenges unique to real disasters vs drills: Stress/fatigue (people make mistakes), concurrent fires (multiple teams need same resources), external dependencies failing too (their DR might be same region), unexpected bugs (code paths never exercised), organizational pressures (customers, media, lawsuits), prolonged outage (region down for days not hours). Post-incident: Blameless postmortem (what went wrong?), runbook updates (gaps found), architecture improvements (what made it fragile?), drill updates (test failure modes we found). Success criteria: RTO met (business acceptable), no data loss beyond RPO, customer trust maintained, team learned and improved.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 49: Load Balancing (5 questions)
    (241, 'Explain Layer 4 vs Layer 7 load balancing. What are the trade-offs?',
     'Layer 4 (Transport - TCP/UDP): load balancer decides based on network information (IP, port). Operates at connection level, forwards packets. Example: client connects to LB:80 → LB picks backend server → pure TCP proxy. Pros: fast (no application parsing), protocol-agnostic (works with any TCP/UDP), low latency, high throughput, simple. Cons: no content-based routing (can''t route /api to different backend than /web), no HTTP features, sticky sessions harder. Use cases: non-HTTP protocols (databases, custom TCP), ultra-high performance needed, simple round-robin sufficient. Tools: HAProxy (TCP mode), NLB (AWS), nginx stream module. Layer 7 (Application - HTTP): load balancer parses application protocol, makes decisions based on content (URL, headers, cookies). Example: request to /api/users → LB routes to API servers, /static → CDN. Pros: intelligent routing (URL-based, header-based), HTTP features (compression, SSL termination, caching), better health checks (HTTP 200 vs TCP connect), sticky sessions via cookies, can modify requests/responses. Cons: slower (must parse HTTP), CPU-intensive (TLS termination), HTTP-only. Use cases: web applications, microservices routing, need content-based routing, API gateway. Tools: HAProxy (HTTP mode), ALB (AWS), nginx, Envoy. Trade-offs: performance vs features, L4 when speed critical, L7 when routing logic needed. Hybrid: L7 at edge (routing), L4 within backend (performance).',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (242, 'Compare load balancing algorithms: round-robin, least connections, least response time, consistent hashing. When would you use each?',
     'Round-robin: sequential distribution, request 1 → server A, request 2 → server B, repeat. Pros: simple, fair distribution, good for homogeneous backends. Cons: ignores load, unhealthy servers, connection length. Use when: backend servers identical, short-lived requests (HTTP), stateless. Least connections: route to server with fewest active connections. Pros: balances load better, handles long-lived connections. Cons: doesn''t account for connection cost (some heavy, some light). Use when: variable request duration (websockets, long polling), heterogeneous backends. Least response time (weighted): route to server with fastest recent response + fewest connections. Pros: adapts to performance, routes to healthier servers. Cons: complex, can oscillate (everyone switches to fast-server, it becomes slow). Use when: backend performance varies, need automatic adaptation. Weighted round-robin: servers get weight (powerful server weight 3, weak weight 1). Pros: handles heterogeneous capacity. Cons: static weights (manually configured). Use when: known capacity differences, manual tuning acceptable. Consistent hashing: hash request property (user ID, session) to server ring. Pros: sticky (same user always gets same server), minimal remapping when servers added/removed. Cons: can be uneven, complex. Use when: need session affinity, caching (requests to same server for cache hits), distributed systems (sharding). IP hash: hash client IP to backend. Pros: sticky sessions without cookies. Cons: uneven if clients behind NAT, doesn''t rebalance. Modern: combination algorithms, machine learning-based routing.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (243, 'What is SSL/TLS termination? Should you terminate SSL at the load balancer or at the backend servers?',
     'SSL/TLS termination: decrypt HTTPS at load balancer, send plain HTTP to backends (or re-encrypt). Terminate at LB: Client HTTPS to LB → LB decrypts → LB sends HTTP to backend. Pros: (1) Offload CPU from backends (encryption expensive). (2) Single certificate management point (don''t distribute certs to all backends). (3) LB can inspect/route based on content (can''t with encrypted). (4) Better health checks (see HTTP). (5) Easier debugging (see plaintext requests). Cons: (1) Unencrypted traffic in private network (internal attacker risk). (2) Compliance issues (some regulations require end-to-end). (3) Single point with cert access (LB compromise leaks cert). End-to-end encryption: Client HTTPS to LB → LB re-encrypts → Backend HTTPS. Pros: security (encrypted in-transit everywhere), compliance, defense-in-depth. Cons: CPU overhead (double encryption), certificate management on every backend, harder debugging, LB can''t inspect content deeply. Passthrough: LB doesn''t decrypt, pure TCP proxy. Pros: maximum security, LB doesn''t need cert. Cons: no L7 features, can''t route on content. Best practice: Terminate at LB for most workloads (acceptable risk in private network), end-to-end for: highly sensitive (healthcare, finance), compliance requirements (PCI-DSS), zero-trust architecture. Hybrid: terminate at LB, use network encryption (IPsec, WireGuard) for the private network. Modern: service mesh handles backend encryption (mTLS) automatically, LB terminates client-facing.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (244, 'How do you handle session affinity (sticky sessions) in a load-balanced environment? What are the trade-offs?',
     'Session affinity: ensure user requests always go to same backend server. Methods: (1) Cookie-based: LB sets cookie with server identifier, routes based on cookie. Pros: reliable, survives client IP changes. Cons: requires L7 LB, cookie overhead. (2) IP hash: hash client IP to backend. Pros: simple, works at L4. Cons: clients behind NAT go to same server (load imbalance), mobile users change IPs. (3) Session ID in URL: embed server identifier in URL. Pros: works without cookies. Cons: ugly URLs, security concern. Trade-offs analyzed: Pros of sticky sessions: stateful apps work (shopping cart in memory), cache hits (user data cached on their server), simpler app (no shared state). Cons: uneven load (popular user overloads one server), server failure loses sessions (bad UX), harder scaling (can''t just add servers), locked-in architecture (can''t easily migrate). Better alternatives: (1) Shared session store: Redis, Memcached - any server can handle any request. Pros: resilient, load-balanced, scalable. Cons: network hop, complexity. (2) Stateless sessions: JWT tokens, client holds state. Pros: truly stateless, infinitely scalable. Cons: security considerations, token size. (3) Database-backed Sessions: session data in DB. Pros: persistent, simple. Cons: DB load, slower. Modern recommendation: avoid sticky sessions, design stateless, use shared session store if state needed. Exceptions: WebSocket/long-lived connections (inherently sticky), legacy apps (can''t refactor).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (245, 'Your application is experiencing uneven load distribution - one backend server consistently receives 3x more traffic than others despite using round-robin load balancing. What could cause this? How would you diagnose and fix it? Discuss both client-side and server-side load balancing considerations.',
     'Symptoms investigation: Uneven load despite round-robin suggests sticky sessions, client behavior, or L4/L7 confusion. Potential causes enumerated: (1) Long-lived connections: HTTP keep-alive or WebSockets - first connection round-robined, then all requests on that connection go to same server. Load looks even by connection count but uneven by request count. (2) Client-side load balancing: some clients (mobile apps, thick clients) cache server address, keeping hitting same one. (3) DNS caching: round-robin DNS but one IP cached heavily. (4) Sticky sessions enabled accidentally: cookie or IP hash turned on. (5) Health checks interfering: one server marked degraded, getting less traffic. (6) Backend differences: one server faster so handles more (if using least-response-time, this is intended). (7) Uneven connection termination: some servers not closing connections properly. (8) Proxy layers: intermediate proxy doing its own load balancing. Diagnostic steps: (1) Check LB metrics: connections per backend, requests per backend, active connections, request distribution - validate round-robin working at LB level. (2) Check backend metrics: CPU, memory, request rate, connection count - identify if overloaded server or just serving more. (3) Inspect protocol: HTTP/1.1 keep-alive vs HTTP/2 multiplexing vs WebSocket. (4) Check configurations: sticky session settings, health check status, weights/priorities. (5) Client analysis: where requests coming from (IPs, user-agents), connection duration patterns. (6) Network tracing: tcpdump to see actual distribution patterns. Solutions mapped to causes: Long-lived connections: (a) If HTTP/1.1 keep-alive: reduce keep-alive timeout, connection max requests before close, client-side connection cycling. (b) If HTTP/2: connection pooling inefficiency (open multiple connections to LB). (c) If WebSocket: inherently sticky, ensure proper distribution on new connections, maybe session draining when scaling. Client-side LB: force client to re-resolve DNS, implement jitter in client retry logic, use service mesh sidecar (eliminates client LB logic). DNS caching: lower TTL (but more DNS queries), use LB IP not round-robin DNS. Sticky sessions: review configuration, disable if not needed, if needed ensure it''s the cause not symptom. Server-side vs client-side LB considerations: Server-side (traditional LB): centralized, client connects to LB IP, LB distributes. Pro: simple client, LB has full view. Con: single point of failure, latency hop, cost. Client-side (service mesh, gRPC, etc.): client library does load balancing, discovers backends (DNS, service discovery), picks one. Pro: no hop, faster, resilient. Con: complex client, need backend discovery, inconsistent behavior across clients. Diagnosis differs: Server-side LB: check LB metrics directly - if LB shows even distribution but backends uneven, problem is connection length/reuse. Client-side LB: check client-side metrics and backend discovery logs - if clients caching stale backend list or imbalanced endpoint distribution. Advanced techniques: (1) Connection draining: gracefully close connections to over-loaded server, force redistribution. (2) Active health checks: synthetic traffic to validate even distribution. (3) Load-based routing: integrate backend metrics into LB decision (if using algo that supports it). (4) Rate limiting per backend: prevent runaway load. (5) Auto-scaling: if one server truly overloaded, scale backends (though doesn''t fix distribution issue). Testing the fix: Send controlled traffic (load testing tool), measure distribution (should be ±5%), test under various scenarios (short requests, long connections, mixed), monitor over time (ensure doesn''t regress). When perfect distribution isn''t necessary: If backends have capacity and not actually impacted, slight unevenness acceptable. Focus on: (1) No backend overloaded, (2) Overall system healthy, (3) Good user experience.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 50: DevOps Security and Compliance (5 questions)
    (246, 'What is shift-left security? How do you integrate security into the DevOps pipeline?',
     'Shift-left security: move security earlier in development lifecycle (left side of timeline), find vulnerabilities before production. Traditional: development → deploy → security audit (late, expensive to fix). Shift-left: security integrated throughout. Integration points: (1) IDE/pre-commit: linters for secrets (git-secrets), SAST plugins warn developers locally. (2) Code commit: pre-commit hooks, reject commits with secrets/bad patterns. (3) CI pipeline: SAST (static analysis - SonarQube, Semgrep), dependency scanning (Snyk, Dependabot), container scanning (Trivy, Grype), IaC scanning (Checkov, tfsec), license compliance. (4) Build: sign artifacts, generate SBOM (Software Bill of Materials). (5) Deploy: DAST (dynamic testing in staging), pen testing, runtime protection. (6) Production: runtime security (Falco), WAF, monitoring. Benefits: find bugs early (cheaper to fix), faster feedback loop (developers fix while context fresh), reduce risk (fewer vulnerabilities reach production), compliance (audit trail). Cultural aspects: security as code, shared responsibility (not just security team), automated policy enforcement, security champions in teams. Challenges: tool fatigue (too many scanners), false positives (noise), slow CI (balance thoroughness vs speed), developer resistance (seen as blocker). Best practice: start small (pick one tool), tune to reduce noise, educate developers, make security enabler not blocker.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (247, 'Explain the concept of immutable infrastructure from a security perspective. How does it improve security?',
     'Immutable infrastructure: servers/containers never modified after deployment, changes via new deployment of updated image. Security benefits: (1) No configuration drift - can''t be manually compromised/misconfigured, always matches known good state, easy to detect anomalies. (2) Reduced attack surface - no SSH/remote access needed (can''t login to change), no package managers (can''t install malware), minimal attack vectors. (3) Intrusion detection - any runtime modification is suspicious (file changes, new processes - definitely malicious), easier to detect breaches. (4) Instant remediation - compromised instance? Terminate and redeploy, no need to forensically clean, back to known good state. (5) Auditability - exactly what''s running (built from specific Git commit + Dockerfile), reproducible builds (same input = same output), full change history. (6) Patch management - update base image, redeploy all instances, no complex patch rollout. Implementation: Golden images (Packer), containers (Docker), immutable deployments (K8s). Challenges: stateful data (databases, uploads - still need mutable storage), logging (must ship logs externally before termination), initial setup more complex, mental model shift for teams. Comparison to mutable: Mutable - patch live server, SSH access, configuration management. Risk: persistence not known, backdoors harder to detect, drift accumulates. Immutable - replace, no access, declarative config. Trade-off: requires more automation, but much better security posture. Modern cloud-native architecture is inherently immutable.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (248, 'How do you implement least privilege access in a DevOps environment where developers need to move fast but security needs to be maintained?',
     'Tension: developers want access to debug/deploy, security wants minimal permissions. Balance via automation + temporary access. Principles: (1) Default deny - no one has production access by default, require justification. (2) Just-in-time access - temporary elevated permissions when needed, auto-expire. (3) Just-enough access - scope to specific resource/action, not broad admin. (4) Automation - actions via pipelines not manual (pipeline has permissions, humans don''t). Implementation strategies: Production access: (1) Break-glass process - request production access with justification, auto-approved for certain roles, time-limited (4 hours), audited, revoked automatically. Tools: AWS SSM Session Manager (temporary sessions), Teleport (audit SSH), (2) Read-only by default - developers get read access (view logs, metrics), write access only via approved tools. (3) Debugging via observability - good logging/tracing reduces need to access servers, distributed tracing, log aggregation. Deploy access: (1) Deploy via CI/CD - pipeline has deploy permission (OIDC token), developers trigger via Git commit, no direct kubectl/helm access. (2) Namespaced access - K8s RBAC per team, can deploy to their namespace, not others. Infrastructure changes: (1) Infrastructure as Code - changes via Terraform/PR, automated apply after approval, no console access. (2) Policy as code - OPA, Sentinel validate changes meet policy before apply. Secret access: (1) Application identity - apps get secrets via workload identity (IAM role, K8s service account), developers don''t have access. (2) Break-glass for incidents - emergency secret access granted, heavily audited. Role-based access: Define roles (developer, SRE, security, auditor), principle of least privilege per role, periodic access reviews (remove unused permissions). Challenges: friction (developers complain it''s slow), emergencies (need quick access for outages), balancing productivity. Solutions: Automate common tasks (self-service), fast break-glass (seconds not hours), measure impact (did security improve? did velocity decrease?).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (249, 'What is compliance as code? How do you automate compliance checks for regulations like SOC2, PCI-DSS, HIPAA?',
     'Compliance as code: express regulatory requirements as executable policies, automated validation in CI/CD, continuous compliance vs point-in-time audits. Example: SOC2 requirement "encryption at rest" → policy: all S3 buckets must have encryption enabled → automated check in Terraform apply. Components: (1) Policy definition - codify requirements (OPA Rego, Sentinel, Python). (2) Automated scanning - check infrastructure/code against policies (pre-deploy and runtime). (3) Evidence generation - automated reports for auditors. (4) Remediation - auto-fix violations or block non-compliant changes. Regulatory examples: SOC2 (security controls): automate checks for MFA enabled, log retention, encryption, access reviews, vulnerability scanning. PCI-DSS (payment card data): network segmentation verified (terraform validate cardholder environment isolated), encryption in transit/rest, no hardcoded secrets, patch levels. HIPAA (healthcare): data encryption, access control to ePHI, audit logs enabled, backup retention. Tools: (1) Cloud compliance - AWS Config Rules, Azure Policy, GCP Policy Intelligence (check cloud resources). (2) IaC scanning - Checkov, tfsec, Sentinel (validate Terraform before deploy). (3) Policy engines - Open Policy Agent (OPA), Kyverno (K8s policies), HashiCorp Sentinel. (4) Compliance platforms - Vanta, Drata, Secureframe (automate evidence collection). Workflow: (1) Map requirements to technical controls (regulation says "encrypt data" → control: S3 default encryption). (2) Write policy (code that checks control). (3) Integrate in pipeline (terraform plan fails if non-compliant). (4) Runtime monitoring (alert if prod becomes non-compliant). (5) Generate reports (for auditors, show continuous compliance). Benefits: shift compliance left (catch before production), reduce manual effort (audits faster), continuous vs annual, reduced risk. Challenges: complex regulations (legal interpretation needed), false positives (tune policies), keeping policies updated, not all controls automatable (human processes).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (250, 'Your company needs to achieve SOC2 Type 2 compliance within 6 months, but your infrastructure has grown organically with minimal security controls - no centralized logging, inconsistent MFA adoption, manual access provisioning, secrets in code repositories. Design a compliance roadmap. How do you prioritize efforts? What quick wins can you achieve vs long-term changes? How do you balance compliance work with feature development?',
     'SOC2 Type 2 requirements understanding: Must demonstrate security controls operating effectively over time (minimum 3-6 months). Five trust principles: Security (foundational, always required), Availability, Processing Integrity, Confidentiality, Privacy (select based on business). Common criteria: access controls, encryption, monitoring, change management, incident response, vendor management, risk assessment. Current state assessment (Month 0): (1) Inventory systems and data - what processes data, where is sensitive data, classify by criticality. (2) Gap analysis - compare current state vs SOC2 requirements, identify gaps by severity. (3) Risk assessment - which gaps pose highest risk. Findings from scenario: Critical gaps: secrets in Git (immediate breach risk), no centralized logging (can''t prove controls), inconsistent MFA (unauthorized access risk), manual access (no audit trail). Prioritization framework: (1) Evidence-generating controls first (need 3-6 months of evidence) - logging, access controls, change management. (2) Critical security gaps (prevent breaches during audit period). (3) High visibility, low effort (quick wins for momentum). (4) Complex projects start early (need time to complete). Roadmap structured: Month 1 (Quick Wins & Foundation): (1) Centralized logging - implement log aggregation (ELK, Splunk, cloud-native), enable audit logs (AWS CloudTrail, K8s audit, application logs), define retention policy (align with SOC2 - typically 1 year). Quick win, generates evidence immediately. (2) Secrets remediation emergency - scan Git history for secrets (tools: gitleaks, truffleHog), rotate all found secrets immediately, implement secrets manager (Vault, cloud secret managers), pre-commit hooks to prevent future commits. Critical for security. (3) Enforce MFA - MFA required for all SaaS (Google Workspace, GitHub, AWS), document policy, give 2-week deadline, automated compliance checks weekly. Quick, high impact. (4) Document current state - inventory assets, document architecture, start policy docs (these take time to finalize). Month 2-3 (Access Controls & Change Management): (1) Identity Provider (IdP) centralization - implement SSO (Okta, Azure AD, Google), onboard critical apps first, integrate with access review process. Foundation for access control. (2) RBAC implementation - define roles (least privilege), migrate from individual permissions to roles, automated provisioning/deprovisioning (JIT access). (3) Access review process - quarterly access review workflow, tool to track (custom or compliance platform), run first review (likely find over-permissioned accounts). Evidence required. (4) Change management - all infrastructure changes via Git (IaC migration started), require PR approvals for production changes, deployment audit trail. Necessary ongoing evidence. (5) Formalize incident response - incident response plan documented, runbooks for common scenarios, incident tracking system (ticketing), practice tabletop exercise. Often audited. Month 4-5 (Hardening & Automation): (1) Encryption verification - audit encryption at rest (databases, S3, disk encryption), encryption in transit (TLS everywhere), automated checks for compliance. (2) Vulnerability management - implement scanning (container, dependency, infrastructure), SLA for patching (critical within 30 days), track exceptions. (3) Backup & DR - automated backups tested, DR runbooks, actual DR test executed (evidence!). (4) Vendor management - inventory third-party vendors, SOC2 reports from critical vendors, vendor risk assessment process. (5) Security monitoring - SIEM or alerting on suspicious activity, document response procedures. Month 5-6 (Audit Prep & Polish): (1) Compliance platform - consider Vanta, Drata to automate evidence collection, map evidence to SOC2 controls. (2) Policy documentation finalized - Information Security Policy, Access Control Policy, Incident Response, Business Continuity, Acceptable Use, all approved and attested. (3) Control testing - internal audit of controls (do they actually work?), address gaps found. (4) Evidence collection - gather 3-6 months of evidence (access reviews, change logs, security meeting notes, training records, vulnerability scans). (5) Audit readiness - choose auditor, pre-audit call (understand what they''ll need), organize evidence. Balancing with feature development: (1) Dedicated compliance team - one or two engineers full-time, supported by platform/infra teams. (2) Incremental integration - security work in every sprint (not separate track), "security story points" quota. (3) Automation reduces ongoing burden - initial investment high, but automated compliance has low maintenance. (4) Executive sponsorship - recognized business need, compliance is feature (customer requirement, sales blocker without it). (5) communicate trade-offs - transparent about velocity impact, temporary (ramps down after audit). Quick wins highlighted: (1) MFA enforcement (days, huge perception impact). (2) Secrets out of Git (week, eliminates critical risk). (3) Centralized logging (2 weeks setup, evidence starts immediately). (4) Access reviews (first review in month, show process). (5) Policy docs (templates available, customize in weeks). Long-term investments: (1) IaC migration (months, touch all infrastructure). (2) Comprehensive RBAC (design roles, migrate all access). (3) Full automation (compliance as code, continuous). (4) Culture change (security-first mindset, training). Risks to manage: (1) Audit start too early (not enough evidence months). (2) Findings mid-audit (control failures during observation period - document exceptions, remediation). (3) Scope creep (focus on Security trust principle first, expand later). (4) Team burnout (sustained compliance work is draining, celebrate wins, rotate responsibilities). Success metrics: (1) Gap closure tracking (weekly updates). (2) Evidence readiness (% of controls with sufficient evidence). (3) Compliance debt (new violations found vs resolved). (4) Audit outcome (pass with minimal findings).',
     'technical', 'hard', 'organization', 1, 'custom', 7, true);


    -- ============================================================================
    -- DATA ENGINEERING TOPICS (Topics 51-63, Questions 251-315)
    -- ============================================================================

    -- Topic 51: ETL/ELT Pipelines (5 questions)
    (251, 'What is the difference between ETL and ELT? When would you use each approach?',
     'ETL (Extract-Transform-Load): transform data before loading into warehouse. Flow: extract from sources → transform in ETL tool/server → load cleaned data to warehouse. Traditional approach for on-premise data warehouses. Pros: only clean data in warehouse, less storage needed, transforms on dedicated servers. Cons: ETL server bottleneck, expensive transformation compute, slow for large data. ELT (Extract-Load-Transform): load raw data first, transform in warehouse. Flow: extract from sources → load raw to warehouse → transform using SQL/warehouse compute. Modern cloud data warehouse approach. Pros: leverage warehouse power (Snowflake, BigQuery scale), faster ingestion (no transform bottleneck), raw data preserved (can retransform), transform using SQL (accessible to analysts). Cons: more warehouse storage (raw + transformed), warehouse compute costs, data quality issues in raw layer. Use ETL when: limited warehouse capacity, expensive warehouse compute, need real-time transformation, complex transformations beyond SQL. Use ELT when: cloud data warehouse (Snowflake, BigQuery, Redshift), warehouse has compute power, want flexibility to retransform, simple transformations. Modern trend: ELT dominant with cloud warehouses, medallion architecture (bronze raw → silver cleaned → gold aggregated), tools: dbt for transformation, Fivetran for EL.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (252, 'Explain idempotency in data pipelines. Why is it important? How do you design idempotent pipelines?',
     'Idempotency: running pipeline multiple times with same input produces same output, no duplicate data, safe to retry. Example: pipeline runs today for yesterday''s data, if rerun, doesn''t create duplicates. Importance: (1) Safe retries - pipeline fails midway, can rerun without corruption. (2) Backfills - reprocess historical data safely. (3) Debugging - can replay to investigate issues. (4) Eventual consistency - distributed systems need safe retries. Non-idempotent problems: append-only without deduplication creates duplicates, incremental loads without tracking processed records miss or duplicate data. Design patterns: (1) Upsert instead of insert - merge on primary key, update if exists, insert if not. Example: MERGE INTO table USING source ON key. (2) Delete and insert - delete existing data for partition, insert new data. Example: DELETE WHERE date=''2024-01-01''; INSERT. (3) Partition overwrite - atomic replace of partition. (4) Watermarking - track last processed timestamp/offset, replay from watermark. (5) Unique constraints - database enforces no duplicates, retry fails gracefully. (6) Staging tables - load to temp table, swap atomically. Implementation: Spark upsertToTable(), Kafka consumer offset tracking, Airflow task idempotency keys, dbt incremental models. Trade-offs: idempotency adds complexity, performance overhead (merge slower than append), but reliability worth it. Best practice: all production pipelines should be idempotent.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (253, 'How do you handle late-arriving data in data pipelines? Discuss watermarking and window strategies.',
     'Late data: events arriving after their event time window processed. Example: server downtime, mobile devices offline, clock skew. Problem: window for hour 2-3pm closes at 3pm, event with timestamp 2:30pm arrives at 4pm, is it included? Watermarking: estimate how late data can be, delay window closing. Watermark = max event time seen - allowed lateness. Example: watermark of 1 hour means wait 1 hour after window end before finalizing. Events within 1 hour lateness are included. Trade-off: higher watermark (more lateness handled) vs longer delay (results not available quickly). Strategies: (1) Fixed watermark - wait fixed duration (simple but inflexible). (2) Percentile-based - accommodate 99% of data (based on historical lateness). (3) Heuristic - adjust based on data patterns. Handling late data: (1) Accept lateness - process within watermark, discard events beyond. (2) Reprocess windows - when very late data arrives, recompute past windows (expensive). (3) Side outputs - separate very late data for manual handling. (4) Approximate - use approximate algorithms (HyperLogLog) where late data less critical. Windowing types: Tumbling (non-overlapping, 1pm-2pm, 2pm-3pm), sliding (overlapping, every 1hr window shift by 15min), session (grouped by activity gaps). Apache Flink/Spark Streaming implementation: define event time, set watermark strategy, handle late data via allowedLateness or sideOutputLateData. Best practice: tune watermark based on SLA (can results wait?) and data patterns (how late does it arrive?), monitor late data percentage, alert if increasing.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (254, 'Compare batch processing vs stream processing. What are the trade-offs? When would you use a Lambda architecture vs Kappa architecture?',
     'Batch processing: process large volumes on schedule (daily, hourly). Example: nightly ETL job. Pros: simple, efficient for large data, easy to reason about, lower cost (batch compute cheaper). Cons: latency (wait for batch), not real-time, hard to update (reprocess all data). Tools: Spark batch, Hadoop MapReduce. Stream processing: process events as they arrive. Example: real-time analytics dashboard. Pros: low latency (milliseconds-seconds), real-time insights, continuous. Cons: complex (ordering, fault tolerance), more expensive (always-on infrastructure), harder to debug. Tools: Kafka Streams, Flink, Spark Streaming. Lambda architecture: separate batch and streaming paths, merge results. Batch layer processes all data (accurate, slow), speed layer processes recent data (fast, approximate), serving layer merges both. Pros: both real-time and accurate, can correct streaming errors in batch. Cons: maintain two codebases, complex, duplicate logic. Kappa architecture: streaming only, no batch layer. All data treated as stream (including historical via replay). Single pipeline, reprocess by replaying. Pros: simpler (one codebase), unified, easier to maintain. Cons: requires replayable source (Kafka), all transformations must work on streams, can be expensive to reprocess. Modern trend: Kappa preferred for simplicity, use batch + stream only if truly need both (rare). Hybrid: mostly streaming with batch for complex aggregations.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (255, 'Your daily ETL pipeline is taking progressively longer to complete - started at 2 hours, now taking 8+ hours and missing SLAs. Data volume has grown 3x, but processing time has grown 4x. The pipeline reads from PostgreSQL source, does transformations in Python pandas, loads to Redshift. How would you diagnose the bottleneck and optimize? Discuss strategies for incremental processing, parallelization, and when to migrate to different technologies.',
     'Performance degradation analysis: 3x data → 4x time suggests non-linear complexity or resource saturation. Bottleneck investigation steps: (1) Profile pipeline stages - time each step (extract, transform, load), identify which stage degraded most. (2) Database source query - is extraction slow? Check query plan, indexes, network bandwidth, source DB load. (3) Transformation - memory usage (pandas loads all to RAM, might be swapping), CPU usage, inefficient operations (row-wise instead of vectorized). (4) Load to Redshift - network throughput, COPY command performance, table distribution keys. (5) Resource monitoring - disk I/O, memory, CPU, network - which saturated? Likely findings: Pandas transformation bottleneck (entire day data in memory, doesn''t scale), full table scan every day (no incremental), single-threaded processing. Quick wins optimization: (1) Incremental processing - instead of reprocessing entire table, process only new/changed records. Watermark last ETL timestamp, extract WHERE updated_at > last_watermark. Reduces data volume linearly. (2) Chunking - instead of loading entire dataset to pandas, process in chunks (read 100k rows, transform, write, repeat). Prevents memory exhaustion. (3) Parallelization - split work across multiple workers. Partition by date ranges (worker 1 handles Jan, worker 2 Feb), process in parallel, merge results. Use Luigi/Airflow for orchestration. (4) Database optimization - add indexes on filter columns (updated_at), consider read replicas (offload from production), use columnar projection (select only needed columns). (5) Redshift optimization - COPY from S3 (faster than individual inserts), use DISTKEY for table distribution, VACUUM and ANALYZE tables, compress data. Medium-term improvements: (1) Technology migration - pandas → Spark (distributed, handles large data), Python → SQL (pushdown to database), local compute → cloud (scalable resources). (2) Change Data Capture (CDC) - instead of query full table, capture changes from DB transaction log (Debezium), only process deltas. Massive reduction. (3) Columnar format - intermediate data in Parquet instead of CSV (smaller, faster). (4) Resource scaling - vertical (bigger machine) for short-term, horizontal (more workers) for long-term. Long-term architecture: (1) Move to ELT - load raw data to Redshift/Snowflake/BigQuery (fast), transform using dbt (SQL in warehouse, leverages warehouse power), eliminates pandas bottleneck. (2) Streaming where applicable - if "daily" batch is actually accumulated events, consider streaming (Kafka → Flink → Warehouse), reduces batch window. (3) Data lake - raw data to S3/Data Lake, process with Spark, results to Warehouse, separation of storage and compute. Decision framework: If current tech can handle with optimization (incremental + parallel) → optimize. If fundamental scaling issue → migrate to Spark or ELT. If real-time needed → streaming. Cost consideration: bigger machines expensive, Spark cluster costs, warehouse compute costs. Measure ROI: SLA adherence, engineering time saved, data freshness value. Implementation approach: (1) Week 1: Add monitoring, profile to confirm bottleneck. (2) Week 2: Implement incremental processing (quick win). (3) Week 3-4: Parallelize, optimize queries. (4) Evaluate: hit SLA? If yes, done. If no, plan migration. (5) Month 2-3: Migrate to Spark or ELT (if needed). Avoid: premature optimization (migrate before profiling), over-engineering (Spark for MB of data), ignoring root cause (scaling won''t fix bad SQL). Success metrics: pipeline duration back under SLA, linear growth (2x data = ~2x time), resource utilization healthy (<80%), maintainability (simpler code if possible).',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 52: Data Warehousing (5 questions)
    (256, 'Explain the difference between OLTP and OLAP databases. How do they differ in design and optimization?',
     'OLTP (Online Transaction Processing): handle transactions, many small reads/writes, current data, normalized. Example: e-commerce database (insert order, update inventory). Characteristics: row-oriented storage, high concurrency, low latency (<100ms), normalized schema (3NF), emphasize writes, indexes on primary keys, ACID transactions. Use cases: applications, operations, real-time. OLAP (Online Analytical Processing): handle analytics, large aggregations, historical data, denormalized. Example: data warehouse (sales analysis, reporting). Characteristics: columnar storage, fewer users, read-heavy, denormalized (star/snowflake schema), emphasize aggregations, compressed storage, batch loads. Use cases: BI, reporting, analytics, data science. Design differences: OLTP normalized to reduce redundancy, update anomalies; OLAP denormalized for query performance, joins pre-computed. Storage: OLTP row storage (whole row read together), OLAP columnar (read only needed columns, better compression). Optimization: OLTP indexes for fast lookups, OLAP distribution keys and partitions for parallel scans. Tooling: OLTP (PostgreSQL, MySQL), OLAP (Snowflake, Redshift, BigQuery). Why separate: conflicting requirements, analytics queries would slow OLTP, OLTP schema not optimized for analytics. Modern: HTAP (Hybrid) systems try to do both (TiDB, CockroachDB), but trade-offs remain.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (257, 'What is a star schema vs snowflake schema? When would you use each? Discuss fact and dimension tables.',
     'Star schema: central fact table (metrics) surrounded by dimension tables (descriptive attributes), denormalized dimensions. Example: Fact_Sales (amount, quantity, date_id, product_id, customer_id) joins to Dim_Date, Dim_Product, Dim_Customer. Dimensions not normalized (Dim_Product has category directly). Pros: simple queries (fewer joins), fast (less joins), easy to understand. Cons: data redundancy in dimensions, larger storage, update anomalies. Snowflake schema: normalized dimensions, multi-level hierarchy. Example: Dim_Product → Dim_Category → Dim_Department. Pros: less storage (normalized), data integrity (no redundancy). Cons: more joins (slower), complex queries, harder to understand. Fact table: contains business metrics and foreign keys. Types: transactional (one row per event), periodic snapshot (daily balance), accumulating snapshot (order lifecycle). Grain: level of detail (one row per order line item vs per order). Dimension table: descriptive context (who, what, when, where). Slowly Changing Dimensions (SCD): Type 1 (overwrite, no history), Type 2 (add new row, keep history), Type 3 (add column for previous value). Use star when: query performance critical, simpler BI tool integration, moderate data volumes, storage cheap (cloud). Use snowflake when: storage expensive, dimensions very large, need strict normalization, fewer queries. Modern trend: star schema dominant in cloud warehouses (storage cheap, simplicity wins), snowflake for extreme cases.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (258, 'Compare cloud data warehouses: Snowflake, BigQuery, and Redshift. What are the key architectural differences and trade-offs?',
     'Snowflake: multi-cloud, separate storage and compute, auto-scaling. Architecture: data in cloud storage (S3/Azure/GCP), virtual warehouses for compute (scale independent), multi-cluster for concurrency. Pros: true separation (scale independently), pause/resume compute (cost savings), cross-cloud, automatic clustering, time travel. Cons: compute costs can escalate, data egress costs, query complexity affects cost. Pricing: compute by second + storage. BigQuery: Google serverless, fully managed, pay-per-query. Architecture: Dremel engine, columnar storage (Capacitor), separates compute, no infrastructure. Pros: true serverless (no cluster management), fast (parallelizes automatically), ML built-in (BQML), flat-rate option for predictable costs, GCP integration. Cons: GCP-only, less control, data egress expensive, complex pricing. Pricing: pay per TB scanned or flat-rate slots. Redshift: AWS, MPP architecture, node-based. Architecture: leader node + compute nodes, local storage (RA3 nodes separate), distribution keys for data layout. Pros: AWS integration, mature, Spectrum for querying S3, ML with SageMaker, predictable costs (node-based). Cons: rigid scaling (resize cluster), must manage clusters, pause/resume limited, vacuuming required. Pricing: node hours + storage. Key differences: BigQuery serverless vs others cluster-based, Snowflake multi-cloud vs others single-cloud, Redshift tightly coupled vs others separated. Performance: comparable for most workloads, optimization matters more than raw speed. Choose Snowflake for: multi-cloud, flexibility, concurrent workloads. Choose BigQuery for: GCP ecosystem, serverless preference, variable workload, ML integration. Choose Redshift for: AWS ecosystem, predictable costs, large existing investment. Modern: all three excellent, choice driven by cloud provider and team expertise.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (259, 'Explain materialized views in data warehousing. How do they differ from regular views? What are refresh strategies and their trade-offs?',
     'View: virtual table, SQL query stored, executed every time queried. No data stored, always fresh. Example: CREATE VIEW active_users AS SELECT * FROM users WHERE status=''active''. Materialized view: query results physically stored, pre-computed. Data stored, potentially stale. Example: CREATE MATERIALIZED VIEW monthly_sales AS SELECT month, SUM(amount) FROM sales GROUP BY month. Differences: Performance - MV fast (pre-computed), view slow (runs every time). Freshness - view always fresh, MV potentially stale. Storage - MV uses storage, view doesn''t. Use cases - MV for expensive aggregations, dashboards, view for simple filters. Refresh strategies: (1) Full refresh - drop and rebuild entire MV. Simple but expensive for large data. (2) Incremental refresh - update only changed rows. Efficient but complex, requires tracking changes. (3) On-demand refresh - manually trigger when needed. Control but risk of stale data. (4) Scheduled refresh - periodic (hourly, daily). Predictable but potentially stale between refreshes. (5) On-commit refresh - update when source table changes. Fresh but high overhead. Platform implementations: Snowflake - automatic clustering, pay for storage + refresh compute. BigQuery - automatic refresh, limited to 24hr staleness. Redshift - manual or scheduled REFRESH. Trade-offs: freshness vs cost (frequent refresh expensive), complexity vs accuracy (incremental refresh complex but efficient). Best practice: use MV for expensive queries used frequently, tune refresh based on acceptable staleness, monitor MV usage (may not be worthwhile), consider dbt incremental models (similar benefits, more control).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (260, 'Your data warehouse queries are slowing down significantly as data grows. A critical dashboard running daily aggregations now takes 45 minutes instead of 5 minutes. The query joins a 500M row fact table with 10 dimension tables and does extensive GROUP BY operations. How would you approach optimization? Discuss partitioning, clustering, distribution keys, aggregation tables, and when to redesign the schema.',
     'Query performance investigation framework: (1) Analyze query plan - use EXPLAIN to understand execution (scans, joins, sorts, aggregations), identify expensive operations (full table scans, large shuffles, spill to disk). (2) Data statistics - row counts, data distribution, cardinality of join keys, skew (are rows evenly distributed?). (3) Resource utilization - CPU, memory, disk I/O, network - which bottleneck. (4) Warehouse metrics - concurrency (other queries competing?), cluster/warehouse size, cache hit rate. Likely findings: Full scan of 500M fact table (no partition pruning), cross-distribution joins (data movement across nodes), high cardinality GROUP BY (large intermediate result), memory spill (aggregation too large for RAM), unoptimized join order. Optimization strategies ranked by impact: (1) Partitioning - partition fact table by date (most common filter). Query with WHERE date >= ''2024-01-01'' scans only relevant partitions. Redshift DISTKEY + SORTKEY, Snowflake clustering keys, BigQuery partitioning. Potential: scan 500M → 50M rows (10x improvement). (2) Clustering/Distribution - distribute fact table by join key (product_id if joining to products frequently), co-locate data to minimize shuffles. Cluster dimension tables. Potential: reduce network shuffle significantly. (3) Incremental aggregation - pre-aggregate at lower granularity. Instead of aggregating 500M rows daily, aggregate daily (create daily_sales table), dashboard query aggregates 1000 days instead of 500M rows. Potential: 100-1000x improvement. (4) Materialized views - create MV for this specific dashboard query, refresh on schedule (hourly if dashboard updated hourly). Query MV (instant) instead of raw tables. Potential: query time → seconds. (5) Column pruning - ensure query selects only needed columns (columnar storage benefit). Review if SELECT * or unnecessary columns included. (6) Join optimization - filter dimensions before joining (reduces join size), ensure smallest tables broadcast (BigQuery auto-optimizes, Redshift may need hints). (7) Compression - ensure optimal encoding (Snowflake auto, Redshift may need tuning), reduces scan I/O. (8) Statistics/ANALYZE - ensure optimizer has fresh statistics (ANALYZE TABLE), poor stats lead to bad plans. Implementation priority: Week 1 - Quick wins: ANALYZE tables, review query for obvious issues (SELECT *, missing filter), partition fact table by date. Expected: 2-3x improvement. Week 2 - Aggregation tables: Create daily summary table (daily_sales), update dashboard to use it, incremental refresh nightly. Expected: 10x+ improvement. Week 3 - Materialized View: If aggregation table insufficient, create MV specifically for dashboard. Week 4 - Clustering: Optimize distribution and cluster keys based on query patterns. Schema redesign consideration: If optimizations insufficient, may need redesign. Indicators: fundamentally wrong grain (too detailed), missing necessary aggregations, poor dimension design (snowflake when star better). Redesign approaches: (1) Change fact table grain - higher level aggregation (per day not per transaction). (2) Pre-join strategy - create wide denormalized table for specific use case (reporting_fact_table). (3) Separate warehouse - dedicated warehouse for reporting (isolate from other workloads). (4) Technology change - if hitting limits, consider different platform (OLAP-specific). Trade-offs evaluation: Aggregation table pros: fast queries, cons: staleness, maintenance overhead, storage. Materialized views: similar trade-offs but platform-managed. Denormalization: fast but redundancy, update complexity. Resource scaling: easy but expensive, masks underlying issues (should optimize first). Anti-patterns to avoid: Over-indexing (doesn''t help OLAP scans much), assuming bigger warehouse solves it (may just cost more without fixing root cause), optimizing before profiling (premature). Monitoring post-optimization: Query execution time trend, resource utilization, cache effectiveness, user satisfaction (dashboard usability). Success criteria: Query under SLA (5 minutes), cost-effective (not just throw resources), maintainable (not overly complex).',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 53: Apache Spark (5 questions)
    (261, 'Explain the architecture of Apache Spark. What are drivers, executors, and cluster managers?',
     'Spark architecture: Driver program, cluster manager, executors. Driver: runs main() function, creates SparkContext, converts program to tasks, schedules tasks on executors, coordinates execution. Lives on client machine or cluster. Executors: worker processes on cluster nodes, execute tasks, store data in memory/disk, report back to driver. Multiple executors per worker node. Cluster Manager: allocates resources, options include Spark Standalone, YARN, Mesos, Kubernetes. Execution flow: (1) User submits Spark application → Driver program starts. (2) Driver asks cluster manager for executors. (3) Cluster manager launches executors on worker nodes. (4) Driver sends application code to executors. (5) Driver schedules tasks and sends to executors. (6) Executors run tasks, return results to driver. (7) SparkContext stops, resources released. Key concepts: Job (Spark action), Stage (set of tasks), Task (unit of work on partition). RDD (Resilient Distributed Dataset): immutable distributed collection, partitioned, fault-tolerant. Transformations (map, filter) lazy, Actions (collect, count) trigger execution. DAG (Directed Acyclic Graph): Spark builds execution plan as DAG of stages, optimizes before execution. Deployment modes: Client mode (driver on client machine), Cluster mode (driver on cluster), affects latency and failure handling.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (262, 'Compare Spark RDDs, DataFrames, and Datasets. When would you use each?',
     'RDD (Resilient Distributed Dataset): low-level API, distributed collection of objects, functional transformations (map, filter, reduce). Pros: full control, can express any computation, works with any object. Cons: no optimization (Spark can''t optimize custom functions), no schema, slower, verbose. Use for: complex custom logic, when DataFrame can''t express, low-level control needed. DataFrame: distributed collection of rows with named columns, like SQL table, Catalyst optimizer applies. Pros: optimized (Catalyst query optimization, Tungsten execution), SQL support, concise, cross-language (Python, Scala, Java). Cons: no compile-time type safety, runtime errors. Use for: SQL-like operations, structured data, most use cases (recommended). Dataset: typed DataFrame, compile-time type safety (Scala/Java only). Example: Dataset[Person] vs DataFrame. Pros: type safety (catch errors at compile), optimized like DataFrame, object-oriented. Cons: Scala/Java only (no Python), serialization overhead for custom objects, slightly more complex. Use for: need type safety, complex objects, Scala/Java project. Evolution: RDD → DataFrame (optimization) → Dataset (type safety). Modern: DataFrame dominant (Python DataFrames most common), Dataset for Scala strong typing needs, RDD rare (legacy or very custom). Interoperability: can convert between (RDD.toDF(), df.rdd), mix APIs in same application. Best practice: start with DataFrame, use RDD only if absolutely necessary.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (263, 'Explain Spark transformations vs actions. What is lazy evaluation and why does it matter?',
     'Transformations: create new RDD/DataFrame from existing, lazy (not executed immediately). Examples: map, filter, join, groupBy, select. Actions: trigger computation, return results to driver or write to storage, eager (execute immediately). Examples: collect, count, save, show, foreach. Lazy evaluation: Spark builds execution plan (DAG) when transformations called, but doesn''t execute until action. Example: df.filter(...).map(...).groupBy(...) → no computation. df.count() → now Spark executes entire chain. Why laziness matters: (1) Optimization - Spark sees entire chain, optimizes holistically (predicate pushdown, column pruning, join reordering). (2) Avoid intermediate results - if filter drastically reduces data, map works on less data. (3) Fault tolerance - can recompute from lineage if partition lost. (4) Pipelining - chain operations in single pass over data. Example optimization: df.select("name", "age").filter(age > 18) → Spark pushes filter before select (scan less data). Without laziness, would scan all columns then filter. Narrow vs wide transformations: Narrow (map, filter) - no shuffle, partition-to-partition mapping, pipelined. Wide (groupBy, join) - shuffle required, stage boundary, expensive. Actions return types: collect (array to driver - careful with large data), count (long), save (persists to storage), take(n) (first n rows). Best practices: minimize actions (each triggers execution), avoid collect on large data (use take or save), understand when shuffles occur (wide transformations), use persist/cache for reused DataFrames (otherwise recomputed).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (264, 'What are Spark shuffles? Why are they expensive? How do you minimize them?',
     'Shuffle: redistribution of data across partitions, required for wide transformations (groupBy, join, distinct, repartition). Example: groupBy("category") needs all rows for same category together, currently spread across partitions, must shuffle. Why expensive: (1) Disk I/O - write shuffle data to disk, read by receiving executors. (2) Network transfer - data moved across nodes over network (high volume). (3) Serialization/deserialization - objects serialized for transfer. (4) Complexity - coordination, potential spill to disk if memory insufficient. Shuffle operation: Map side writes shuffle files partitioned by key, reduce side reads relevant partitions. Performance impact: can be 10-100x slower than in-partition operations. Minimize shuffles strategies: (1) Avoid unnecessary wide transformations - review if groupBy necessary, maybe aggregation can be local first (use reduceByKey instead of groupBy + reduce). (2) Broadcast joins - for joining small table to large table, broadcast small table to all executors (no shuffle large table). Example: df_large.join(broadcast(df_small), "key"). (3) Partition before wide operations - if doing multiple groupBys on same key, repartition once, then multiple operations are local. (4) Coalesce instead of repartition - reduce partitions without full shuffle (coalesce combines partitions, repartition shuffles). (5) Salting for skewed keys - if one key has 90% of data, split key to distribute (salt: append random 0-9 to key, process, aggregate). (6) Proper partitioning scheme - partition data by common join/group keys in storage. Monitoring: Spark UI shows shuffle read/write bytes, identify stages with heavy shuffles. Tuning: spark.sql.shuffle.partitions (default 200, set based on data volume and cores), spark.sql.adaptive.enabled (adaptive query execution optimizes dynamically).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),


    (265, 'Your Spark job processing 10TB of data is running for 6 hours and frequently failing with OutOfMemory errors and data skew issues. One partition has 100x more data than others. The job does multiple groupBy and join operations. How would you diagnose and fix the performance and stability issues? Discuss partitioning strategies, memory management, and skew handling.',
     'Multi-pronged diagnosis approach: (1) Spark UI Analysis - check stage timeline (which stages longest?), task metrics (skew visible if one task much longer), shuffle read/write volumes (expensive shuffles?), executor memory (OOM locations). (2) Data profiling - cardinality of group keys (one key 100x more frequent?), partition size distribution (show 100x skew), data statistics. (3) Resource monitoring - executor memory usage over time, GC frequency (high GC = memory pressure), disk spill events (memory insufficient). Identified issues: Data skew (one group key has 100x data), memory pressure (10TB data, insufficient executor memory), multiple wide transformations (repeated shuffles), potentially inefficient joins. Solutions by priority: Issue 1 - Data Skew: Technique: Salting for aggregations - add random salt to skewed key, pre-aggregate, then final aggregate. Example: key "popular" → ["popular_0", "popular_1"..."popular_9"], distribute across partitions, run groupBy, then groupBy on original key. For joins: Broadcast join if one side small, Salted join for large skewed joins (split heavy key, join multiple times). Measure: task duration variation should reduce significantly. Issue 2 - Memory Management: Increase executor memory (--executor-memory 16g → 32g), increase driver memory if collecting, tune memory fractions (spark.memory.fraction, spark.memory.storageFraction). Persist/cache strategy: if DataFrame reused, cache intelligently (MEMORY_AND_DISK_SER to balance memory and spill), unpersist after use. Broadcast join: for small dimension tables, broadcast to avoid shuffle (spark.sql.autoBroadcastJoinThreshold). Reduce partition size: if partitions too large, increase partition count (spark.sql.shuffle.partitions = 200 → 1000), smaller partitions = less memory per task. Issue 3 - Shuffle Optimization: Reduce shuffle count: combine operations where possible, use reduceByKey instead of groupByKey (pre-aggregates locally), dataframe API optimizes better than RDD. Partition early: repartition by common key once at start, subsequent groupBy/join operations local. Coalesce for writing: reduce partitions before write (avoid many small files). Adaptive Query Execution: enable AQE (spark.sql.adaptive.enabled=true), dynamically optimizes (coalesces partitions, skew joins, broadcast runtime). Issue 4 - Job Structure: Break into stages: instead of one 6-hour job, checkpoint intermediate results (df.write.parquet("intermediate/"), df_cached = spark.read.parquet()), allows restart without full recomputation. Incremental processing: if possible, process in smaller batches (partition by date, process each separately), reduces memory footprint. Specific configuration tuning: spark.executor.memory = 32g (more RAM), spark.executor.cores = 4 (fewer cores per executor = more memory per core), spark.sql.shuffle.paritions = 1000 (smaller shuffle partitions), spark.sql.adaptive.enabled = true (AQE), spark.sql.adaptive.skewJoin.enabled = true (auto-handle skew joins), spark.sql.files.maxPartitionBytes = 128MB (control read partition size), spark.network.timeout = 600s (prevent timeout on large shuffles). Testing approach: (1) Sample data test (1% sample), validate logic works, profile skew on sample. (2) Tune on medium dataset (1TB), validate OOM fixed, measure time improvement. (3) Full run with monitoring, watch for new issues. (4) Iterate. Advanced techniques: Skew hint (Spark 3.0+): use join hints to tell Spark about skew. Custom partitioner: write custom partitioner for very specific skew patterns. Dynamic partition pruning: ensure partition filters applied properly. Bucketing: pre-bucket tables by join key (avoids shuffle at query time). Alternative: if Spark struggling, consider other tools - Presto/Trino for queries, Snowflake/BigQuery for warehouse operations, Dask/Ray for alternative distributed compute. Success criteria: Job completes without OOM, completion time under SLA (target 2-3 hours with optimizations), task duration variance < 2x (minimal skew), resource utilization healthy (not hitting limits).',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 54: Apache Kafka (5 questions)
    (266, 'What is Apache Kafka? Explain the basic concepts: topics, partitions, producers, consumers, and brokers.',
     'Apache Kafka: distributed event streaming platform, publish-subscribe messaging system, high-throughput, fault-tolerant, durable. Use cases: real-time data pipelines, stream processing, event sourcing, log aggregation. Core concepts: (1) Topic - category/feed name for messages. Example: "user-clicks", "order-events". Logical grouping of messages. (2) Partition - topics split into partitions for parallelism and scalability. Each partition ordered, immutable sequence of messages (log). Message order guaranteed within partition, not across partitions. (3) Producer - publishes messages to topics. Chooses which partition (round-robin, key-based, custom). Can batch for throughput. (4) Consumer - reads messages from topics. Subscribes to one or more topics. Tracks offset (position in partition). (5) Consumer Group - multiple consumers work together, each partition consumed by one consumer in group. Load balancing and fault tolerance. (6) Broker - Kafka server, stores data, serves requests. Cluster has multiple brokers for HA. (7) Offset - unique ID for message in partition, sequential. Consumer tracks offset to know what''s been read. Message flow: Producer sends message to topic → Kafka writes to partition → Consumer reads from partition. Guarantees: at-least-once delivery (default), exactly-once with configuration, message ordering within partition. Why Kafka: high throughput (millions messages/sec), scalability (add brokers), durability (replication), fault tolerance (broker failures handled).',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (267, 'Explain Kafka consumer groups and partition assignment. What happens when a consumer joins or leaves a group?',
     'Consumer group: multiple consumers collaborate to consume topic, each partition consumed by exactly one consumer in group. Enables parallel processing and fault tolerance. Example: topic with 6 partitions, consumer group with 3 consumers → each consumer gets 2 partitions. Partition assignment: Kafka coordinator assigns partitions to consumers, strategies include: (1) Range - assign consecutive partitions (C1 gets P0-P1, C2 gets P2-P3). (2) Round-robin - distribute evenly (C1: P0,P2,P4, C2: P1,P3,P5). (3) Sticky - minimize reassignments on rebalance. (4) Custom - implement own logic. Consumer joins group: (1) Consumer sends JoinGroup request to coordinator. (2) Coordinator triggers rebalance. (3) All consumers stop consuming, participate in rebalance. (4) Leader consumer calculates assignment. (5) Coordinator distributes assignment. (6) Consumers resume from committed offsets. Consumer leaves (graceful): same rebalance process, remaining consumers get more partitions. Consumer crashes: coordinator detects heartbeat failure (session timeout), triggers rebalance, partitions reassigned. Rebalance implications: (1) Stop-the-world - all consumers pause during rebalance (latency spike). (2) Duplicate processing - uncommitted offsets may be reprocessed. (3) Coordination overhead. Minimize rebalances: stable consumer instances, tune session.timeout.ms and heartbeat.interval.ms, static membership (consumer.group.instance.id), avoid long processing (max.poll.interval.ms). Independent consumers: no consumer group (empty group ID), read all partitions themselves, manual offset management. Use for: exactly-once processing, don''t need load balancing.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (268, 'What are Kafka offset management strategies? Explain auto-commit vs manual commit and their trade-offs.',
     'Offset: consumer position in partition, tracking what''s been read. Committed offset: last processed message offset stored in Kafka, used to resume after restart. Strategies: (1) Auto-commit - Kafka commits offsets automatically at interval (enable.auto.commit=true, auto.commit.interval.ms=5000). Simple, no code needed. Risk: at-most-once or at-least-once depending on when failure occurs. Example: poll messages → process → crash before auto-commit → messages lost (at-most-once). Or: poll → auto-commit → crash during processing → reprocess on restart (at-least-once). (2) Manual commit synchronous - commit after processing (consumer.commitSync()). Blocks until committed. Provides at-least-once guarantee (process then commit). Slower but safe. (3) Manual commit asynchronous - commit without blocking (consumer.commitAsync()). Faster, doesn''t wait. Risk: failure before commit persisted (reprocessing). Callback for error handling. (4) Commit specific offsets - fine-grained control (commitSync(Map<TopicPartition, OffsetAndMetadata>)). Commit per batch or per message. Trade-offs: Auto-commit vs Manual: auto simple but less control, manual precise but more code. Sync vs Async: sync safer but slower (blocks), async faster but failure risk. Exactly-once: require transactional producer + idempotent consumer + manual commit, complexity high. Best practices: For correctness-critical: manual sync commit after processing each batch. For throughput: manual async commit with periodic sync commit checkpoint. For exactly-once: enable idempotence, use transactions, store offsets with results (database transaction). Offset storage: Kafka v0.9+ stores offsets in internal __consumer_offsets topic, older versions used ZooKeeper. External storage: can store offsets in external database alongside results for transactional guarantees.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (269, 'How does Kafka ensure high availability and fault tolerance? Explain replication, ISR, and recovery.',
     'Replication: each partition replicated across multiple brokers, one leader + N-1 followers. Replication factor = copies. Example: RF=3 means 3 copies, tolerates 2 broker failures. Leader: handles all reads and writes for partition, followers replicate. In-Sync Replica (ISR): follower fully caught up with leader (lag within threshold). Leader + ISR provide durability guarantee. Configuration: replica.lag.time.max.ms determines when follower considered out-of-sync. Producer ACKs: (1) acks=0 - fire and forget, no durability. (2) acks=1 - leader acknowledges (fast but leader failure before replication = loss). (3) acks=all - all ISR acknowledge (durable, slower). Failure scenarios: (1) Follower fails - removed from ISR, leader continues, when recovers catches up and rejoins ISR. (2) Leader fails - controller elects new leader from ISR, clients failover to new leader, short unavailability. (3) Broker fails - partitions it led elect new leaders, partitions it followed catch up from new leaders. (4) Multiple failures - if all ISR down, unclean leader election (elect out-of-sync replica with unclean.leader.election.enable=true) or wait for ISR recovery. Recovery: failed broker restarts, rejoins cluster, catches up on partitions, becomes ISR again. ZooKeeper/KRaft: ZooKeeper (legacy) coordinates cluster, KRaft (newer) eliminates ZooKeeper dependency (metadata in Kafka itself). Guarantees: no message loss if min.insync.replicas configured (require at least N ISR for write), example: RF=3, min.insync.replicas=2, acks=all → survives 1 failure without loss. Availability vs durability trade-off: higher replication more durable but more resource intensive, acks=all more durable but higher latency.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (270, 'Your Kafka-based real-time analytics system is experiencing increasing lag - consumer group is falling behind producers by hours. The topic has 12 partitions and receives 100K messages/sec. Your consumer group has 4 consumers, each taking 50ms to process a message. How do you diagnose the bottleneck and scale to eliminate lag? Discuss parallelism, partition strategy, consumer optimization, and when to add more partitions.',
     'Lag diagnosis framework: (1) Kafka metrics - consumer lag per partition (kafka-consumer-groups.sh --describe), producer rate vs consumer rate, partition distribution across consumers. (2) Consumer metrics - processing time per message, poll batch size, commit frequency, GC overhead. (3) System metrics - CPU, memory, network on consumer instances. Capacity calculation: Producer rate: 100K msg/sec across 12 partitions = ~8333 msg/sec per partition. Consumer capacity: 50ms per message = 20 msg/sec per consumer. Current setup: 4 consumers, 12 partitions → 3 partitions per consumer. Per consumer: 3 partitions × 8333 msg/sec = 25K msg/sec needed, but capacity only 20 msg/sec. Bottleneck identified: consumers drastically underpowered (need 1250x more capacity per consumer). Critical issue: 50ms processing time too slow OR too few consumers. Solutions prioritized: (1) Optimize consumer processing (high impact): Profile consumer code - 50ms where spent? Database call (batch!), API call (async!), computation (optimize algorithm!). If DB writes: batch inserts (100 messages → 1 batch write), reduces per-message overhead. If API calls: async HTTP clients, parallel requests. If CPU: algorithm optimization, caching. Target: reduce to 5ms per message (10x improvement). New capacity: 200 msg/sec per consumer. May still be insufficient. (2) Increase consumer parallelism (medium impact): Max consumers = partition count, increase to 12 consumers (one per partition). Each consumer: 8333 msg/sec × 5ms = can handle 200 msg/sec but needs 8333. Still insufficient! Must optimize processing + add consumers. (3) Further processing optimization: Stream processing mindset - not every message needs 50ms, aggregate in-memory, flush periodically. Example: analytics aggregation (count events per minute), buffer in-memory, flush every second instead of write per event. Async processing: decouple intake from processing - consumer reads fast, puts in local queue, worker threads process. Consumer not blocked. (4) Increase partitions (careful!): Currently 12 partitions, can add more BUT: requires topic rebalancing (existing data doesn''t auto-redistribute), increases complexity, diminishing returns. When to increase: measured consumer headroom (all running at capacity even after optimization), linear scaling needed (each partition processes independently). How to increase: create new topic with more partitions, migrate producers, or use Kafka partition tool (requires downtime). Example: 12 → 24 partitions, can run 24 consumers. (5) Horizontal scaling infrastructure: More powerful consumer machines (vertical scaling), auto-scaling consumer group (K8s HPA based on lag metric). Advanced techniques: Parallel processing within consumer: each consumer multi-threaded, one thread per partition, careful with thread safety. Tiered architecture: fast consumers do minimal work (just write to database), separate batch processing for heavy analytics. Sampled processing: if analytics allow, process sample not every message (1% sample still 1K msg/sec insights). Implementation plan: Week 1 - Profile and optimize consumer code, target < 5ms per message, measure improvement. Week 2 - Scale to 12 consumers (max for current partitions), benchmark lag reduction. Week 3 - If still lagging, increase partitions to 24, scale to 24 consumers, validate lag eliminated. Week 4 - Monitor and tune, ensure sustainable. Monitoring post-fix: Consumer lag metric (alert if > threshold), consumer processing time p99, end-to-end latency (producer to consumer), resource utilization. When not to increase partitions: Over-partitioning (too many partitions) increases broker overhead, rebalances slower, diminishing returns. Rule of thumb: partitions should be multiple of expected max consumers, not excessively high. Avoid: increase partitions blindly without optimizing first (won''t fix slow processing), under-provision consumers (won''t use partition parallelism), ignore root cause (maybe producer should slow down or use batching). Alternative architectures: If Kafka struggling, consider: multi-tier (Kafka → buffer layer → slower processing), different tech (Pulsar for better scalability), queuing system if strict ordering not needed.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 55: Apache Airflow (5 questions)
    (271, 'What is Apache Airflow? Explain DAGs, tasks, operators, and how Airflow schedules workflows.',
     'Apache Airflow: platform to programmatically author, schedule, and monitor workflows as code. Use cases: data pipelines, ETL, ML pipelines, batch processing. Core concepts: (1) DAG (Directed Acyclic Graph) - workflow definition, collection of tasks with dependencies, Python code. Example: extract → transform → load. Acyclic: no circular dependencies. (2) Task - unit of work in DAG (run Python function, execute SQL, trigger external system). (3) Operator - template for task, defines what task does. Examples: PythonOperator (run Python), BashOperator (run shell), PostgresOperator (run SQL). Custom operators possible. (4) Task Instance - specific run of task for specific date. (5) DAG Run - execution of entire DAG for specific date/time. Scheduling: Airflow scheduler triggers DAGs based on schedule_interval (cron expression), start_date defines when DAG becomes active, catchup determines backfilling. Execution: scheduler creates DAG runs, breaks into task instances, workers execute tasks, results tracked in metadata database. Dependencies: set with >> or <<. Example: task1 >> task2 >> task3 defines sequential execution. Complex dependencies possible (fan-out, fan-in). Executor types: SequentialExecutor (local, one at time), LocalExecutor (local, parallel), CeleryExecutor (distributed, multiple workers), KubernetesExecutor (each task separate pod). Architecture: Scheduler (triggers), Workers (execute), Web UI (monitor), Metadata DB (state). Why Airflow: workflows as code (version control), rich UI (visualize, debug), extensible (custom operators), retry/alerting built-in, large ecosystem.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (272, 'How do you handle dependencies between tasks in Airflow? Explain different dependency patterns.',
     'Dependency operators: >> (downstream), << (upstream), Chain helper for sequential. Patterns: (1) Sequential - task1 >> task2 >> task3, linear pipeline. (2) Fan-out - one task triggers multiple parallel tasks. Example: extract >> [transform_a, transform_b, transform_c], all transforms run in parallel. (3) Fan-in - multiple tasks converge to one. Example: [load_a, load_b] >> report, report waits for both. (4) Branching - conditional execution. BranchPythonOperator chooses next task based on logic. Example: check_data >> [process_route, skip_route]. (5) Trigger Rules - control when task runs. "all_success" (default, all parents succeed), "all_failed" (run if all  parents fail), "all_done" (run regardless of parent status), "one_success" (run if any parent succeeds), "one_failed", "none_failed". Use case: final cleanup task runs always (trigger_rule="all_done"). (6) Cross-DAG dependencies - ExternalTaskSensor waits for task in another DAG. Use for: modular DAGs, dependencies across workflows. (7) Dynamic dependencies - generate tasks programmatically. Example: for file in files: create_task(file), useful for variable workloads. (8) SubDAGs - embed DAG within task (now deprecated, use TaskGroups). TaskGroups organize tasks visually without extra DAG run. Best practices: keep DAGs simple (complex dependencies hard to debug), use TaskGroups for visual organization, avoid overly deep nesting, make dependencies explicit, use sensors for external dependencies (wait for file, database record).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),


    (273, 'What are Airflow XComs? How do you pass data between tasks? What are the limitations?',
     'XCom (Cross-Communication): mechanism to pass small amounts of data between tasks, stored in Airflow metadata database. How it works: tasks push data to XCom (return value auto-pushed or explicit), downstream tasks pull data (task_instance.xcom_pull). Usage: task1 returns result → task2 accesses via xcom_pull(task_ids="task1"). Example: extract task returns file path, transform task reads that path. Limitations: (1) Size - stored in DB, should be small (KB not GB), large data causes DB bloat. (2) Serialization - values pickled/JSON, must be serializable, complex objects problematic. (3) Coupling - creates dependency (tight coupling between tasks). (4) Database load - many XComs in frequently running DAG strains DB. Best practices: Use XComs for: metadata (file paths, record counts, status). Don''t use for: large datasets (use external storage like S3), binary data (inefficient). Alternatives for large data: (1) External storage - write to S3/GCS, pass location via XCom. (2) Database staging table - write data temp table, pass table name. (3) Message queue - for event-driven workflows. XCom custom backends: configure different storage (S3, GCS instead of metadata DB) for large XComs, requires Airflow 2.0+. Cleanup: XCom retention policy prevents DB growth (auto-delete old XComs). Advanced: custom XCom serialization for complex objects.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (274, 'How do you implement retries and error handling in Airflow? Discuss task retries, SLAs, and alerting.',
     'Retry mechanisms: (1) Task retries - retry_delay (wait between retries), retries (max attempts), retry_exponential_backoff (increase delay). Example: retries=3, retry_delay=timedelta(minutes=5), task fails → wait 5min → retry → fail → wait 5min → retry. (2) Task failure behavior - on_failure_callback (Python function called on final failure, send alert), on_retry_callback (called on each retry), on_success_callback. SLAs (Service Level Agreements): sla parameter defines max time task should complete, if exceeded triggers SLA miss callback. Example: sla=timedelta(hours=2), if task not done in 2hr → alert. Use for: critical tasks with time requirements. Email alerting: configure SMTP, email_on_failure=True sends email on task failure, email_on_retry, email_on_success. Email recipients via email parameter. Sensors and timeouts: timeout parameter kills task if too long, poke_interval for sensors (polling frequency). Error handling patterns: (1) Defensive tasks - use try-except in PythonOperator, handle expected failures gracefully, return status. (2) Conditional downstream - BranchOperator routes based on upstream success/failure. (3) Cleanup tasks - trigger_rule="all_done" ensures cleanup runs even if pipeline fails. (4) CircuitBreaker pattern - skip tasks if dependency consistently failing. Monitoring: Airflow UI shows task status, failed task investigations (logs, XComs, duration), DAG run history. External monitoring: export DAG metrics to Prometheus, Datadog for alerting. Best practices: set appropriate retries (transient failures common), exponential backoff prevents overwhelming systems, clear SLAs for business-critical DAGs, comprehensive alerting (Slack,等 PagerDuty), runbook links in alert descriptions.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (275, 'Your Airflow environment is struggling with 100+ DAGs running daily. The scheduler is lagging, tasks queue up, and DAG parsing takes minutes. How would you diagnose and optimize Airflow performance? Discuss database optimization, scheduler tuning, executor choice, and DAG design best practices.',
     'Performance problem indicators: Scheduler lag (tasks not starting on time), slow DAG parsing (every 30sec Airflow parses DAGs, high latency), tasks queued (workers busy), UI slow (database queries slow). Diagnosis methodology: (1) Airflow metrics - DAG file parse time, scheduler loop duration, task instance queue length, executor queue size. (2) Database metrics - query performance, connection pool utilization, table sizes (task_instance, dag_run, xcom). (3) Resource monitoring - scheduler CPU/memory, worker CPU/memory, database load. (4) DAG analysis - complexity (tasks per DAG), dependencies, scheduled runs (how often each DAG runs). Optimization strategies: (1) Database optimization: CRITICAL - metadata DB is bottleneck for large deployments. Use production database (PostgreSQL/MySQL, not SQLite), increase connection pool (sql_alchemy_pool_size, sql_alchemy_max_overflow), tune DB queries (EXPLAIN ANALYZE slow queries), partition tables (task_instance grows large), purge old data (airflow db clean), read replicas for web server. (2) Scheduler tuning: Increase scheduler resources (CPUs, memory), tune scheduler_heartbeat_sec (how often scheduler runs), min_file_process_interval (DAG parse frequency, default 30s may be too frequent), max_threads (parallel DAG processing), parsing_processes (parallel parsers). Avoid: over-tuning causes thrashing, test incrementally. (3) Executor choice: LocalExecutor: good for single machine, limited parallelism. CeleryExecutor: distributed workers, horizontal scaling, requires message queue (Redis/RabbitMQ), complex but scalable. KubernetesExecutor: each task in separate pod, elastic scaling, overhead of pod creation. Recommendation: CeleryExecutor for high task throughput, KubernetesExecutor for variable workload / resource isolation. (4) DAG design best practices: Minimize top-level DAG code (parsed every scheduler loop), move logic into task operators. Avoid: loops, API calls, database queries at DAG level, do it in tasks! Example BAD: for file in read_s3_files(): create_task(file) # reads S3 every parse! GOOD: dynamic task creation inside operator or use TaskFlow API. Reduce DAG complexity: fewer tasks per DAG (split mega-DAGs), use SubDAGs/TaskGroups wisely (subDAGs spawn separate runs, overhead). Turn off unnecessary catchup (catchup=False prevents backfilling). Use LatestOnlyOperator for incremental pipelines (skip old runs). Reduce XCom usage (DB bloat), cleanup policy. Use sensors sparingly (poke mode blocks worker, reschedule mode better). (5) Parallelism configuration: parallelism (max tasks across all DAGs), dag_concurrency (max tasks per DAG), max_active_runs_per_dag (max simultaneous DAG runs), worker_concurrency (CeleryExecutor tasks per worker). Balance these avoid overwhelming. (6) Operational improvements: Upgrade Airflow (newer versions faster, 2.x much better than 1.x), monitor and alert scheduler health, horizontally scale workers (add more Celery workers), shard DAGs (separate Airflow instance for different teams/use cases, reduces per-instance load). Specific tuning from symptoms: Slow parsing: reduce parsing frequency, optimize DAG code, reduce DAG count (consolidate). Tasks queued: add more workers, increase parallelism limits, optimize task duration. Scheduler lag: tune scheduler parameters, upgrade DB, reduce DAG complexity. Database slow: optimize queries, partition tables, increase resource, purge old data. Testing process: Baseline metrics before changes, tune one parameter at a time (isolate impact), load test (simulate peak), monitor for regressions. Success criteria: Scheduler lag < 5sec, DAG parse time < 1sec, task queue minimal, SLAs met, UI responsive. When to architect differently: If single Airflow instance hitting limits even after optimization, consider: (1) Multi-instance - separate instances for different teams, reduces blast radius. (2) Alternative orchestrator - explore other tools (Prefect, Dagster, Argo Workflows) if Airflow not fitting. (3) Simplify workflows - maybe too complex, break into simpler pipelines.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 56: Data Quality (5 questions)
    (276, 'What is data quality? What are the key dimensions of data quality?',
     'Data quality: degree to which data meets requirements for intended use, fit-for-purpose data. Poor quality leads to bad decisions, customer dissatisfaction, compliance issues. Key dimensions: (1) Accuracy - data correct and represents reality. Example: customer email address is valid, not typo. (2) Completeness - all required data present, no missing critical fields. Example: all orders have customer ID. (3) Consistency - data same across systems, no contradictions. Example: customer name same in CRM and billing DB. (4) Timeliness - data available when needed, fresh. Example: inventory counts updated hourly not daily. (5) Validity - data conforms to format/rules. Example: date in YYYY-MM-DD format, phone number with correct digits. (6) Uniqueness - no duplicates where not expected. Example: customer records not duplicated. (7) Integrity - relationships maintained (referential integrity). Example: order references existing customer. Measuring data quality: quality score (% records meeting criteria), completeness rate (% fields non-null), accuracy sampling (manual validation), anomaly detection (statistical outliers). Impact of poor quality: wrong business decisions, revenue loss (bad addresses = failed deliveries), compliance violations (GDPR requires accuracy), low trust in data. Data quality framework: (1) Define quality rules (business requirements). (2) Profile data (understand current state). (3) Monitor quality (automated checks). (4) Remediate issues (clean data, fix pipeline). (5) Prevent future issues (validation at source).',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (277, 'How do you implement data quality checks in data pipelines? Discuss validation strategies and tools.',
     'Validation strategies: (1) Schema validation - enforce expected schema (columns, types). Example: Parquet file must have columns [id:int, name:string, date:date], reject if missing or wrong type. Tools: Great Expectations, Pandera, custom code. (2) Range validation - values within expected range. Example: age between 0-120, price > 0. SQL: WHERE NOT (age BETWEEN 0 AND 120). (3) Uniqueness checks - primary keys unique, no duplicates. SQL: GROUP BY key HAVING COUNT(*) > 1 (finds dupes). (4) Completeness checks - required fields non-null. SQL: WHERE critical_field IS NULL. (5) Referential integrity - foreign keys exist. SQL: LEFT JOIN, find orphans where parent IS NULL. (6) Business rule validation - domain-specific rules. Example: order_total = SUM(line_items). (7) Statistical validation - data distribution expected (mean, std dev, percentiles). Detect anomalies. Example: daily record count within 2 std dev of average. (8) Freshness checks - data recent. Example: max(updated_at) within last 24hrs. Implementation approaches: (1) Pipeline stage - dedicated validation task after extract before transform, fail pipeline if validation fails or quarantine bad data. (2) Great Expectations - framework for data validation, define expectations (expect_column_values_to_be_between), generates data docs, integrates with Airflow. (3) dbt tests - built-in tests (unique, not_null, relationships, accepted_values), custom tests in SQL, fails build if tests fail. (4) Custom SQL/Python - query data, assert conditions, raise exception if fails. When to validate: (1) At source - validate as data enters system, reject bad data early. (2) After transformation - ensure transform logic correct. (3) Before load - final check before warehouse. (4) In warehouse - scheduled checks on existing data (detect degradation). Response to failures: (1) Fail pipeline - stop processing, alert on-call. Use for: critical data quality requirements. (2) Quarantine - move bad records to error table, process good records, review bad data. Use for: some bad data acceptable. (3) Alert and continue - log warning, notify team, don''t block pipeline. Use for: non-critical issues. Tools: Great Expectations (comprehensive framework), dbt tests (transformation testing), WhyLogs (data logging and monitoring), Monte Carlo, Datafold (DQ monitoring platforms), custom solutions.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (278, 'What is data profiling? How does it help identify data quality issues?',
     'Data profiling: analyzing data to understand structure, content, quality, relationships. Automated discovery of data characteristics. Purpose: understand data before building pipelines, identify quality issues, discover patterns, define validation rules. Profiling components: (1) Column profiling - data type, non-null percentage, distinct count, cardinality (unique values), min/max/mean/median, common values (top 10), value length distribution. (2) Pattern detection - regex patterns (phone numbers, emails), date formats, encoding. (3) Relationship discovery - correlations between columns, potential foreign keys, dependency detection. (4) Outlier detection - statistical outliers (values far from mean), rare values. (5) Duplicate detection - exact duplicates, fuzzy duplicates (similar records). Quality issues discovered: Missing data (50% of column null → need handling), unexpected nulls (assumed non-null but 10% null), cardinality issues (expected unique but duplicates), format inconsistencies (dates in multiple formats), outliers (age = 999, likely invalid), orphaned records (foreign key not in parent table). Use cases: (1) New data source - profile before integration, understand shape. (2) Pipeline development - validate assumptions (column always populated?), design transforms. (3) Migration - compare source and destination profile (did migration preserve data?). (4) Monitoring - regular profiling detects drift (distribution changing, new nulls). Tools: Great Expectations (profiling + expectations), Pandas Profiling (Python reports), AWS Glue DataBrew, Atlan, Alation (data catalogs with profiling), ydata-profiling. Workflow: Run profiler → Review report → Define quality rules based on findings → Implement validation → Monitor ongoing. Example: profile customer table → find email column 20% null but required for marketing → add "contact_preference" column, make email optional, add validation for preference=email requires email.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (279, 'Explain the concept of data lineage. Why is it important for data quality and governance?',
     'Data lineage: complete trail of data from origin through transformations to final destination, shows data journey and dependencies. Visual representation: DAG showing table/column relationships. Example: customer_orders table → joined with customers and products → aggregated to revenue_report. Components: (1) Source - where data originated (database, API, file). (2) Transformations - operations applied (joins, filters, aggregations, business logic). (3) Destination - where data lands (warehouse table, report, ML model). (4) Column-level lineage - track specific column transformations (revenue = SUM(price * quantity)). Importance for data quality: (1) Root cause analysis - data quality issue in report, trace lineage upstream to find where corruption occurred. (2) Impact analysis - change source schema, lineage shows all downstream affected. (3) Trust - understand data provenance, increases confidence. (4) Debugging - unexpected value, trace calculation steps. (5) Compliance - prove data handling for audits (GDPR - where did PII go?). Governance benefits: (1) Data discovery - find where data used, who depends on it. (2) Change management - assess impact before changes. (3) Decommissioning - safely deprecate tables (check if anything depends). (4) Access control - understand sensitive data flow. Implementation: (1) Automated extraction - parse SQL, ETL jobs for lineage (tools: dbt docs, Airflow lineage backend). (2) Metadata management - store lineage in catalog (Atlan, Collibra, Alation). (3) Open standards - OpenLineage (CNCF) for interoperability. (4) Manual documentation - for complex logic, document transformations. Tools: dbt (automatic lineage in docs), Apache Atlas, Egeria, Amundsen (metadata management), OpenMetadata, commercial solutions (Alation, Collibra, Atlan). Visualization: graph showing tables as nodes, transformations as edges, clickable to see logic, filters for specific flows.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (280, 'Your executive dashboard is showing metrics that don''t match similar reports from other teams. Finance reports $10M revenue, your data pipeline shows $8M for the same period. You need to investigate and resolve the discrepancy. Walk through your troubleshooting process. How do you trace the data lineagebackward, identify where the difference occurs, and establish a single source of truth?',
     'Critical discrepancy investigation framework: Immediate actions: (1) Freeze changes - pause pipeline updates until resolved (avoid moving target). (2) Document - record both numbers, screenshots, queries used. (3) Assemble team - data engineers, finance analyst, stakeholders. (4) Set urgency - revenue numbers critical, prioritize resolution. Investigation Phase 1 - Scope Definition: (1) Validate queries - ensure comparing apples-to-apples (same date range, timezone, filters). Example: your query uses order_date, finance uses payment_date (different!). (2) Reproduce both numbers - run both team''s queries, confirm $10M vs $8M. (3) Document definitions - what is "revenue"? Gross vs net? Include tax? Refunds? Currency conversions? Often discrepancies are definitional. (4) Check time windows - date inclusive/exclusive boundaries, timezone inconsistencies. Phase 2 - Data Lineage Tracing Backward: Your pipeline lineage: Executive dashboard → revenue_summary table → daily_sales aggregation → sales_transactions → source CRM. Finance lineage: Finance report → SQL query → accounting_systems table → ERP system. Trace each step comparing values: (1) Start at reporting layer - dashboard shows $8M from revenue_summary, finance report shows $10M from query. Query finance''s exact SQL, run it - does it actually give $10M? Verify. (2) Trace to source of truth - what is authoritative source? Likely ERP/accounting system (finance owns). Query source directly: SELECT SUM(revenue) FROM erp.transactions WHERE date BETWEEN ''2024-01-01'' AND ''2024-01-31''. Result: $10M. This validates finance number, your pipeline has issue. (3) Trace your pipeline backward: Check revenue_summary (aggregated) value, check daily_sales (intermediate) values, check sales_transactions (raw) values from CRM. Find WHERE discrepancy introduced - if sales_transactions from CRM already shows $8M, issue is upstream (CRM not syncing all data). If sales_transactions has $10M but daily_sales drops to $8M, issue in aggregation logic. Phase 3 - Identify Root Cause: Common causes and detection: (1) Missing data - incomplete extraction from source. Investigation: compare record counts (your pipeline: 1000 orders, source ERP: 1250 orders → missing 250!). Query for missing records: find which orders not in your pipeline. Root cause example: extraction query has WHERE region=''US'', but finance includes all regions. (2) Incorrect filter/transformation - bug in aggregation logic. Investigation: review transformation SQL, spot unintended filters (WHERE price > 0 excludes refunds counted by finance). (3) Duplicate removal - pipeline deduplicates incorrectly, removes valid records. (4) Join issues - LEFT JOIN drops records where join fails, should be OUTER JOIN or different logic. (5) Data type issues - implicit conversions causing errors (numeric overflow, rounding). (6) Time window misalignment - pipeline uses UTC, finance uses local timezone (day boundary differs). (7) Delayed data - pipeline snapshot from day earlier, newer transactions not yet loaded. Phase 4 - Validation and Fix: Once root cause identified (example: missing 250 orders due to filter), fix pipeline: (1) Update extraction query - remove incorrect filter or adjust to match definition. (2) Backfill historical data - reprocess past periods to correct historical metrics. (3) Validate fix - new pipeline run shows $10M, matches finance. (4) Reconciliation report - compare key metrics across both systems daily going forward (early detection of future drift). Phase 5 - Establish Single Source of Truth: (1) Agree on authoritative source - ERP is source of truth for revenue, all reports derive from it. (2) Centralize metric definitions - create data dictionary defining "revenue" explicitly, document in catalog, accessible to all. (3) Shared dataset - create canonical revenue metrics table both teams use, no separate calculations. (4) Contract testing - dbt tests or Great Expectations ensure pipelines produce expected results, alert on deviation. Example test: revenue sum must be within 0.1% of ERP total. (5) Automated reconciliation - scheduled job compares yourpipeline output to finance source, alerts if drift > threshold. Phase 6 - Preventive Measures: (1) Data lineage documentation - document full path from ERP → dashboard, everyone sees dependencies. (2) Change review process - changes to metric definitions require cross-team approval (prevent drift). (3) Regular reconciliation - weekly/monthly compare key metrics across systems, early detection. (4) Ownership clarity - define data steward for each metric (who is accountable for accuracy?). (5) Data governance council - regular meetings to align on definitions, resolve issues. Communication throughout: (1) Stakeholder updates - daily progress on investigation (executives waiting). (2) Root cause explanation - document what happened, why, how fixed (transparency). (3) Confidence rebuilding - demonstrate fix, show validation, restore trust in dashboard. Post-incident review: (1) Blameless postmortem - what went wrong, how detected late, how prevent recurrence. (2) Documentation - capture in runbook for future similar issues. (3) Training - team learns about reconciliation importance. Success criteria: Both reports show same number, documented definition everyone agrees on, automated alerts prevent future drift, stakeholder confidence restored.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 57: Data Modeling (5 questions)
    (281, 'What is the difference between normalization and denormalization? When would you use each in data modeling?',
     'Normalization: organize data to reduce redundancy, split into related tables, enforce referential integrity. Normal forms (1NF, 2NF, 3NF, BCNF) progressively eliminate duplication. Example: E-commerce database - customers table, orders table (references customer_id), order_items table (references order_id, product_id), products table. Benefits: no data duplication, update in one place, data integrity, storage efficient. Drawbacks: more joins (slower queries), complex queries, harder to understand. Denormalization: deliberately add redundancy for performance, combine related data into fewer tables. Example: order_details table with customer name, product name embedded (duplicated). Benefits: faster queries (fewer joins), simpler SQL, better read performance. Drawbacks: more storage, update anomalies (change customer name in multiple places), data inconsistency risk. When to normalize: OLTP systems (transactional databases), data integrity critical, frequent updates, moderate query complexity acceptable, storage premium. Example: banking system (customer info changed once, referenced many times). When to denormalize: OLAP systems (data warehouses), read-heavy workloads, query performance critical, updates rare, storage cheap. Example: analytics warehouse (query billions of rows, joins expensive). Hybrid approach: normalize in source system (OLTP), denormalize in warehouse (ETL transforms normalized to star schema), best of both worlds. Modern: cloud warehouses so powerful that moderate joins acceptable, but still denormalize for very large scale.',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),


    (282, 'Explain dimensional modeling: fact tables and dimension tables. What is a conformed dimension?',
     'Dimensional modeling: data warehousing technique, organizes data for analytics, uses facts and dimensions. Ralph Kimball methodology. Fact table: contains business measurements (facts/metrics) and foreign keys to dimensions. Grain: level of detail (one row per what?). Example: fact_sales - one row per order line item, columns: quantity, amount, date_key, product_key, customer_key. Facts are additive (can sum across dimensions). Dimension table: descriptive attributes providing context (who, what, when, where, why). Example: dim_product (product_id, name, category, brand), dim_date (date_key, year, quarter, month, day_of_week), dim_customer (customer_id, name, segment, region). Relationships: fact table references dimensions via foreign keys, star schema (fact center, dimensions radiate), snowflake (normalized dimensions). Conformed dimension: shared dimension used across multiple fact tables, same structure and meaning everywhere. Example: dim_date shared by fact_sales, fact_inventory, fact_web_clicks. Benefits: (1) Consistent analysis - date definitions same across all facts. (2) Cross-fact reporting - can combine facts on common dimensions. (3) Single maintenance - update dim_date once, all facts benefit. (4) Data warehouse bus architecture - conformed dimensions are integration points. Implementation: centralized dimension tables, published and managed centrally, strict versioning, all teams use same dimensions. Violations: each team creates own dim_date (inconsistent), different customer definitions across facts (can''t join). Best practice: identify conformed dimensions early, govern strictly, compromise on slight differences to maintain conformity.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (283, 'What is a slowly changing dimension (SCD)? Explain Type 1, Type 2, and Type 3 SCD strategies.',
     'Slowly Changing Dimension (SCD): dimension attributes that change over time, how to track changes. Example: customer moves, address changes; product rebranding, name changes. Strategies: Type 1 (Overwrite): update record, no history. Example: customer address changes, overwrite old address. Pros: simple, current state always accurate, no storage growth. Cons: history lost, can''t analyze historical context (what was address when order placed?). Use when: history unimportant, corrections (typos), low-value attributes. Type 2 (Add New Row): insert new record with new values, keep old record. Track history with effective dates or version flags. Example: customer address changes, insert new row with new address and effective_from date, old row gets effective_to date. Columns: customer_key (surrogate key, unique per version), customer_id (natural key, same across versions), address, effective_from, effective_to, is_current. Pros: complete history, can query point-in-time, support historical reporting. Cons: dimension grows, more complex queries, surrogate key management. Use when: history critical (regulatory, analysis), reporting needs "as of" date. Type 3 (Add New Column): add column for previous value, limited history. Example: customer address changes, add previous_address column. Pros: simple, some history, no new rows. Cons: limited (usually 1-2 prior values), inflexible. Use when: need only current + one previous, rare changes. Other types: Type 0 (Never changes), Type 4 (History in separate table), Type 6 (Hybrid 1+2+3). Implementation: ETL logic detects changes (hash current vs new), applies SCD strategy, maintains surrogate keys (Type 2). Tools: dbt snapshots (automatic SCD Type 2), SQL merge statements. Best practice: use Type 2 for important attributes, Type 1 for minor, document strategy per attribute.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (284, 'Compare Kimball (dimensional modeling) vs Inmon (normalized enterprise warehouse) vs Data Vault methodologies.',
     'Kimball (Dimensional/Bottom-up): build data marts for specific business areas, star schemas, conformed dimensions link marts, emphasize user access and performance. Approach: identify business process → define grain → identify dimensions → identify facts. Pros: fast time-to-value (deliver marts incrementally), user-friendly (simple queries), optimized for analytics. Cons: can become departmentalized silos, harder to integrate long-term, less normalized. Best for: fast analytics delivery, smaller organizations, specific use cases. Inmon (Enterprise/Top-down): build centralized normalized enterprise warehouse, then create data marts from it, emphasize data integrity and consistency. Approach: atomic data layer (3NF), create integrated model, data marts for access. Pros: single source of truth, data integrity, integrated, future-proof. Cons: long initial build, expensive, complex, delayed business value. Best for: large enterprises, complex integration needs, long-term investment. Data Vault (Hybrid): flexible modeling for historical tracking and auditability, separates business keys (hubs), relationships (links), and attributes (satellites). Components: Hubs (business entities with keys), Links (relationships between hubs), Satellites (attributes with history). Pros: highly flexible (easy to add sources), audit trail (full history), parallel loading, agile-friendly (iterative). Cons: complex (many tables), query performance needs views/caching, learning curve, over-engineering risk. Best for: complex source systems, frequent changes, regulatory requirements (full audit), large scale. Modern trend: hybrid approach - land data in normalized/vault structure, serve dimensional marts for users, leverage cloud warehouse flexibility. ELT enables both normalized storage and denormalized serving. Recommendations: Start-up/fast results: Kimball (pragmatic, fast value). Large enterprise: Inmon or Data Vault (structure for complexity). Regulatory/audit: Data Vault (history tracking). Cloud-native: flexibility allows mixing approaches.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (285, 'You''re designing a data warehouse for a global e-commerce company. Sales occur across 50 countries, 10K products, 100M customers, 1B orders. The business needs to analyze sales by customer segment, product category, time, region, and payment method. Design your fact and dimension tables. How do you handle slowly changing dimensions for customer addresses and product categories? What grain do you choose for the fact table? How do you optimize for common query patterns like "sales by category by quarter" vs detailed drill-down to individual orders?',
     'Requirements analysis: Scale (1B orders, large dimensions), query patterns (mix of aggregated reports and drill-down), global (multi-currency, timezones), slowly changing dimensions (addresses, categories). Dimensional model design: Fact table design - Grain decision critical. Options analyzed: (a) One row per order: 100M rows (manageable). Columns: order_total, item_count, keys. Simple but loses line-item detail (can''t analyze product mix per order). (b) One row per order line item: 3-5B rows (1B orders × avg 3-5 items). Columns: quantity, unit_price, line_total, discount, keys. Enables product analysis, larger but cloud warehouse handles this. Chosen grain: One row per order line item (fact_order_line), additive facts (quantity, line_total, discount). Semi-additive: unit_price (average not sum). Keys: date_key, product_key, customer_key, payment_method_key, region_key, order_id. Dimension tables designed: (1) dim_date: date_key (PK), full_date, year, quarter, month, day, day_of_week, is_holiday, fiscal_period. Grain: one row per day (perpetual 10+ years = 4K rows, tiny). Conformed dimension. (2) dim_product: product_key (surrogate key, PK), product_id (natural key), product_name, category, subcategory, brand, supplier, cost, effective_from, effective_to, is_current. SCD Type 2 for category (products recategorized over time). Version per category change. Size: 10K products × avg 2 versions = 20K rows. (3) dim_customer: customer_key (surrogate), customer_id (natural), name, email, segment (VIP, regular, new), region, country, address_line1, city, postal_code, effective_from, effective_to, is_current. SCD Type 2 for address (customers move). Type 1 for segment (overwrite, current classification matters more). Size: 100M customers × avg 1.2 changes = 120M rows (manageable). (4) dim_payment_method: payment_method_key, method ( credit card, PayPal, etc), category (card, digital wallet). Small, Type 1. (5) dim_region: region_key, country, region, timezone, currency. Type 1. (6) dim_order: order_id (degenerate dimension, could be in fact or separate), order_date, ship_date, status. Consideration: order attributes rarely change, could be in fact table to reduce joins. Modeling decisions: SCD strategy per dimension: - Product category: Type 2 (analyze historical sales in category at time of sale). - Customer address: Type 2 (analyze geographic trends over time, know where they lived when order placed). - Customer segment: Type 1 (current segment for targeting, history less critical). - Payment method, region: Type 1 (rarely change). Optimization for query patterns: (1) Aggregate fact tables (OLAP optimization): fact_sales_daily: pre-aggregate to daily grain (date, product, region), reduce 3B rows to millions, fast for "sales by category by quarter" query. fact_sales_monthly: further aggregation, thousands of rows, dashboard queries instant. Tradeoff: storage (3 fact tables) vs query speed (much faster aggregates). Modern: materialized views auto-maintain aggregates. (2) Partitioning: fact_order_line partitioned by date (common filter), enables partition pruning (query one quarter only scans relevant partitions). Snowflake/BigQuery native partitioning. (3) Clustering/sorting: cluster by product_key (product-heavy queries), sort by date (time-series queries). (4) Denormalization for hot paths: if "sales by category" is 80% of queries, denormalize category_name into fact table (avoid join to dim_product), tradeoff: redundancy vs speed. Alternatively: create reporting view with common joins pre-defined. (5) Column selection: fact table includes commonly filtered/grouped attributes directly (country_code, category_id), reduces joins for simple queries, full dimensions for detailed drill-down. Multi-currency handling: Store amounts in local currency + USD equivalent, conversion_rate column (allows recalculation), dim_currency table (exchange rates by date). Query pattern optimization examples: Query: "Total sales by category by quarter" → Use fact_sales_daily aggregate → Join dim_date (quarter), dim_product (category) → Fast (millions of rows, simple joins). Query: "Orders for customer John in 2023 with product details" → Use fact_order_line detail → Join dim_customer (filter name), dim_date (filter year), dim_product (details) → Partition pruning on date, index on customer → Acceptable performance. Scalability considerations: 1B order lines manageable in Snowflake/BigQuery (TBs of data), aggregates for common queries (daily, monthly), partition pruning reduces scan volumes, materialized views for dashboards (auto-refresh), separate cold data (orders > 2 years to archive table). Implementation approach: Phase 1: Core dimensions + fact_order_line → support detailed queries. Phase 2: Aggregate tables → optimize performance. Phase 3: Slowly changing dimension implementation → track history. Phase 4: Monitoring and tuning → add indexes, optimize based on actual query patterns. Validation: Test queries for common patterns, measure performance (sub-second for aggregates, seconds for drill-down), ensure SCD logic correct (point-in-time queries accurate), data quality checks (referential integrity, no orphans). Success metrics: Queries under SLA (aggregates < 1sec, detailed < 10sec), storage costs reasonable, business users self-serve (simple star schema), accurate historical analysis (SCD working).',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

    -- Topic 58: Stream Processing (5 questions)
    (286, 'What is stream processing? How does it differ from batch processing? What are typical use cases?',
     'Stream processing: continuous processing of unbounded data streams in real-time, events processed as they arrive. Example: sensor data, user clicks, transactions. Batch processing: processing finite dataset at scheduled intervals. Example: nightly ETL, monthly reports. Key differences: Latency - stream: milliseconds-seconds, batch: minutes-hours-days. Data - stream: unbounded/infinite, batch: bounded/finite. Trigger - stream: event-driven (continuous), batch: time-driven (scheduled). Model - stream: process one event or micro-batch, batch: process entire dataset. Infrastructure - stream: always on, batch: ephemeral jobs. Use cases stream processing: (1) Real-time analytics - dashboards updated live (website traffic, app metrics). (2) Fraud detection - analyze transaction patterns real-time, block suspicious instantly. (3) Alerting - system monitoring, trigger alerts on threshold (error spike, latency increase). (4) Event-driven architectures - microservices react to events. (5) IoT - sensor data processing (anomaly detection, predictive maintenance). (6) Real-time recommendations - personalize content based on behavior. (7) Log aggregation - centralized logging, search/alert in realtime. Batch use cases: historical analysis, complex computations not time-sensitive, large-scale aggregations, model training. Hybrid: Lambda/Kappa architecture combines both. Tools: Stream - Kafka Streams, Flink, Spark Streaming, KSQL. Batch - Spark Batch, Hadoop MapReduce. Trend: streaming increasingly preferred, batch for when real-time not needed, cost considerations (streaming infrastructure always-on).',
     'technical', 'easy', 'organization', 1, 'custom', 3, true),
    
    (287, 'Compare Apache Kafka, Apache Flink, and Spark Streaming for stream processing. When would you use each?',
     'Apache Kafka: distributed event streaming platform, primarily message broker with stream processing (Kafka Streams, KSQL). Architecture: durable log, producers/consumers, strong ordering. Stream processing: Kafka Streams (library, embedded in app), KSQL (SQL interface). Pros: simple (library not cluster), exactly-once, scales well, tight Kafka integration. Cons: Kafka-only (requires Kafka as source), limited windowing vs Flink. Use for: Kafka-centric architectures, simple stream processing, stateful aggregations, microservices event processing. Apache Flink: true stream processing engine, designed for stateful computations over streams. Architecture: JobManager + TaskManagers, operator state. Features: event time processing, powerful windowing, exactly-once, savepoints (state snapshots), backpressure. Pros: best-in-class stream processing, low latency, complex event processing (CEP), handles late data well, batch + stream unified. Cons: complexity (cluster management), learning curve, operational overhead. Use for: complex stream processing (multi-stage, stateful), low-latency requirements (milliseconds), exactly-once critical, event-time semantics. Spark Streaming: micro-batch processing on Spark, Structured Streaming (newer, true streaming). Architecture: DStreams (RDD micro-batches) or Structured Streaming (continuous). Pros: Spark ecosystem (use same Spark code for batch + stream), simple (familiar Spark API), good integration (all connectors). Cons: higher latency (micro-batches, seconds not milliseconds), stateful operations complex, not true streaming (DStreams). Use for: existing Spark investment, batch + stream unified codebase, moderate latency acceptable (seconds), leverage Spark MLlib for real-time inference. Comparison summary: Latency - Flink (milliseconds) > Kafka Streams (low) > Spark (seconds). Complexity - Flink (high) > Spark (medium) > Kafka Streams (low). Ecosystem - Spark (broad) > Flink (growing) > Kafka (Kafka-focused). Choose Kafka Streams for: already using Kafka, microservices architecture, simple processing. Choose Flink for: complex streaming, low latency, large scale, stateful processing. Choose Spark Streaming for: unified batch + stream, existing Spark, seconds latency OK. Modern trend: Flink growing popularity for sophisticated use cases, Kafka Streams for simpler Kafka-native apps, Spark still common for unified batch/stream.',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (288, 'What are stateful vs stateless stream processing? Explain windowing, triggers, and watermarks.',
     'Stateless processing: each event processed independently, no memory of past events. Example: filter, map, flat map. Simple, scalable, no coordination. Stateful processing: maintains state across events, aggregations, joins. Example: count events per user (state = user counts), sessionization (state = session windows). Complex, requires state management (checkpointing, fault tolerance). State types: Keyed state (per key, like user ID), Operator state (per operator instance), Broadcast state (replicated to all). Windowing: grouping events into finite chunks for aggregation. Types: (1) Tumbling windows - fixed-size, non-overlapping. Example: 5-minute windows (12:00-12:05, 12:05-12:10, no overlap). Use: periodic aggregations. (2) Sliding windows - fixed-size, overlapping. Example: 10-minute window every 5 minutes (12:00-12:10, 12:05-12:15, overlap 5min). Use: moving averages. (3) Session windows - dynamic size based on inactivity gap. Example: user session ends after 30min inactivity. Use: sessionization, user behavior analysis. (4) Global window - single window for all data (rarely used alone). Time semantics: Event time (when event occurred - embedded in data), Processing time (when system processes - wall clock), Ingestion time (when system receives). Event time preferred (accurate despite delays). Watermarks: estimate of event time progress, signal "all events before watermark time have arrived". Allows closing windows despite late data. Example: watermark at 12:10 means no more events with timestamp < 12:10 expected (window 12:00-12:05 can be finalized). Late data handling: allow lateness (process late within threshold), discard (ignore very late), re-trigger (update previousresults). Triggers: determine when window results are emitted. Types: Time triggers (after wall-clock time), Count triggers (after N events), Completeness (watermark), Custom. Use: early results (progressive aggregation), handle late data. Example: emit preliminary result on first event, update on watermark. State management: checkpointing (periodic snapshots to persistent storage), recovery from checkpoints (exactly-once guarantees), state backends (RocksDB, in-memory). Windowing framework (Flink, Beam): WindowAssigner (assign events to windows) → Trigger (when to emit) → Evictor (optional, remove events) → ProcessFunction (compute).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (289, 'Explain backpressure in stream processing. What causes it and how do you handle it?',
     'Backpressure: downstream consumer can''t keep up with upstream producer, queue fills, system must react. Flow control mechanism. Cause: consumer slower than producer (processing bottleneck, network saturation, downstream database slow). Example: Kafka producer sends 10K msg/sec, Flink consumer processes 5K msg/sec → buffer fills. Handling mechanisms: (1) Blocking/slowing producer - consumer signals upstream to slow down, producer waits before sending more. Flink uses this: TaskManager backpressure propagates to source, source slows reading. Pros: prevents data loss, automatic. Cons: producer blocked (may cause timeout, full pipeline slowdown). (2) Buffering - queue events temporarily, absorb bursts. Kafka log acts as buffer, consumers read at own pace. Pros: decouples producer/consumer, handles bursts. Cons: limited buffer size, latency increases (events queued longer), eventual overflow if sustained. (3) Dropping events - discard events when overwhelmed (lossy). Use for: non-critical data, sampling acceptable. Example: metrics (drop some, still statistically valid). Pros: prevents system crash. Cons: data loss. (4) Load shedding - selectively drop low-priority events, keep high-priority. (5) Dynamic scaling - add more consumers/workers when backpressure detected, auto-scale based on lag. Kubernetes HPA scales pods based on Kafka lag metric. Detection: Flink metrics (backpressure ratio), Kafka consumer lag (increasing), queue depths, processing latency. Prevention: (1) Optimize consumer - make processing faster (algorithm, caching, batching database writes). (2) Increase parallelism - more consumer instances, partition data. (3) Scale infrastructure - more CPU/memory. (4) Aggregate upstream - reduce event volume (pre-aggregation, sampling). (5) Asynchronous processing - non-blocking operations. Design considerations: choose buffer sizes appropriately (too small = frequent backpressure, too large = memory issues, long latency), monitoring (detect backpressure early), graceful degradation (reduce quality instead of failing).',
     'technical', 'medium', 'organization', 1, 'custom', 5, true),
    
    (290, 'Your real-time fraud detection system processes payment transactions through Flink. Recently you''ve observed increasing lag and occasional transaction processing delays exceeding 10 seconds (SLA is 500ms). The stream processes 50K transactions/sec, does stateful pattern matching (sequence of actions per user), and joins with customer profile data. How do you diagnose where the delay occurs and optimize for ultra-low latency?',
     'SLA violation diagnosis (target 500ms, seeing 10sec): This is critical for fraud detection (false negatives = fraud, false positives = customer frustration). Diagnostic approach: (1) Flink metrics - end-to-end latency (source to sink), operator latency (which operator slow?), backpressure (upstream waiting for downstream?), checkpoint duration (state snapshots blocking?), GC time (memory pressure?). (2) Breakdown by stage - source read latency, pattern matching latency (stateful operation), join latency (enrichment), sink write latency. (3) Resource monitoring - CPU saturation, memory (heap, state size), network bandwidth, disk I/O (state backend). (4) Data characteristics - transaction volume trend (50K constant or spiking?), state size growth (user state accumulating?), join data size (customer profile table growing?). Likely bottlenecks identified: (1) Stateful pattern matching - maintaining sequence state per user (millions of users), state size explosion, checkpoint takes minutes (blocks processing). (2) Join with customer profiles - potentially slow lookup (network call to database?), large enrichment data, broadcast join inefficient. (3) Checkpointing - large state = slow checkpoints, processing paused during checkpoint. (4) Resource constraints - CPU/memory insufficient for 50K/sec. Optimization strategies: Issue 1 - State Size Management: State explosion (keeping full transaction history per user), solution: (a) TTL on state - configure state Time-To-Live (Flink state TTL API), expire old data (only keep last 10 minutes for fraud patterns), reduces state size dramatically. (b) State compression - enable RocksDB compression (snappy/lz4). (c) Incremental checkpoints - checkpoint only changed state (Flink RocksDB incremental checkpoints), faster than full snapshots. (d) State cleanup - explicit cleanup after pattern matched (no need to keep after detected). Target: reduce state from GBs to MBs per operator. Issue 2 - Join Optimization: If joining with customer profiles stored externally (database lookup per transaction = 50K queries/sec, kills database!), solutions: (a) Async I/O - non-blocking database lookups (Flink AsyncDataStream), process multiple transactions concurrently while waiting for lookups, throughput increase 10-100x. (b) Broadcast join - if customer profile data small enough, broadcast to all Flink workers (profiles in memory), local joins (no network calls), extremely fast. Update broadcast when profiles change (Flink broadcast state). (c) Caching - local cache (Caffeine, Guava) in Flink operators, cache hot customer profiles, TTL for freshness, reduces database lookups 80-90%. (d) Pre-join in Kafka - if profiles rarely change, join upstream (Kafka Streams join), Flink receives enriched transactions, no join needed. Issue 3 - Checkpoint Optimization: checkpoints blocking processing (synchronous barrier alignment), solutions: (a) Increase checkpoint interval - currently every minute? change to 5 minutes (fewer checkpoints, less disruption), trade-off: recovery time (more data to replay). (b) Unaligned checkpoints - Flink 1.11+ (checkpoints don''t wait for barrier alignment), much faster for backpressure scenarios. (c) Async barrier snapshots - state snapshots happen async while processing continues. (d) Faster state backend - RocksDB (disk-based, slower) vs HashMap (memory-based, faster but limited by RAM), tune RocksDB (block cache size, write buffer). Issue 4 - Parallelism and Resource Scaling: under-resourced for 50K/sec, solutions: (a) Increase parallelism - more task slots, distribute load across more workers. Calculate: 50K transactions/sec, target 500ms processing = 25K concurrent, need enough parallelism. (b) Scale cluster - more TaskManagers, more CPU cores, more memory (reduce GC), use auto-scaling if on Kubernetes. (c) Right-size - profile to find optimal parallelism (too high also causes overhead). Issue 5 - Pattern Matching Optimization: fraud pattern logic inefficient (complex regex, nested loops?), solutions: (a) CEP optimization - use Flink CEP library efficiently, simplify patterns (avoid overly complex), consider stateless scoring (ML model) instead of stateful patterns. (b) Sampling for complex checks - run expensive checks on sample (10%), fast checks on all, acceptable trade-off if fraud rare. (c) Pre-filtering - filter obvious non-fraud early (reduce stateful processing volume). Advanced techniques: (1) Event time vs processing time - if using event time, watermarks critical, tune watermark strategy (allow lateness vs completeness). (2) Operator chaining - ensure operators chained (fused into same task, avoid network shuffle), Flink auto-optimizes but verify. (3) Network buffers - increase Flink network buffer configuration (avoid backpressure from buffer exhaustion). (4) Monitoring and alerting - Prometheus metrics, Grafana dashboards, alert on latency p99 > 1sec. Testing optimization: (1) Load test - synthetic 50K TPS, measure latency distribution (p50, p95, p99). (2) A/B test - run optimized version in parallel, compare latency. (3) Incremental rollout - canary deployment (10% traffic), validate before full rollout. Measuring success: p99 latency < 500ms (SLA met), throughput sustained at 50K/sec, checkpoint duration < 30sec, backpressure = 0, fraud detection accuracy maintained (optimization didn''t hurt accuracy). Architecture alternatives if optimization insufficient: (1) Tiered processing - fast path (simple rules, sub-100ms) handles 95%, slow path (complex ML, seconds) handles 5% flagged, most transactions fast. (2) Approximate fraud detection - use probabilistic data structures (Bloom filters, HyperLogLog) for fast checks, sacrifice precision for speed. (3) Pre-aggregation - aggregate user behavior upstream (Kafka Streams), Flink processes aggregates not raw transactions, reduce volume. Expected outcome: latency p99 reduced from 10sec → 200ms (well under SLA), state size reduction (TTL + incremental checkpoints), async I/O for joins (eliminate database bottleneck), scaled cluster horizontally.',
     'technical', 'hard', 'organization', 1, 'custom', 7, true),

